import{_ as a,c as e,o as m,b as t}from"./app.1117c437.js";const q='{"title":"\u0410\u0444\u043E\u0440\u0438\u0437\u043C 34-40","description":"","frontmatter":{"title":"\u0410\u0444\u043E\u0440\u0438\u0437\u043C 34-40","subtitle":"\u0428\u0438\u0432\u0430 \u0441\u0443\u0442\u0440\u0430 \u0432\u0438\u043C\u0430\u0440\u0448\u0438\u043D\u0438. \u0413\u043B\u0430\u0432\u0430 3.","tags":"vim-3","date":"2021-01-22T00:00:00.000Z"},"headers":[],"relativePath":"texts/shiva-sutra-vimarshini/3/34-40/index.md"}',u={},o=t('<div class="stanza"><a href="#s3.34" id="s3.34" class="num">3.34</a><div class="sans"><p>\u092F\u0924\u0936\u094D\u091A\u094B\u0924\u094D\u0924\u0940\u0930\u094D\u0923\u092A\u0941\u0930\u094D\u092F\u0937\u094D\u091F\u0915\u092A\u094D\u0930\u092E\u093E\u0924\u0943\u092D\u093E\u0935\u0938\u094D\u092F \u092F\u094B\u0917\u093F\u0928\u094B \u0928\u093E\u0928\u094D\u0924\u0903 \u0938\u0941\u0916\u0926\u0941\u0903\u0916\u0938\u0902\u0938\u094D\u092A\u0930\u094D\u0936\u094B\u093D\u0924 \u090F\u0935\u093E\u0938\u094C\u2014</p><blockquote><p><strong>\u0924\u0926\u094D\u0935\u093F\u092E\u0941\u0915\u094D\u0924\u0938\u094D\u0924\u0941 \u0915\u0947\u0935\u0932\u0940\u0965\u0969\u096A\u0965</strong></p></blockquote><p>\u0924\u093E\u092D\u094D\u092F\u093E\u0902 \u0938\u0941\u0916\u0926\u0941\u0903\u0916\u093E\u092D\u094D\u092F\u093E\u0902 \u0935\u093F\u0936\u0947\u0937\u0947\u0923 \u092E\u0941\u0915\u094D\u0924\u0903 \u0938\u0902\u0938\u094D\u0915\u093E\u0930\u092E\u093E\u0924\u094D\u0930\u0947\u0923\u093E\u092A\u094D\u092F\u0928\u094D\u0924\u0930\u0938\u0902\u0938\u094D\u092A\u0943\u0937\u094D\u091F\u0903 \u0915\u0947\u0935\u0932\u0940 \u0915\u0947\u0935\u0932\u0902 \u091A\u093F\u0928\u094D\u092E\u093E\u0924\u094D\u0930\u092A\u094D\u0930\u092E\u093E\u0924\u0943\u0924\u093E\u0930\u0942\u092A\u0902 \u092F\u0938\u094D\u092F\u0964 \u0924\u0926\u0941\u0915\u094D\u0924\u0902 \u0936\u094D\u0930\u0940\u0915\u093E\u0932\u093F\u0915\u093E\u0915\u094D\u0930\u092E\u0947</p><blockquote><p>\u0938\u0941\u0916\u0926\u0941\u0903\u0916\u093E\u0926\u093F\u0935\u093F\u091C\u094D\u091E\u093E\u0928\u0935\u093F\u0915\u0932\u094D\u092A\u093E\u0928\u0932\u094D\u092A\u0915\u0932\u094D\u092A\u093F\u0924\u092E\u094D\u0964<br> \u092D\u093F\u0924\u094D\u0924\u094D\u0935\u093E \u0926\u094D\u0935\u0948\u0924\u092E\u0939\u093E\u092E\u094B\u0939\u0902 \u092F\u094B\u0917\u0940 \u092F\u094B\u0917\u092B\u0932\u0902 \u0932\u092D\u0947\u0924\u094D\u0965</p></blockquote><p>\u0907\u0924\u093F\u0964 \u0924\u0941\u0936\u092C\u094D\u0926\u094B \u0935\u0915\u094D\u0937\u094D\u092F\u092E\u093E\u0923\u093E\u092A\u0947\u0915\u094D\u0937\u092F\u093E \u0935\u093F\u0936\u0947\u0937\u0926\u094D\u092F\u094B\u0924\u0915 \u090F\u0935\u092E\u0941\u0924\u094D\u0924\u0930\u0938\u0942\u0924\u094D\u0930\u0917\u0924\u094B\u093D\u092A\u094D\u092F\u0947\u0924\u0924\u094D\u0938\u0942\u0924\u094D\u0930\u093E\u092A\u0947\u0915\u094D\u0937\u092F\u093E\u0965\u0969\u096A\u0965</p></div><hr><div class="trans"><p>Yata\u015Bcott\u012Br\u1E47apurya\u1E63\u1E6Dakapram\u0101t\u1E5Bbh\u0101vasya yogino n\u0101nta\u1E25 sukhadu\u1E25khasa\u1E41spar\u015Bo&#39;ta ev\u0101sau\u2014</p><blockquote><p><strong>Tadvimuktastu keval\u012B||34||</strong></p></blockquote><p>T\u0101bhy\u0101\u1E41 sukhadu\u1E25kh\u0101bhy\u0101\u1E41 vi\u015Be\u1E63e\u1E47a mukta\u1E25 sa\u1E41sk\u0101ram\u0101tre\u1E47\u0101pyantarasa\u1E41sp\u1E5B\u1E63\u1E6Da\u1E25 keval\u012B kevala\u1E41 cinm\u0101trapram\u0101t\u1E5Bt\u0101r\u016Bpa\u1E41 yasya| Tadukta\u1E41 \u015Br\u012Bk\u0101lik\u0101krame</p><blockquote><p>Sukhadu\u1E25kh\u0101divij\xF1\u0101navikalp\u0101nalpakalpitam|<br> Bhittv\u0101 dvaitamah\u0101moha\u1E41 yog\u012B yogaphala\u1E41 labhet||</p></blockquote><p>iti| Tu\u015Babdo vak\u1E63yam\u0101\u1E47\u0101pek\u1E63ay\u0101 vi\u015Be\u1E63adyotaka evamuttaras\u016Btragato&#39;pyetats\u016Btr\u0101pek\u1E63ay\u0101||34||</p></div><hr><p>\u0418 <em>(ca)</em>, \u043F\u043E\u0441\u043A\u043E\u043B\u044C\u043A\u0443 <em>(yatas)</em> \u0434\u043B\u044F Yog\u012B <em>(yogina\u1E25)</em>, \u043A\u043E\u0442\u043E\u0440\u044B\u0439 \u0432\u044B\u0448\u0435\u043B \u0437\u0430 \u043F\u0440\u0435\u0434\u0435\u043B\u044B \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u044F <em>(utt\u012Br\u1E47a... bh\u0101vasya)</em>, \u0433\u0434\u0435 \u0442\u043E\u043D\u043A\u043E\u0435 \u0442\u0435\u043B\u043E --\u0438\u043D\u0442\u0435\u043B\u043B\u0435\u043A\u0442, \u044D\u0433\u043E, \u0443\u043C \u0438 \u0442\u043E\u043D\u043A\u0438\u0435 \u044D\u043B\u0435\u043C\u0435\u043D\u0442\u044B-- <em>(purya\u1E63\u1E6Daka)</em> [\u0440\u0430\u0441\u0441\u043C\u0430\u0442\u0440\u0438\u0432\u0430\u0435\u0442\u0441\u044F \u043A\u0430\u043A][\u043E\u0431\u044A\u0435\u043A\u0442\u0438\u0432\u043D\u043E \u0441\u0443\u0449\u0435\u0441\u0442\u0432\u0443\u044E\u0449\u0438\u0439] \u0412\u043E\u0441\u043F\u0440\u0438\u043D\u0438\u043C\u0430\u044E\u0449\u0438\u0439 <em>(pram\u0101t\u1E5B)</em>, \u0432\u043E\u0441\u043F\u0440\u0438\u044F\u0442\u0438\u0435 <em>(sa\u1E41spar\u015Ba\u1E25)</em> \u043D\u0430\u0441\u043B\u0430\u0436\u0434\u0435\u043D\u0438\u044F \u0438 \u0431\u043E\u043B\u0438 <em>(sukha-du\u1E25kha)</em> \u043D\u0435 \u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F <em>(na)</em> \u0432\u043D\u0443\u0442\u0440\u0435\u043D\u043D\u0438\u043C <em>(antar)</em> --\u043E\u043D\u043E \u043D\u0435 \u0437\u0430\u0442\u0440\u0430\u0433\u0438\u0432\u0430\u0435\u0442 \u0435\u0433\u043E \u0438\u0441\u0442\u0438\u043D\u043D\u043E\u0435 &quot;\u042F&quot;, \u043A\u0430\u043A \u043E\u0442\u043C\u0435\u0447\u0430\u043B\u043E\u0441\u044C \u0432 \u043A\u043E\u043C\u043C\u0435\u043D\u0442\u0430\u0440\u0438\u0438 \u043A \u043F\u0440\u0435\u0434\u044B\u0434\u0443\u0449\u0435\u043C\u0443 \u0430\u0444\u043E\u0440\u0438\u0437\u043C\u0443--<sup>1</sup>, \u0441\u043B\u0435\u0434\u043E\u0432\u0430\u0442\u0435\u043B\u044C\u043D\u043E <em>(atas eva)</em> \u043E\u043D <em>(asau)</em>\u2014</p><blockquote><p><strong>[\u041F\u043E\u0441\u043A\u043E\u043B\u044C\u043A\u0443 \u044D\u0442\u043E\u0442 \u0431\u043B\u0430\u0433\u043E\u0440\u043E\u0434\u043D\u044B\u0439 Yog\u012B] \u0430\u0431\u0441\u043E\u043B\u044E\u0442\u043D\u043E \u0441\u0432\u043E\u0431\u043E\u0434\u0435\u043D <em>(vimukta\u1E25)</em> \u043E\u0442 \u0442\u043E\u0433\u043E --\u043D\u0430\u0441\u043B\u0430\u0436\u0434\u0435\u043D\u0438\u044F \u0438 \u0431\u043E\u043B\u0438-- <em>(tad)</em>, \u0442\u043E\u043B\u044C\u043A\u043E [\u043E\u043D \u0435\u0441\u0442\u044C] \u043E\u0434\u0438\u043D <em>(keval\u012B)</em> \u0442\u043E\u0433\u0434\u0430 <em>(tu)</em>, [\u043A\u043E\u0440\u043E\u0447\u0435 \u0433\u043E\u0432\u043E\u0440\u044F, \u043E\u043D \u0434\u043E\u0441\u0442\u0438\u0433 \u0441\u0432\u043E\u0435\u0439 \u0441\u043E\u0431\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u0439 \u0421\u0430\u043C\u043E\u0441\u0442\u0438, \u044F\u0432\u043B\u044F\u044E\u0449\u0435\u0439\u0441\u044F \u043E\u0434\u043D\u043E\u0432\u0440\u0435\u043C\u0435\u043D\u043D\u043E &quot;\u0435\u0434\u0438\u043D\u0441\u0442\u0432\u0435\u043D\u043D\u044B\u043C&quot; \u041F\u043E\u0437\u043D\u0430\u044E\u0449\u0438\u043C \u0438 &quot;\u0435\u0434\u0438\u043D\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u0439&quot; \u041C\u0430\u0441\u0441\u043E\u0439 \u0447\u0438\u0441\u0442\u043E\u0433\u043E \u0421\u043E\u0437\u043D\u0430\u043D\u0438\u044F]||34||</strong></p></blockquote><p>\u0411\u0443\u0434\u0443\u0447\u0438 \u043F\u043E\u043B\u043D\u043E\u0441\u0442\u044C\u044E \u0438 \u043E\u0441\u043E\u0431\u044B\u043C \u043E\u0431\u0440\u0430\u0437\u043E\u043C <em>(vi\u015Be\u1E63e\u1E47a)</em> \u0441\u0432\u043E\u0431\u043E\u0434\u043D\u044B\u043C <em>(mukta\u1E25)</em> \u043E\u0442 \u043D\u0438\u0445 \u043E\u0431\u043E\u0438\u0445 <em>(t\u0101bhy\u0101m)</em> \u2014\u043E\u0442 \u043D\u0430\u0441\u043B\u0430\u0436\u0434\u0435\u043D\u0438\u044F \u0438 \u0431\u043E\u043B\u0438 <em>(sukha-du\u1E25kh\u0101bhy\u0101m)</em>\u2014 [\u0438] \u043D\u0435 \u0431\u0443\u0434\u0443\u0447\u0438 \u0437\u0430\u0442\u0440\u043E\u043D\u0443\u0442\u044B\u043C <em>(asa\u1E41sp\u1E5B\u1E63\u1E6Da\u1E25)</em> \u0432\u043D\u0443\u0442\u0440\u0435\u043D\u043D\u0435 <em>(antar)</em> \u0434\u0430\u0436\u0435 <em>(api)</em> \u043F\u0440\u043E\u0441\u0442\u044B\u043C\u0438 <em>(m\u0101tre\u1E47a)</em> \u043E\u0441\u0442\u0430\u0442\u043E\u0447\u043D\u044B\u043C\u0438 \u0432\u043F\u0435\u0447\u0430\u0442\u043B\u0435\u043D\u0438\u044F\u043C\u0438 <em>(sa\u1E41sk\u0101ra)</em><sup>2</sup>, \u0442\u043E\u043B\u044C\u043A\u043E [\u043E\u043D \u0435\u0441\u0442\u044C] \u043E\u0434\u0438\u043D <em>(keval\u012B)</em>, [\u0430 \u0438\u043C\u0435\u043D\u043D\u043E, \u043E\u043D \u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F] \u0442\u0435\u043C, \u0447\u044C\u044F <em>(yasya)</em> \u043F\u0440\u0438\u0440\u043E\u0434\u0430 <em>(r\u016Bpam)</em> \u0437\u0430\u043A\u043B\u044E\u0447\u0430\u0435\u0442\u0441\u044F \u0442\u043E\u043B\u044C\u043A\u043E <em>(kevalam)</em> \u0432 \u0441\u0443\u0449\u043D\u043E\u0441\u0442\u0438 \u0432\u043E\u0441\u043F\u0440\u0438\u043D\u0438\u043C\u0430\u044E\u0449\u0435\u0433\u043E, \u0438\u043B\u0438 \u043F\u043E\u0437\u043D\u0430\u044E\u0449\u0435\u0433\u043E <em>(pram\u0101t\u1E5Bt\u0101)</em>, \u043A\u0442\u043E \u0435\u0441\u0442\u044C \u0447\u0438\u0441\u0442\u043E\u0435 \u0421\u043E\u0437\u043D\u0430\u043D\u0438\u0435 <em>(cit-m\u0101tra)</em> --\u0434\u0440\u0443\u0433\u0438\u043C\u0438 \u0441\u043B\u043E\u0432\u0430\u043C\u0438, \u043E\u043D \u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F \u0447\u0438\u0441\u0442\u044B\u043C \u0421\u043E\u0437\u043D\u0430\u043D\u0438\u0435\u043C, \u0435\u0434\u0438\u043D\u0441\u0442\u0432\u0435\u043D\u043D\u044B\u043C \u0438 \u0438\u0441\u0442\u0438\u043D\u043D\u044B\u043C \u041F\u043E\u0437\u043D\u0430\u044E\u0449\u0438\u043C \u0432\u0441\u0435\u0433\u043E--|</p><p>\u0422\u0430\u043A <em>(tad)</em> \u0431\u044B\u043B\u043E \u0441\u043A\u0430\u0437\u0430\u043D\u043E <em>(uktam)</em> \u0432 \u0434\u043E\u0441\u0442\u043E\u0447\u0442\u0438\u043C\u043E\u043C K\u0101lik\u0101krama <em>(\u015Br\u012B-k\u0101lik\u0101krame)</em> [\u0442\u0430\u043A\u0436\u0435]:</p><blockquote><p>&quot;Yog\u012B <em>(yog\u012B)</em> \u0441\u043B\u0435\u0434\u0443\u0435\u0442 \u043E\u0431\u0440\u0435\u0441\u0442\u0438 <em>(labhet)</em> \u043F\u043B\u043E\u0434 <em>(phalam)</em> \u0432 \u0419\u043E\u0433\u0435 <em>(yoga)</em> \u043F\u043E\u0441\u0440\u0435\u0434\u0441\u0442\u0432\u043E\u043C \u0440\u0430\u0441\u0441\u0435\u0447\u0435\u043D\u0438\u044F \u043D\u0430 \u0447\u0430\u0441\u0442\u0438 <em>(bhittv\u0101)</em> \u0432\u0435\u043B\u0438\u043A\u043E\u0433\u043E <em>(mah\u0101)</em> \u0437\u0430\u0431\u043B\u0443\u0436\u0434\u0435\u043D\u0438\u044F <em>(moham)</em>, [\u0438\u043C\u0435\u043D\u0443\u0435\u043C\u043E\u0433\u043E] \u0434\u0432\u043E\u0439\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u0441\u0442\u044C\u044E <em>(dvaita)</em>, \u043A\u043E\u0442\u043E\u0440\u043E\u0435 --\u0437\u0430\u0431\u043B\u0443\u0436\u0434\u0435\u043D\u0438\u0435-- \u0441\u0444\u0430\u0431\u0440\u0438\u043A\u043E\u0432\u0430\u043D\u043E <em>(kalpitam)</em> \u043C\u043D\u043E\u0433\u043E\u0447\u0438\u0441\u043B\u0435\u043D\u043D\u044B\u043C\u0438 <em>(analpa)</em> \u043C\u044B\u0441\u043B\u044F\u043C\u0438 <em>(vikalpa)</em>, [\u043E\u0441\u043D\u043E\u0432\u0430\u043D\u043D\u044B\u043C\u0438 \u043D\u0430] \u043A\u043E\u0433\u043D\u0438\u0446\u0438\u044F\u0445 <em>(vij\xF1\u0101na)</em>, [\u0442\u0430\u043A\u0438\u0445 \u043A\u0430\u043A] \u043D\u0430\u0441\u043B\u0430\u0436\u0434\u0435\u043D\u0438\u0435 <em>(sukha)</em>, \u0431\u043E\u043B\u044C <em>(du\u1E25kha)</em>, \u0438 \u0442.\u0434. <em>(\u0101di... iti)</em>&quot;||</p></blockquote><p>\u0422\u0435\u0440\u043C\u0438\u043D <em>(\u015Babda\u1E25)</em> &quot;tu&quot; --\u0442.\u0435. \u0442\u043E\u0433\u0434\u0430-- <em>(tu)</em> [\u0438\u043C\u0435\u044E\u0449\u0438\u0439 \u043C\u0435\u0441\u0442\u043E \u0432 \u043D\u0430\u0441\u0442\u043E\u044F\u0449\u0435\u043C \u0430\u0444\u043E\u0440\u0438\u0437\u043C\u0435] \u044F\u0441\u043D\u043E \u043F\u043E\u043A\u0430\u0437\u044B\u0432\u0430\u0435\u0442 <em>(dyotaka\u1E25)</em> \u0440\u0430\u0437\u043D\u0438\u0446\u0443 <em>(vi\u015Be\u1E63a)</em> \u0432 \u043E\u0442\u043D\u043E\u0448\u0435\u043D\u0438\u0438 \u0442\u043E\u0433\u043E <em>(apek\u1E63ay\u0101)</em>, \u0447\u0442\u043E \u0434\u043E\u043B\u0436\u043D\u043E \u0431\u044B\u0442\u044C \u0443\u043F\u043E\u043C\u044F\u043D\u0443\u0442\u043E <em>(vak\u1E63yam\u0101\u1E47a)</em> [\u0432 \u0441\u043B\u0435\u0434\u0443\u044E\u0449\u0435\u043C \u0430\u0444\u043E\u0440\u0438\u0437\u043C\u0435]; \u043F\u043E\u044D\u0442\u043E\u043C\u0443 \u0442\u0430\u043A\u0436\u0435 <em>(evam... api)</em> [\u0441\u043B\u043E\u0432\u043E &quot;tu&quot;], \u0432\u0441\u0442\u0440\u0435\u0447\u0430\u044E\u0449\u0435\u0435\u0441\u044F <em>(gata\u1E25)</em> \u0432 \u0441\u043B\u0435\u0434\u0443\u044E\u0449\u0435\u043C <em>(uttara)</em> \u0430\u0444\u043E\u0440\u0438\u0437\u043C\u0435 <em>(s\u016Btra)</em>, [\u044F\u0441\u043D\u043E \u043F\u043E\u043A\u0430\u0437\u044B\u0432\u0430\u0435\u0442 \u0440\u0430\u0437\u043B\u0438\u0447\u0438\u0435] \u0432 \u043E\u0442\u043D\u043E\u0448\u0435\u043D\u0438\u0438 \u0442\u043E\u0433\u043E <em>(apek\u1E63ay\u0101)</em>, [\u0447\u0442\u043E \u0443\u043F\u043E\u043C\u044F\u043D\u0443\u0442\u043E] \u0432 \u044D\u0442\u043E\u043C <em>(etad)</em> \u0430\u0444\u043E\u0440\u0438\u0437\u043C\u0435 <em>(s\u016Btra)</em><sup>3</sup>||34||</p><hr><ol><li><p>\u0421\u0443\u0449\u0435\u0441\u0442\u0432\u0443\u0435\u0442 \u0434\u0440\u0443\u0433\u043E\u0439 \u0432\u043E\u0437\u043C\u043E\u0436\u043D\u044B\u0439 \u043F\u0435\u0440\u0435\u0432\u043E\u0434 \u0434\u043B\u044F &quot;sa\u1E41spar\u015Ba&quot;: \u043A\u043E\u043D\u0442\u0430\u043A\u0442. \u0422\u0430\u043A\u0438\u043C \u043E\u0431\u0440\u0430\u0437\u043E\u043C, \u0444\u0440\u0430\u0437\u0430 &quot;\u0432\u043E\u0441\u043F\u0440\u0438\u044F\u0442\u0438\u0435 <em>(sa\u1E41spar\u015Ba\u1E25)</em> \u0443\u0434\u043E\u0432\u043E\u043B\u044C\u0441\u0442\u0432\u0438\u044F \u0438 \u0431\u043E\u043B\u0438 <em>(sukha-du\u1E25kha)</em> \u043D\u0435 \u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F <em>(na)</em> \u0432\u043D\u0443\u0442\u0440\u0435\u043D\u043D\u0438\u043C <em>(antar)</em>&quot; \u043F\u0440\u0435\u0432\u0440\u0430\u0449\u0430\u0435\u0442\u0441\u044F \u0432 &quot;\u043A\u043E\u043D\u0442\u0430\u043A\u0442 <em>(sa\u1E41spar\u015Ba\u1E25)</em> \u0441 \u0443\u0434\u043E\u0432\u043E\u043B\u044C\u0441\u0442\u0432\u0438\u0435\u043C \u0438 \u0431\u043E\u043B\u044C\u044E <em>(sukha-du\u1E25kha)</em> \u043D\u0435 \u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F <em>(na)</em> \u0432\u043D\u0443\u0442\u0440\u0435\u043D\u043D\u0438\u043C <em>(antar)</em>&quot;. \u0412 \u043B\u044E\u0431\u043E\u043C \u0441\u043B\u0443\u0447\u0430\u0435, \u043A\u043E\u043D\u0435\u0447\u043D\u043E\u0435 \u0443\u0447\u0435\u043D\u0438\u0435 \u043E\u0434\u043D\u043E \u0438 \u0442\u043E \u0436\u0435: \u0443\u0434\u043E\u0432\u043E\u043B\u044C\u0441\u0442\u0432\u0438\u0435 \u0438 \u0431\u043E\u043B\u044C \u0441\u043E\u0432\u0441\u0435\u043C \u043D\u0435 \u0437\u0430\u0442\u0440\u0430\u0433\u0438\u0432\u0430\u044E\u0442 \u0435\u0433\u043E \u0441\u0443\u0449\u043D\u043E\u0441\u0442\u043D\u0443\u044E \u043F\u0440\u0438\u0440\u043E\u0434\u0443.</p></li><li><p>\u041E\u043D \u043D\u0435 \u043E\u0442\u043E\u0436\u0434\u0435\u0441\u0442\u0432\u043B\u044F\u0435\u0442\u0441\u044F \u0441\u043E \u0441\u0432\u043E\u0438\u043C \u0442\u043E\u043D\u043A\u0438\u043C \u0442\u0435\u043B\u043E\u043C (\u0438\u043D\u0442\u0435\u043B\u043B\u0435\u043A\u0442\u043E\u043C, \u044D\u0433\u043E, \u0443\u043C\u043E\u043C \u0438 \u0442\u043E\u043D\u043A\u0438\u043C\u0438 \u044D\u043B\u0435\u043C\u0435\u043D\u0442\u0430\u043C\u0438), \u043D\u0435 \u0433\u043E\u0432\u043E\u0440\u044F \u0443\u0436\u0435 \u043E \u0435\u0433\u043E \u0444\u0438\u0437\u0438\u0447\u0435\u0441\u043A\u043E\u043C \u0442\u0435\u043B\u0435. \u041A\u0440\u043E\u043C\u0435 \u0442\u043E\u0433\u043E, \u043D\u0435 \u0431\u0443\u0434\u0443\u0447\u0438 \u0434\u0430\u0436\u0435 \u0432\u043D\u0443\u0442\u0440\u0435\u043D\u043D\u0435 \u0437\u0430\u0442\u0440\u043E\u043D\u0443\u0442\u044B\u043C \u043D\u0438\u043A\u0430\u043A\u0438\u043C\u0438 \u043E\u0441\u0442\u0430\u0442\u043E\u0447\u043D\u044B\u043C\u0438 \u0432\u043F\u0435\u0447\u0430\u0442\u043B\u0435\u043D\u0438\u044F\u043C\u0438 \u043E\u0442 \u0434\u0435\u0439\u0441\u0442\u0432\u0438\u0439, \u043E\u043D \u0442\u0430\u043A\u0436\u0435 \u043D\u0435 \u043F\u043E\u0434\u0432\u0435\u0440\u0436\u0435\u043D \u0432\u043B\u0438\u044F\u043D\u0438\u044E \u0441\u0432\u043E\u0435\u0433\u043E \u043F\u0440\u0438\u0447\u0438\u043D\u043D\u043E\u0433\u043E (\u043A\u0430\u0443\u0437\u0430\u043B\u044C\u043D\u043E\u0433\u043E) \u0442\u0435\u043B\u0430. \u041E\u043D \u043F\u0440\u0435\u0431\u044B\u0432\u0430\u0435\u0442 \u0432 \u0441\u0432\u043E\u0435\u043C \u0434\u0443\u0445\u043E\u0432\u043D\u043E\u043C \u0442\u0435\u043B\u0435, \u043D\u0430\u0437\u044B\u0432\u0430\u0435\u043C\u043E\u043C \u0441\u0443\u043F\u0440\u0430\u043A\u0430\u0443\u0437\u0430\u043B\u044C\u043D\u044B\u043C, \u0438 \u0434\u0430\u0436\u0435 \u0437\u0430 \u0435\u0433\u043E \u043F\u0440\u0435\u0434\u0435\u043B\u0430\u043C\u0438. \u0421\u043B\u0435\u0434\u043E\u0432\u0430\u0442\u0435\u043B\u044C\u043D\u043E, \u043E\u043D \u0435\u0441\u0442\u044C \u0442\u043E\u0442, \u0447\u044C\u044F \u043F\u0440\u0438\u0440\u043E\u0434\u0430 \u2014 \u0447\u0438\u0441\u0442\u043E\u0435 \u0421\u043E\u0437\u043D\u0430\u043D\u0438\u0435. \u041D\u0430 \u0441\u0430\u043C\u043E\u043C \u0434\u0435\u043B\u0435, &quot;\u043A\u0430\u0436\u0434\u044B\u0439&quot; \u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F \u0447\u0438\u0441\u0442\u044B\u043C \u0421\u043E\u0437\u043D\u0430\u043D\u0438\u0435\u043C, \u043D\u043E \u0438\u0437-\u0437\u0430 \u043E\u0442\u043E\u0436\u0434\u0435\u0441\u0442\u0432\u043B\u0435\u043D\u0438\u044F \u0441 \u043A\u0430\u0443\u0437\u0430\u043B\u044C\u043D\u044B\u043C, \u0442\u043E\u043D\u043A\u0438\u043C \u0438 \u0444\u0438\u0437\u0438\u0447\u0435\u0441\u043A\u0438\u043C \u0442\u0435\u043B\u0430\u043C\u0438, \u0431\u043E\u043B\u044C\u0448\u0438\u043D\u0441\u0442\u0432\u043E \u043B\u044E\u0434\u0435\u0439 \u043D\u0435 \u043E\u0441\u043E\u0437\u043D\u0430\u0451\u0442 \u0441\u0432\u043E\u044E \u0441\u0443\u0449\u043D\u043E\u0441\u0442\u043D\u0443\u044E \u043F\u0440\u0438\u0440\u043E\u0434\u0443 \u0438, \u0441\u043B\u0435\u0434\u043E\u0432\u0430\u0442\u0435\u043B\u044C\u043D\u043E, \u0436\u0438\u0432\u0451\u0442 \u0432 \u0440\u0430\u0431\u0441\u0442\u0432\u0435.</p></li><li><p>\u0421 \u043E\u0434\u043D\u043E\u0439 \u0441\u0442\u043E\u0440\u043E\u043D\u044B, \u0442\u0435\u0440\u043C\u0438\u043D &quot;tu&quot; \u0438\u0441\u043F\u043E\u043B\u044C\u0437\u0443\u0435\u0442\u0441\u044F \u0432 \u0441\u043C\u044B\u0441\u043B\u0435 &quot;\u0442\u043E\u0433\u0434\u0430&quot; \u0432 \u0442\u0435\u043A\u0443\u0449\u0435\u043C \u0430\u0444\u043E\u0440\u0438\u0437\u043C\u0435, \u0447\u0442\u043E\u0431\u044B \u0437\u0430\u0432\u0435\u0440\u0448\u0438\u0442\u044C \u043E\u043F\u0438\u0441\u0430\u043D\u0438\u0435 \u043F\u0440\u043E\u0441\u0432\u0435\u0442\u043B\u0435\u043D\u043D\u043E\u0433\u043E \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u044F \u0432\u0435\u043B\u0438\u043A\u043E\u0433\u043E Yog\u012B. \u0421 \u0434\u0440\u0443\u0433\u043E\u0439 \u0441\u0442\u043E\u0440\u043E\u043D\u044B, \u0442\u043E \u0436\u0435 \u0441\u0430\u043C\u043E\u0435 \u0441\u043B\u043E\u0432\u043E \u0438\u0441\u043F\u043E\u043B\u044C\u0437\u0443\u0435\u0442\u0441\u044F \u0432 \u0437\u043D\u0430\u0447\u0435\u043D\u0438\u0438 &quot;\u043E\u0434\u043D\u0430\u043A\u043E&quot; \u0432 \u043F\u043E\u0441\u043B\u0435\u0434\u0443\u044E\u0449\u0435\u043C \u0430\u0444\u043E\u0440\u0438\u0437\u043C\u0435, \u043F\u0435\u0440\u0435\u0434 \u043E\u043F\u0438\u0441\u0430\u043D\u0438\u0435\u043C \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u044F \u043E\u0433\u0440\u0430\u043D\u0438\u0447\u0435\u043D\u043D\u043E\u0433\u043E \u0441\u0443\u0449\u0435\u0441\u0442\u0432\u0430. \u0422\u0430\u043A \u0438\u043B\u0438 \u0438\u043D\u0430\u0447\u0435, \u043E\u0433\u0440\u0430\u043D\u0438\u0447\u0435\u043D\u043D\u043E\u0435 \u0441\u0443\u0449\u0435\u0441\u0442\u0432\u043E \u0442\u0430\u043A\u0436\u0435 \u043C\u043E\u0436\u0435\u0442 \u0441\u0442\u0430\u0442\u044C \u043E\u0441\u0432\u043E\u0431\u043E\u0436\u0434\u0435\u043D\u043D\u043E\u0439 \u0434\u0443\u0448\u043E\u0439. \u042D\u0442\u043E \u0431\u0443\u0434\u0435\u0442 \u043F\u043E\u043A\u0430\u0437\u0430\u043D\u043E \u0431\u0443\u0434\u0443\u0449\u0438\u043C\u0438 \u0430\u0444\u043E\u0440\u0438\u0437\u043C\u0430\u043C\u0438. \u041D\u0430 \u0441\u0430\u043C\u043E\u043C \u0434\u0435\u043B\u0435, \u0435\u0441\u043B\u0438 \u0431\u044B \u043E\u0433\u0440\u0430\u043D\u0438\u0447\u0435\u043D\u043D\u044B\u0439 \u0438\u043D\u0434\u0438\u0432\u0438\u0434 &quot;\u0443\u0436\u0435 \u043D\u0435 \u0431\u044B\u043B \u0431\u044B&quot; \u0412\u044B\u0441\u0448\u0438\u043C \u0421\u0443\u0449\u0435\u0441\u0442\u0432\u043E\u043C, \u043E\u043D \u043D\u0435 \u0441\u043C\u043E\u0433 \u0431\u044B \u043E\u0441\u043E\u0437\u043D\u0430\u0442\u044C \u0415\u0433\u043E. \u041D\u0435\u0432\u043E\u0437\u043C\u043E\u0436\u043D\u043E \u0434\u043E\u0441\u0442\u0438\u0447\u044C \u0442\u043E\u0433\u043E, \u0447\u0435\u0433\u043E \u0443\u0436\u0435 \u0437\u0434\u0435\u0441\u044C \u043D\u0435\u0442. \u042D\u0442\u043E \u043E\u0447\u0435\u043D\u044C \u0442\u0440\u0443\u0434\u043D\u043E \u043F\u043E\u043D\u044F\u0442\u044C \u0431\u043E\u043B\u044C\u0448\u0438\u043D\u0441\u0442\u0432\u0443 \u043B\u044E\u0434\u0435\u0439, \u044F \u0437\u043D\u0430\u044E, \u043D\u043E \u044D\u0442\u043E \u0430\u0431\u0441\u043E\u043B\u044E\u0442\u043D\u0430\u044F \u043F\u0440\u0430\u0432\u0434\u0430. \u042F \u0437\u043D\u0430\u044E \u044D\u0442\u043E, \u0431\u043B\u0430\u0433\u043E\u0434\u0430\u0440\u044F \u043D\u0435\u043F\u043E\u0441\u0440\u0435\u0434\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u043C\u0443 \u043E\u043F\u044B\u0442\u0443, \u0430 \u043D\u0435 \u043F\u0440\u043E\u0441\u0442\u043E \u0431\u043B\u0430\u0433\u043E\u0434\u0430\u0440\u044F \u043B\u043E\u0433\u0438\u043A\u0435 \u0438 \u0434\u043E\u043A\u0430\u0437\u0430\u0442\u0435\u043B\u044C\u0441\u0442\u0432\u0430\u043C.</p><p>\u041A\u043E\u0433\u0434\u0430 \u0432\u044B \u043E\u0449\u0443\u0442\u0438\u0442\u0435 \u0445\u043E\u0442\u044F \u0431\u044B \u0435\u0434\u0438\u043D\u043E\u0436\u0434\u044B \u0441\u0432\u043E\u0435 \u0441\u043E\u0431\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u0435 \u0412\u044B\u0441\u0448\u0435\u0435 \u042F, \u0432\u044B \u043E\u0441\u043E\u0437\u043D\u0430\u0435\u0442\u0435, \u0447\u0442\u043E \u0432\u043E\u0441\u043F\u0440\u0438\u043D\u0438\u043C\u0430\u043B\u0438 \u0415\u0433\u043E \u0432\u0441\u0435\u0433\u0434\u0430. \u0414\u0440\u0443\u0433\u0430\u044F \u0442\u0440\u0443\u0434\u043D\u0430\u044F \u0434\u043B\u044F \u043F\u043E\u043D\u0438\u043C\u0430\u043D\u0438\u044F \u0438\u0441\u0442\u0438\u043D\u0430 \u0434\u043B\u044F \u0431\u043E\u043B\u044C\u0448\u0438\u043D\u0441\u0442\u0432\u0430 \u0447\u0438\u0442\u0430\u0442\u0435\u043B\u0435\u0439, \u043D\u043E \u044D\u0442\u043E \u0441\u043E\u0432\u0435\u0440\u0448\u0435\u043D\u043D\u043E \u0432\u0435\u0440\u043D\u043E. \u0415\u0441\u043B\u0438 \u0432\u044B \u043D\u0435 \u043F\u043E\u043D\u0438\u043C\u0430\u0435\u0442\u0435 \u044D\u0442\u043E \u0441\u0435\u0439\u0447\u0430\u0441, \u043D\u0435 \u0431\u0435\u0441\u043F\u043E\u043A\u043E\u0439\u0442\u0435\u0441\u044C, \u043F\u043E\u0442\u043E\u043C\u0443 \u0447\u0442\u043E \u0440\u0430\u043D\u043E \u0438\u043B\u0438 \u043F\u043E\u0437\u0434\u043D\u043E \u0432\u044B \u043F\u043E\u0439\u043C\u0435\u0442\u0435 \u044D\u0442\u043E, \u0435\u0441\u043B\u0438 \u0431\u0443\u0434\u0435\u0442\u0435 \u0443\u043F\u043E\u0440\u043D\u044B \u0432 \u0447\u0442\u0435\u043D\u0438\u0438, \u043F\u0440\u0430\u043A\u0442\u0438\u043A\u0435 \u0438 \u0442.\u043F. \u041F\u0440\u043E\u0434\u043E\u043B\u0436\u0430\u0439\u0442\u0435 \u043F\u0438\u043B\u0438\u0442\u044C \u0432\u0435\u0442\u043A\u0443 \u0441 &quot;\u043F\u0440\u0430\u0432\u043E\u0439&quot; \u0441\u0442\u043E\u0440\u043E\u043D\u044B, \u0438 \u0432 \u043A\u043E\u043D\u0446\u0435 \u043A\u043E\u043D\u0446\u043E\u0432 \u0432\u044B \u0432\u043D\u0435\u0437\u0430\u043F\u043D\u043E \u0443\u043F\u0430\u0434\u0435\u0442\u0435. \u041A\u043E\u0433\u0434\u0430 \u0432\u044B \u043F\u0438\u043B\u0438\u0442\u0435 \u0432 \u044D\u0442\u043E\u043C \u043F\u043E\u043B\u043E\u0436\u0435\u043D\u0438\u0438, \u043D\u0438\u0447\u0435\u0433\u043E \u043D\u0435 \u043F\u0440\u043E\u0438\u0441\u0445\u043E\u0434\u0438\u0442, \u043F\u043E\u043A\u0430 \u0432\u044B \u043D\u0435 \u0443\u0441\u043B\u044B\u0448\u0438\u0442\u0435 \u0445\u0440\u0443\u0441\u0442, \u0445\u0430-\u0445\u0430. \u042F \u0433\u043E\u0432\u043E\u0440\u044E \u0441\u0435\u0440\u044C\u0435\u0437\u043D\u043E, \u043D\u0435\u0441\u043C\u043E\u0442\u0440\u044F \u043D\u0430 \u043C\u043E\u0439 \u0441\u043C\u0435\u0445. \u0412\u0441\u0435 \u044D\u0442\u043E \u041F\u0438\u0441\u0430\u043D\u0438\u0435 \u0442\u0430\u043A\u0436\u0435 \u0443\u0447\u0438\u043B\u043E \u0442\u043E\u0439 \u0436\u0435 \u0438\u0441\u0442\u0438\u043D\u0435. \u0415\u0441\u043B\u0438 \u0432\u044B \u0431\u0443\u0434\u0435\u0442\u0435 \u0447\u0438\u0442\u0430\u0442\u044C \u0435\u0433\u043E \u0441\u043D\u043E\u0432\u0430 \u0438 \u0441\u043D\u043E\u0432\u0430, \u0432\u0435\u0442\u043A\u0430 \u0431\u0443\u0434\u0435\u0442 \u043F\u043E\u0434\u043F\u0438\u043B\u0435\u043D\u0430 \u0438 \u0432\u044B \u043E\u0441\u043E\u0437\u043D\u0430\u0435\u0442\u0435, \u0447\u0442\u043E \u0432\u044B \u2014 \u0412\u044B\u0441\u0448\u0430\u044F \u0421\u0430\u043C\u043E\u0441\u0442\u044C. \u042D\u0442\u043E \u0432\u0441\u0435\u0433\u0434\u0430 \u043E\u0434\u043D\u0430 \u0438 \u0442\u0430 \u0436\u0435 \u0438\u0441\u0442\u043E\u0440\u0438\u044F, &quot;\u043E\u0447\u0435\u0432\u0438\u0434\u043D\u043E&quot;, \u0447\u0442\u043E \u0442\u043E\u043B\u044C\u043A\u043E \u0442\u0435\u043B\u0430/\u043B\u0438\u0447\u043D\u043E\u0441\u0442\u0438 \u043C\u0435\u043D\u044F\u044E\u0442\u0441\u044F. \u041A\u043E\u0440\u043E\u0447\u0435 \u0433\u043E\u0432\u043E\u0440\u044F, \u044D\u0442\u043E \u0432\u0441\u0435\u0433\u0434\u0430 \u0438\u0441\u0442\u043E\u0440\u0438\u044F \u043E \u0442\u043E\u043C, \u043A\u043E\u0433\u0434\u0430 &quot;\u0422\u044B&quot; \u0441\u0442\u0430\u043D\u043E\u0432\u0438\u0448\u044C\u0441\u044F &quot;\u0441\u043E\u0431\u043E\u0439&quot;, \u0430 \u0437\u0430\u0442\u0435\u043C \u043E\u043F\u044F\u0442\u044C &quot;\u0421\u043E\u0431\u043E\u0439&quot;, \u043F\u043E\u0441\u043A\u043E\u043B\u044C\u043A\u0443 \u0437\u0434\u0435\u0441\u044C \u0431\u043E\u043B\u044C\u0448\u0435 \u043D\u0438\u043A\u043E\u0433\u043E \u043D\u0435\u0442. \u0412\u043E\u0442 \u043F\u043E\u0447\u0435\u043C\u0443 \u0430\u0444\u043E\u0440\u0438\u0437\u043C \u0433\u043B\u0430\u0441\u0438\u0442, \u0447\u0442\u043E \u0432\u0435\u043B\u0438\u043A\u0438\u0439 Yog\u012B \u2014 keval\u012B, \u0438\u043B\u0438 \u043E\u0434\u0438\u043D.</p></li></ol></div><div class="stanza"><a href="#s3.35" id="s3.35" class="num">3.35</a><div class="sans"><p>\u092F\u0926\u093E\u0939\u2014</p><blockquote><p><strong>\u092E\u094B\u0939\u092A\u094D\u0930\u0924\u093F\u0938\u0902\u0939\u0924\u0938\u094D\u0924\u0941 \u0915\u0930\u094D\u092E\u093E\u0924\u094D\u092E\u093E\u0965\u0969\u096B\u0965</strong></p></blockquote><p>\u092E\u094B\u0939\u0947\u0928\u093E\u091C\u094D\u091E\u093E\u0928\u0947\u0928 \u092A\u094D\u0930\u0924\u093F\u0938\u0902\u0939\u0924\u0938\u094D\u0924\u0926\u0947\u0915\u0918\u0928\u0938\u094D\u0924\u0924 \u090F\u0935 \u0938\u0941\u0916\u0926\u0941\u0903\u0916\u093E\u0936\u094D\u0930\u092F\u094B \u092F\u0903 \u0938 \u092A\u0941\u0928\u0903 \u0915\u0930\u094D\u092E\u093E\u0924\u094D\u092E\u093E \u0928\u093F\u0924\u094D\u092F\u0902 \u0936\u0941\u092D\u093E\u0936\u0941\u092D\u0915\u0932\u0919\u094D\u0915\u093F\u0924\u0903\u0964 \u0924\u0926\u0941\u0915\u094D\u0924\u0902 \u0924\u0924\u094D\u0930\u0948\u0935</p><blockquote><p>\u092F\u0926\u0935\u093F\u0926\u094D\u092F\u093E\u0935\u0943\u0924\u0924\u092F\u093E \u0935\u093F\u0915\u0932\u094D\u092A\u0935\u093F\u0927\u093F\u092F\u094B\u0917\u0924\u0903\u0964<br> \u0936\u093F\u0935\u093E\u0926\u0940\u0928\u094D\u0928\u0948\u0935 \u091D\u091F\u093F\u0924\u093F \u0938\u092E\u0941\u0926\u094D\u092D\u093E\u0935\u092F\u0924\u0947\u093D\u0916\u093F\u0932\u093E\u0928\u094D\u0965<br> \u0924\u0924\u0903 \u0936\u0941\u092D\u093E\u0936\u0941\u092D\u093E \u092D\u093E\u0935\u093E \u0932\u0915\u094D\u0937\u094D\u092F\u0928\u094D\u0924\u0947 \u0924\u0926\u094D\u0935\u0936\u0924\u094D\u0935\u0924\u0903\u0964<br> \u0905\u0936\u0941\u092D\u0947\u092D\u094D\u092F\u0936\u094D\u091A \u092D\u093E\u0935\u0947\u092D\u094D\u092F\u0903 \u092A\u0930\u0902 \u0926\u0941\u0903\u0916\u0902 \u092A\u094D\u0930\u091C\u093E\u092F\u0924\u0947\u0965</p></blockquote><p>\u0907\u0924\u093F\u0965\u0969\u096B\u0965</p></div><hr><div class="trans"><p>Yad\u0101ha\u2014</p><blockquote><p><strong>Mohapratisa\u1E41hatastu karm\u0101tm\u0101||35||</strong></p></blockquote><p>Mohen\u0101j\xF1\u0101nena pratisa\u1E41hatastadekaghanastata eva sukhadu\u1E25kh\u0101\u015Brayo ya\u1E25 sa puna\u1E25 karm\u0101tm\u0101 nitya\u1E41 \u015Bubh\u0101\u015Bubhakala\u1E45kita\u1E25| Tadukta\u1E41 tatraiva</p><blockquote><p>Yadavidy\u0101v\u1E5Btatay\u0101 vikalpavidhiyogata\u1E25|<br> \u015Aiv\u0101d\u012Bnnaiva jha\u1E6Diti samudbh\u0101vayate&#39;khil\u0101n||<br> Tata\u1E25 \u015Bubh\u0101\u015Bubh\u0101 bh\u0101v\u0101 lak\u1E63yante tadva\u015Batvata\u1E25|<br> A\u015Bubhebhya\u015Bca bh\u0101vebhya\u1E25 para\u1E41 du\u1E25kha\u1E41 praj\u0101yate||</p></blockquote><p>iti||35||</p></div><hr><p>[\u015Aiva, \u0430\u0432\u0442\u043E\u0440 \u015Aivas\u016Btra-s,] \u0441\u043A\u0430\u0437\u0430\u043B <em>(\u0101ha)</em> \u0442\u0430\u043A --\u0442.\u0435. \u0441\u043B\u0435\u0434\u0443\u044E\u0449\u0435\u0435-- <em>(yad)</em>\u2014</p><blockquote><p><strong>\u041E\u0434\u043D\u0430\u043A\u043E <em>(tu)</em>, \u0442\u043E\u0442, \u043A\u0442\u043E \u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F \u043F\u043B\u043E\u0442\u043D\u043E\u0439 \u043C\u0430\u0441\u0441\u043E\u0439 <em>(pratisa\u1E41hata\u1E25)</em> \u0437\u0430\u0431\u043B\u0443\u0436\u0434\u0435\u043D\u0438\u044F <em>(moha)</em> [\u0432\u0441\u0435\u0433\u043E \u043B\u0438\u0448\u044C] \u0432\u043E\u0432\u043B\u0435\u0447\u0435\u043D <em>(\u0101tm\u0101)</em> \u0432 \u0434\u0435\u0439\u0441\u0442\u0432\u0438\u044F <em>(karma)</em>||35||</strong></p></blockquote><p>\u0421 \u0437\u0430\u0431\u043B\u0443\u0436\u0434\u0435\u043D\u0438\u0435\u043C [\u0438\u043B\u0438] \u043D\u0435\u0432\u0435\u0434\u0435\u043D\u0438\u0435\u043C <em>(mohena aj\xF1\u0101nena)</em>. [\u0422\u0435\u0440\u043C\u0438\u043D] pratisa\u1E41hata <em>(pratisa\u1E41hata\u1E25)</em> [\u043E\u0437\u043D\u0430\u0447\u0430\u0435\u0442], \u0447\u0442\u043E \u043E\u043D --\u0442.\u0435. \u043E\u0433\u0440\u0430\u043D\u0438\u0447\u0435\u043D\u043D\u044B\u0439 \u0438\u043D\u0434\u0438\u0432\u0438\u0434-- \u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F \u043F\u043B\u043E\u0442\u043D\u043E\u0439 \u043C\u0430\u0441\u0441\u043E\u0439 <em>(eka-ghana\u1E25)</em>, [\u0437\u0430\u043F\u043E\u043B\u043D\u0435\u043D\u043D\u043E\u0439] \u0442\u0435\u043C --\u0442.\u0435. \u0437\u0430\u0431\u043B\u0443\u0436\u0434\u0435\u043D\u0438\u0435\u043C, \u0438\u043B\u0438 \u043D\u0435\u0432\u0435\u0434\u0435\u043D\u0438\u0435\u043C-- <em>(tad)</em>. \u041F\u043E \u044D\u0442\u043E\u0439 \u0441\u0430\u043C\u043E\u0439 \u043F\u0440\u0438\u0447\u0438\u043D\u0435 <em>(tatas eva)</em>, \u043E\u043D \u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F \u043F\u043E\u043B\u0443\u0447\u0430\u0442\u0435\u043B\u0435\u043C <em>(\u0101\u015Braya\u1E25 ya\u1E25)</em> \u043D\u0430\u0441\u043B\u0430\u0436\u0434\u0435\u043D\u0438\u044F \u0438 \u0431\u043E\u043B\u0438 <em>(sukha-du\u1E25kha)</em>. \u0421 \u0434\u0440\u0443\u0433\u043E\u0439 \u0441\u0442\u043E\u0440\u043E\u043D\u044B <em>(punar)</em>, \u0438\u0437-\u0437\u0430 \u0441\u0432\u043E\u0435\u0439 \u0432\u043E\u0432\u043B\u0435\u0447\u0435\u043D\u043D\u043E\u0441\u0442\u0438 <em>(\u0101tm\u0101)</em> \u0432 \u0434\u0435\u0439\u0441\u0442\u0432\u0438\u044F <em>(karma)</em>, \u043E\u043D <em>(sa\u1E25)</em> \u0432\u0441\u0435\u0433\u0434\u0430 \u0437\u0430\u043F\u044F\u0442\u043D\u0430\u043D <em>(nityam kala\u1E45kita\u1E25)</em> \u0445\u043E\u0440\u043E\u0448\u0438\u043C\u0438 \u0438 \u043F\u043B\u043E\u0445\u0438\u043C\u0438 \u043F\u043E\u0441\u0442\u0443\u043F\u043A\u0430\u043C\u0438 <em>(\u015Bubha-a\u015Bubha)</em>|</p><p>\u042D\u0442\u043E <em>(tad)</em> \u0431\u044B\u043B\u043E \u043F\u0440\u043E\u0432\u043E\u0437\u0433\u043B\u0430\u0448\u0435\u043D\u043E <em>(uktam)</em> \u0432 \u044D\u0442\u043E\u043C \u0441\u0430\u043C\u043E\u043C [\u041F\u0438\u0441\u0430\u043D\u0438\u0438] --\u0432 K\u0101lik\u0101krama-- <em>(tatra eva)</em>:</p><blockquote><p>&quot;[\u0412 \u0441\u043B\u0443\u0447\u0430\u0435 \u043D\u0435\u0432\u0435\u0436\u0435\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u0433\u043E \u0447\u0435\u043B\u043E\u0432\u0435\u043A\u0430,] \u0431\u0443\u0434\u0443\u0447\u0438 \u043E\u0445\u0432\u0430\u0447\u0435\u043D\u043D\u044B\u043C, \u0438\u043B\u0438 \u043F\u043E\u043A\u0440\u044B\u0442\u044B\u043C <em>(\u0101v\u1E5Btatay\u0101)</em> \u043D\u0435\u0432\u0435\u0434\u0435\u043D\u0438\u0435\u043C <em>(avidy\u0101)</em> \u043E \u0422\u043E\u043C --\u043E \u0421\u0430\u043C\u043E\u0441\u0442\u0438-- <em>(yad)</em> [\u0438] \u0438\u0437-\u0437\u0430 <em>(yogatas)</em> \u0438\u0441\u043F\u043E\u043B\u044C\u0437\u043E\u0432\u0430\u043D\u0438\u044F, \u0438\u043B\u0438 \u043F\u0440\u0438\u043C\u0435\u043D\u0435\u043D\u0438\u044F <em>(vidhi)</em> \u043C\u044B\u0441\u043B\u0435\u0439 <em>(vikalpa)</em>, \u043E\u043D \u043D\u0435 \u0441\u0440\u0430\u0437\u0443 \u043E\u0441\u043E\u0437\u043D\u0430\u0435\u0442 <em>(na eva jha\u1E6Diti samudbh\u0101vayate)</em> \u0432\u0441\u0435 [\u0442\u0430\u0442\u0442\u0432\u044B, \u0438\u043B\u0438 \u043A\u0430\u0442\u0435\u0433\u043E\u0440\u0438\u0438] <em>(akhil\u0101n)</em>, \u043D\u0430\u0447\u0438\u043D\u0430\u044E\u0449\u0438\u0435\u0441\u044F \u0441 <em>(\u0101d\u012Bn)</em> \u015Aiva <em>(\u015Biva)</em> [\u043A\u0430\u043A \u0441\u0432\u043E\u044E \u0441\u043E\u0431\u0441\u0442\u0432\u0435\u043D\u043D\u0443\u044E \u0441\u0443\u0449\u043D\u043E\u0441\u0442\u043D\u0443\u044E \u043F\u0440\u0438\u0440\u043E\u0434\u0443, \u043A\u043E\u0442\u043E\u0440\u0430\u044F \u0435\u0441\u0442\u044C \u043F\u043B\u043E\u0442\u043D\u0430\u044F \u043C\u0430\u0441\u0441\u0430 \u0421\u043E\u0437\u043D\u0430\u043D\u0438\u044F]<sup>1</sup></p></blockquote><p>. \u0422\u043E\u0433\u0434\u0430 <em>(tatas)</em>, \u043F\u043E\u044F\u0432\u043B\u044F\u044E\u0442\u0441\u044F <em>(lak\u1E63yante)</em> \u0445\u043E\u0440\u043E\u0448\u0438\u0435 \u0438 \u043F\u043B\u043E\u0445\u0438\u0435 <em>(\u015Bubha-a\u015Bubh\u0101\u1E25)</em> \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u044F <em>(bh\u0101v\u0101\u1E25)</em> ; \u0438 <em>(ca)</em> \u043F\u043E\u0441\u043A\u043E\u043B\u044C\u043A\u0443 [\u0442\u0430\u043A\u043E\u0439 \u0447\u0435\u043B\u043E\u0432\u0435\u043A] \u043D\u0430\u0445\u043E\u0434\u0438\u0442\u0441\u044F \u043F\u043E\u0434 \u043A\u043E\u043D\u0442\u0440\u043E\u043B\u0435\u043C <em>(va\u015Batvata\u1E25)</em> \u044D\u0442\u043E\u0433\u043E [\u043D\u0435\u0432\u0435\u0434\u0435\u043D\u0438\u044F \u043E \u0441\u0432\u043E\u0435\u043C \u0441\u043E\u0431\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u043C \u042F] <em>(tad)</em>, \u0432\u0435\u043B\u0438\u043A\u0430\u044F <em>(param)</em> \u0431\u043E\u043B\u044C <em>(du\u1E25kham)</em> \u043F\u0440\u0438\u0445\u043E\u0434\u0438\u0442 \u043A [\u043D\u0435\u043C\u0443] <em>(praj\u0101yate)</em> \u0438\u0437-\u0437\u0430 [\u0432\u044B\u0448\u0435\u0443\u043F\u043E\u043C\u044F\u043D\u0443\u0442\u044B\u0445] \u043F\u043B\u043E\u0445\u0438\u0445 \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u0439 <em>(a\u015Bubhebhya\u1E25... bh\u0101vebhya\u1E25... iti)</em><sup>2</sup>&quot;||</p><p>||35||</p><hr><ol><li><p>\u041E\u0447\u0435\u0432\u0438\u0434\u043D\u043E, \u0442\u0440\u0435\u0431\u043E\u0432\u0430\u043D\u0438\u044F \u0440\u0430\u0437\u043C\u0435\u0440\u0430/\u0440\u0438\u0442\u043C\u0430 \u0437\u0430\u0441\u0442\u0430\u0432\u0438\u043B\u0438 \u0430\u0432\u0442\u043E\u0440\u0430 \u043E\u043F\u0443\u0441\u0442\u0438\u0442\u044C \u043D\u0435\u0441\u043A\u043E\u043B\u044C\u043A\u043E \u0441\u043B\u043E\u0432. \u0422\u043E\u0433\u0434\u0430 \u0447\u0442\u043E-\u0442\u043E \u0432\u0440\u043E\u0434\u0435 \u044D\u0442\u043E\u0433\u043E \u0434\u043E\u043B\u0436\u043D\u043E \u0431\u044B\u043B\u043E \u0431\u044B \u0431\u044B\u0442\u044C \u043D\u0430\u043F\u0438\u0441\u0430\u043D\u043E: &quot; \u0936\u093F\u0935\u093E\u0926\u093F\u0924\u0924\u094D\u0924\u094D\u0935\u093E\u0902\u0936\u094D\u091A\u093F\u0926\u094D\u0918\u0928\u0938\u094D\u0935\u092D\u093E\u0935\u0924\u092F\u093E \u0928\u0948\u0935 \u091D\u091F\u093F\u0924\u093F \u0938\u092E\u0941\u0926\u094D\u092D\u093E\u0935\u092F\u0924\u0947\u093D\u0916\u093F\u0932\u093E\u0928\u094D\u0965 &quot; - &quot;\u015Aiv\u0101ditattv\u0101\u1E41\u015Bcidghanasvabh\u0101vatay\u0101 naiva jha\u1E6Diti samudbh\u0101vayate&#39;khil\u0101n||&quot; \u043E\u043D \u043D\u0435 \u0441\u0440\u0430\u0437\u0443 \u043E\u0441\u043E\u0437\u043D\u0430\u0435\u0442 <em>(na eva jha\u1E6Diti samudbh\u0101vayate)</em> \u0432\u0441\u0435 <em>(akhil\u0101n)</em> \u0442\u0430\u0442\u0442\u0432\u044B, \u0438\u043B\u0438 \u043A\u0430\u0442\u0435\u0433\u043E\u0440\u0438\u0438 <em>(tattv\u0101n)</em>, \u043D\u0430\u0447\u0438\u043D\u0430\u044F \u0441 <em>(\u0101di)</em> \u015Aiva <em>(\u015Biva)</em> \u043A\u0430\u043A [\u0441\u0432\u043E\u044E \u0441\u043E\u0431\u0441\u0442\u0432\u0435\u043D\u043D\u0443\u044E] \u0441\u0443\u0449\u043D\u043E\u0441\u0442\u043D\u0443\u044E \u043F\u0440\u0438\u0440\u043E\u0434\u0443 <em>(sva-bh\u0101vatay\u0101)</em>, \u043A\u043E\u0442\u043E\u0440\u0430\u044F \u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F \u043F\u043B\u043E\u0442\u043D\u043E\u0439 \u043C\u0430\u0441\u0441\u043E\u0439 <em>(ghana)</em> \u0421\u043E\u0437\u043D\u0430\u043D\u0438\u044F <em>(cit)</em>&quot;.</p><p>\u0421\u043F\u0440\u044F\u0436\u0435\u043D\u0438\u0435 &quot;samudbh\u0101vayate&quot; (\u0442.\u0435. \u043E\u043D \u043F\u043E\u043B\u0430\u0433\u0430\u0435\u0442, \u0434\u0443\u043C\u0430\u0435\u0442 \u0438 \u0442.\u0434.) \u0441\u043B\u0435\u0434\u0443\u0435\u0442 \u0438\u043D\u0442\u0435\u0440\u043F\u0440\u0435\u0442\u0438\u0440\u043E\u0432\u0430\u0442\u044C \u0437\u0434\u0435\u0441\u044C \u043A\u0430\u043A &quot;par\u0101m\u1E5B\u015Bati&quot; (\u043E\u043D \u043C\u044B\u0441\u043B\u0435\u043D\u043D\u043E \u0443\u0445\u0432\u0430\u0442\u044B\u0432\u0430\u0435\u0442, \u043E\u0441\u043E\u0437\u043D\u0430\u0435\u0442 \u0438 \u0442.\u043F.). \u0421\u043B\u043E\u0432\u043E &quot;jha\u1E6Diti&quot; \u043E\u0437\u043D\u0430\u0447\u0430\u0435\u0442 &quot;\u0442\u043E\u0442\u0447\u0430\u0441/\u043D\u0435\u043C\u0435\u0434\u043B\u0435\u043D\u043D\u043E&quot;. \u041F\u043E\u043B\u0443\u0447\u0435\u043D\u043D\u043E\u0435 \u0432 \u0440\u0435\u0437\u0443\u043B\u044C\u0442\u0430\u0442\u0435 \u0437\u043D\u0430\u0447\u0435\u043D\u0438\u0435 \u0432\u0441\u0435\u0433\u043E \u0443\u0442\u0432\u0435\u0440\u0436\u0434\u0435\u043D\u0438\u044F \u0441\u043E\u0441\u0442\u043E\u0438\u0442 \u0432 \u0442\u043E\u043C, \u0447\u0442\u043E \u043D\u0435\u0432\u0435\u0436\u0435\u0441\u0442\u0432\u0435\u043D\u043D\u044B\u0439 \u0447\u0435\u043B\u043E\u0432\u0435\u043A \u0441\u0442\u0430\u043D\u043E\u0432\u0438\u0442\u0441\u044F \u0436\u0435\u0440\u0442\u0432\u043E\u0439 M\u0101y\u012Byamala (\u041C\u0430\u0439\u0438\u0447\u0435\u0441\u043A\u043E\u0433\u043E \u0437\u0430\u0433\u0440\u044F\u0437\u043D\u0435\u043D\u0438\u044F) \u0438, \u0441\u043B\u0435\u0434\u043E\u0432\u0430\u0442\u0435\u043B\u044C\u043D\u043E, \u0438\u0441\u043F\u044B\u0442\u044B\u0432\u0430\u0435\u0442 \u0434\u0432\u043E\u0439\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u0441\u0442\u044C. \u0414\u0440\u0443\u0433\u0438\u043C\u0438 \u0441\u043B\u043E\u0432\u0430\u043C\u0438, \u043E\u043D \u0432\u043E\u0441\u043F\u0440\u0438\u043D\u0438\u043C\u0430\u0435\u0442 \u0432\u0441\u0435 \u0442\u0430\u0442\u0442\u0432\u044B, \u043A\u0430\u043A \u043E\u0442\u043B\u0438\u0447\u043D\u044B\u0435 \u043E\u0442 \u0441\u0435\u0431\u044F.</p></li><li><p>\u042D\u0442\u0438 \u043F\u043B\u043E\u0445\u0438\u0435 \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u044F \u043A\u043E\u0440\u0435\u043D\u044F\u0442\u0441\u044F \u0432 K\u0101rmamala (\u041A\u0430\u0440\u043C\u0438\u0447\u0435\u0441\u043A\u043E\u043C \u0437\u0430\u0433\u0440\u044F\u0437\u043D\u0435\u043D\u0438\u0438). \u042D\u0442\u043E \u0437\u0430\u0433\u0440\u044F\u0437\u043D\u0435\u043D\u0438\u0435 \u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F \u043F\u043E\u043B\u043D\u044B\u043C \u0437\u0430\u043C\u0435\u0448\u0430\u0442\u0435\u043B\u044C\u0441\u0442\u0432\u043E\u043C \u0432 \u043E\u0442\u043D\u043E\u0448\u0435\u043D\u0438\u0438 \u0440\u0435\u0430\u043B\u044C\u043D\u043E\u0433\u043E \u0414\u0435\u043B\u0430\u0442\u0435\u043B\u044F \u0434\u0435\u0439\u0441\u0442\u0432\u0438\u0439. \u041F\u043E\u0441\u043A\u043E\u043B\u044C\u043A\u0443 \u044D\u0442\u043E\u0442 \u0447\u0435\u043B\u043E\u0432\u0435\u043A \u0438\u0433\u043D\u043E\u0440\u0438\u0440\u0443\u0435\u0442 \u0442\u043E, \u0447\u0442\u043E \u0413\u043E\u0441\u043F\u043E\u0434\u044C \u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F \u0440\u0435\u0430\u043B\u044C\u043D\u044B\u043C \u0418\u0441\u043F\u043E\u043B\u043D\u0438\u0442\u0435\u043B\u0435\u043C \u0432\u0441\u0435\u0433\u043E, \u043E\u043D \u0434\u0443\u043C\u0430\u0435\u0442, \u0447\u0442\u043E \u043E\u043D \u0434\u0435\u043B\u0430\u0435\u0442. \u0422\u0430\u043A\u0438\u043C \u043E\u0431\u0440\u0430\u0437\u043E\u043C, \u043E\u043D \u0432\u043E\u0432\u043B\u0435\u043A\u0430\u0435\u0442\u0441\u044F \u0432 \u0445\u043E\u0440\u043E\u0448\u0438\u0435 \u0438 \u043F\u043B\u043E\u0445\u0438\u0435 \u0434\u0435\u0439\u0441\u0442\u0432\u0438\u044F, \u0438 \u0438\u0437-\u0437\u0430 \u043D\u0435\u0438\u0437\u0431\u0435\u0436\u043D\u044B\u0445 \u043F\u043B\u043E\u0434\u043E\u0432 \u0435\u0433\u043E \u043F\u043B\u043E\u0445\u0438\u0445 \u043F\u043E\u0441\u0442\u0443\u043F\u043A\u043E\u0432 \u043A \u043D\u0435\u043C\u0443 \u043F\u0440\u0438\u0445\u043E\u0434\u0438\u0442 \u0443\u0436\u0430\u0441\u043D\u0430\u044F \u0431\u043E\u043B\u044C.</p></li></ol></div><div class="stanza"><a href="#s3.36" id="s3.36" class="num">3.36</a><div class="sans"><p>\u090F\u0935\u092E\u0940\u0926\u0943\u0936\u0938\u094D\u092F\u093E\u092A\u093F \u0915\u0930\u094D\u092E\u093E\u0924\u094D\u092E\u0928\u094B \u092F\u0926\u093E\u0928\u0930\u094D\u0917\u0932\u092E\u093E\u0939\u0947\u0936\u0936\u0915\u094D\u0924\u093F\u092A\u093E\u0924\u0935\u0936\u094B\u0928\u094D\u092E\u093F\u0937\u093F\u0924\u0938\u0939\u091C\u0938\u094D\u0935\u093E\u0924\u0928\u094D\u0924\u094D\u0930\u094D\u092F\u092F\u094B\u0917\u094B \u092D\u0935\u0924\u093F \u0924\u0926\u093E\u0938\u094D\u092F\u2014</p><blockquote><p><strong>\u092D\u0947\u0926\u0924\u093F\u0930\u0938\u094D\u0915\u093E\u0930\u0947 \u0938\u0930\u094D\u0917\u093E\u0928\u094D\u0924\u0930\u0915\u0930\u094D\u092E\u0924\u094D\u0935\u092E\u094D\u0965\u0969\u096C\u0965</strong></p></blockquote><p>\u0936\u0930\u0940\u0930\u092A\u094D\u0930\u093E\u0923\u093E\u0926\u094D\u092F\u0939\u0928\u094D\u0924\u093E\u092D\u093F\u092E\u093E\u0928\u093E\u0924\u094D\u092E\u0928\u0903 \u0938\u0915\u0932\u092A\u094D\u0930\u0932\u092F\u093E\u0915\u0932\u093E\u0926\u093F\u092A\u094D\u0930\u092E\u093E\u0924\u094D\u0930\u0941\u091A\u093F\u0924\u0938\u094D\u092F \u092D\u0947\u0926\u0938\u094D\u092F \u0924\u093F\u0930\u0938\u094D\u0915\u093E\u0930\u0947 \u0938\u094D\u0925\u093F\u0924\u0938\u094D\u092F\u093E\u092A\u093F \u091A\u093F\u0926\u094D\u0918\u0928\u0938\u094D\u0935\u092D\u093E\u0935\u094B\u0928\u094D\u092E\u091C\u094D\u091C\u0928\u093E\u0926\u092A\u0939\u0938\u094D\u0924\u0928\u0947 \u0938\u0924\u093F \u0915\u094D\u0930\u092E\u0947\u0923 \u092E\u0928\u094D\u0924\u094D\u0930\u092E\u0928\u094D\u0924\u094D\u0930\u0947\u0936\u094D\u0935\u0930\u092E\u0928\u094D\u0924\u094D\u0930\u092E\u0939\u0947\u0936\u094D\u0935\u0930\u093E\u0924\u094D\u092E\u0915\u0938\u094D\u0935\u092E\u093E\u0939\u093E\u0924\u094D\u092E\u094D\u092F\u093E\u0935\u093E\u092A\u094D\u0924\u094C \u0938\u0930\u094D\u0917\u093E\u0928\u094D\u0924\u0930\u0915\u0930\u094D\u092E\u0924\u094D\u0935\u0902 \u092F\u0925\u093E\u092D\u093F\u0932\u0937\u093F\u0924\u0928\u093F\u0930\u094D\u092E\u0947\u092F\u0928\u093F\u0930\u094D\u092E\u093E\u0924\u0943\u0924\u094D\u0935\u0902 \u092D\u0935\u0924\u093F\u0964 \u0924\u0925\u093E \u091A \u0936\u094D\u0930\u0940\u0938\u094D\u0935\u091A\u094D\u091B\u0928\u094D\u0926\u0947</p><blockquote><p>\u0924\u094D\u0930\u093F\u0917\u0941\u0923\u0947\u0928 \u0924\u0941 \u091C\u092A\u094D\u092F\u0947\u0928 \u0938\u094D\u0935\u091A\u094D\u091B\u0928\u094D\u0926\u0938\u0926\u0943\u0936\u094B \u092D\u0935\u0947\u0924\u094D\u0964</p></blockquote><p>\u0907\u0924\u093F \u0938\u094D\u0935\u091A\u094D\u091B\u0928\u094D\u0926\u0938\u093E\u0926\u0943\u0936\u094D\u092F\u0947\u0928 \u092D\u0947\u0926\u0924\u093F\u0930\u0938\u094D\u0915\u093E\u0930\u092E\u0938\u094D\u092F\u094B\u0915\u094D\u0924\u094D\u0935\u093E</p><blockquote><p>\u092C\u094D\u0930\u0939\u094D\u092E\u0935\u093F\u0937\u094D\u0923\u094D\u0935\u093F\u0928\u094D\u0926\u094D\u0930\u0926\u0947\u0935\u093E\u0928\u093E\u0902 \u0938\u093F\u0926\u094D\u0927\u0926\u0948\u0924\u094D\u092F\u094B\u0930\u0917\u0947\u0936\u093F\u0928\u093E\u092E\u094D\u0965<br> \u092D\u092F\u0926\u093E\u0924\u093E \u091A \u0939\u0930\u094D\u0924\u093E \u091A \u0936\u093E\u092A\u093E\u0928\u0941\u0917\u094D\u0930\u0939\u0915\u0943\u0926\u094D\u092D\u0935\u0947\u0924\u094D\u0964<br> \u0926\u0930\u094D\u092A\u0902 \u0939\u0930\u0924\u093F \u0915\u093E\u0932\u0938\u094D\u092F \u092A\u093E\u0924\u092F\u0947\u0926\u094D\u092D\u0942\u0927\u0930\u093E\u0928\u092A\u093F\u0965</p></blockquote><p>\u0907\u0924\u094D\u092F\u0941\u0915\u094D\u0924\u092E\u094D\u0965\u0969\u096C\u0965</p></div><hr><div class="trans"><p>Evam\u012Bd\u1E5B\u015Basy\u0101pi karm\u0101tmano yad\u0101nargalam\u0101he\u015Ba\u015Baktip\u0101tava\u015Bonmi\u1E63itasahajasv\u0101tantryayogo bhavati tad\u0101sya\u2014</p><blockquote><p><strong>Bhedatirask\u0101re sarg\u0101ntarakarmatvam||36||</strong></p></blockquote><p>\u015Aar\u012Brapr\u0101\u1E47\u0101dyahant\u0101bhim\u0101n\u0101tmana\u1E25 sakalapralay\u0101kal\u0101dipram\u0101trucitasya bhedasya tirask\u0101re sthitasy\u0101pi cidghanasvabh\u0101vonmajjan\u0101dapahastane sati krame\u1E47a mantramantre\u015Bvaramantramahe\u015Bvar\u0101tmakasvam\u0101h\u0101tmy\u0101v\u0101ptau sarg\u0101ntarakarmatva\u1E41 yath\u0101bhila\u1E63itanirmeyanirm\u0101t\u1E5Btva\u1E41 bhavati| Tath\u0101 ca \u015Br\u012Bsvacchande</p><blockquote><p>Trigu\u1E47ena tu japyena svacchandasad\u1E5B\u015Bo bhavet|</p></blockquote><p>iti svacchandas\u0101d\u1E5B\u015Byena bhedatirask\u0101ramasyoktv\u0101</p><blockquote><p>Brahmavi\u1E63\u1E47vindradev\u0101n\u0101\u1E41 siddhadaityorage\u015Bin\u0101m||<br> Bhayad\u0101t\u0101 ca hart\u0101 ca \u015B\u0101p\u0101nugrahak\u1E5Bdbhavet|<br> Darpa\u1E41 harati k\u0101lasya p\u0101tayedbh\u016Bdhar\u0101napi||</p></blockquote><p>ityuktam||36||</p></div><hr><p>\u0422\u0430\u043A <em>(evam)</em>, \u0434\u0430\u0436\u0435 <em>(api)</em> \u0434\u043B\u044F \u0442\u0430\u043A\u0438\u0445 [\u043D\u0435\u0432\u0435\u0436\u0435\u0441\u0442\u0432\u0435\u043D\u043D\u044B\u0445 \u043B\u044E\u0434\u0435\u0439] <em>(\u012Bd\u1E5B\u015Basya)</em>, \u043A\u0442\u043E \u0432\u043E\u0432\u043B\u0435\u0447\u0435\u043D <em>(\u0101tmana\u1E25)</em> \u0432 \u0434\u0435\u0439\u0441\u0442\u0432\u0438\u044F <em>(karma)</em>, \u043A\u043E\u0433\u0434\u0430 <em>(yad\u0101)</em> \u043F\u0440\u043E\u0438\u0441\u0445\u043E\u0434\u0438\u0442 <em>(bhavati)</em> \u0435\u0434\u0438\u043D\u0435\u043D\u0438\u0435 <em>(yoga\u1E25)</em> \u0441 \u0435\u0441\u0442\u0435\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u0439 <em>(sahaja)</em> \u0410\u0431\u0441\u043E\u043B\u044E\u0442\u043D\u043E\u0439 \u0421\u0432\u043E\u0431\u043E\u0434\u043E\u0439 [\u0412\u044B\u0441\u0448\u0435\u0439 \u0421\u0430\u043C\u043E\u0441\u0442\u0438] <em>(sv\u0101tantrya)</em>, \u043A\u043E\u0442\u043E\u0440\u043E\u0435 \u0432\u043E\u0437\u043D\u0438\u043A\u0430\u0435\u0442 <em>(unmi\u1E63ita)</em> \u0438\u0437-\u0437\u0430 <em>(va\u015Ba)</em> \u0431\u0435\u0441\u043F\u0440\u0435\u043F\u044F\u0442\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u0433\u043E <em>(anargala)</em> \u0434\u0430\u0440\u043E\u0432\u0430\u043D\u0438\u044F \u041C\u0438\u043B\u043E\u0441\u0442\u0438 --\u0442.\u0435. \u043D\u0438\u0441\u0445\u043E\u0436\u0434\u0435\u043D\u0438\u044F \u0421\u0438\u043B\u044B-- <em>(\u015Bakti-p\u0101ta)</em>, \u043F\u0440\u0438\u0445\u043E\u0434\u044F\u0449\u0435\u0439 \u043E\u0442 Mahe\u015Ba --\u0442.\u0435. &quot;\u0412\u0435\u043B\u0438\u043A\u043E\u0433\u043E \u0413\u043E\u0441\u043F\u043E\u0434\u0430&quot;, \u044D\u043F\u0438\u0442\u0435\u0442 \u015Aiva-- <em>(m\u0101he\u015Ba)</em>, \u0442\u043E\u0433\u0434\u0430 <em>(tad\u0101)</em> \u0432 \u0435\u0433\u043E \u0441\u043B\u0443\u0447\u0430\u0435 <em>(asya)</em>\u2014</p><blockquote><p><strong>\u041A\u043E\u0433\u0434\u0430 \u0440\u0430\u0437\u043B\u0438\u0447\u0438\u0435 <em>(bheda)</em> \u0438\u0441\u0447\u0435\u0437\u0430\u0435\u0442 <em>(tirask\u0101re)</em>, [\u0443 \u043F\u0440\u043E\u0441\u0432\u0435\u0442\u043B\u0435\u043D\u043D\u043E\u0433\u043E Yog\u012B \u043F\u043E\u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F] \u0441\u043F\u043E\u0441\u043E\u0431\u043D\u043E\u0441\u0442\u044C \u0441\u043E\u0432\u0435\u0440\u0448\u0438\u0442\u044C <em>(karmatvam)</em> \u0434\u0440\u0443\u0433\u043E\u0435 <em>(antara)</em> \u0422\u0432\u043E\u0440\u0435\u043D\u0438\u0435 <em>(sarga)</em>||36||</strong></p></blockquote><p>[\u0421 \u043E\u0434\u043D\u043E\u0439 \u0441\u0442\u043E\u0440\u043E\u043D\u044B, \u0432 \u0441\u043E\u0441\u0442\u0430\u0432\u043D\u043E\u043C \u0441\u043B\u043E\u0432\u0435 &quot;Bhedatirask\u0101re&quot;, \u0441\u043B\u043E\u0432\u043E &quot;bheda&quot; \u043E\u0437\u043D\u0430\u0447\u0430\u0435\u0442] &quot;\u0440\u0430\u0437\u043B\u0438\u0447\u0438\u0435 \u0438\u043B\u0438 \u0434\u0432\u043E\u0439\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u0441\u0442\u044C&quot; <em>(bhedasya)</em>, [\u0441\u043E\u0441\u0442\u043E\u044F\u0449\u0435\u0435 \u0438\u0437 \u0440\u0430\u0437\u043D\u044B\u0445 \u043E\u0431\u043B\u0430\u0441\u0442\u0435\u0439 \u043E\u043F\u044B\u0442\u0430] \u0441\u043E\u043E\u0442\u0432\u0435\u0442\u0441\u0442\u0432\u0443\u044E\u0449\u0438\u0445 <em>(ucitasya)</em> \u0432\u043E\u0441\u043F\u0440\u0438\u043D\u0438\u043C\u0430\u044E\u0449\u0438\u0445 <em>(pram\u0101t\u1E5B)</em>, [\u0442\u0430\u043A\u0438\u0445 \u043A\u0430\u043A] Sakala <em>(sakala)</em>, Pralay\u0101kala <em>(pralaya-akala)</em>, \u0438 \u0442.\u0434. <em>(\u0101di)</em>, \u0447\u044C\u044F \u043F\u0440\u0438\u0440\u043E\u0434\u0430 <em>(\u0101tmana\u1E25)</em> [\u0438\u043C\u0435\u0435\u0442 \u0434\u0435\u043B\u043E \u0441][\u043E\u0448\u0438\u0431\u043E\u0447\u043D\u043E\u0439] \u043A\u043E\u043D\u0446\u0435\u043F\u0446\u0438\u0435\u0439, \u0438\u043B\u0438 \u0438\u0434\u0435\u0435\u0439 <em>(abhim\u0101na)</em>, \u0447\u0442\u043E [\u0438\u0445] &quot;\u042F&quot; \u0438\u043B\u0438 &quot;\u0440\u0435\u0430\u043B\u044C\u043D\u0430\u044F \u0421\u0430\u043C\u043E\u0441\u0442\u044C&quot; <em>(ahant\u0101)</em> \u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F \u0442\u0435\u043B\u043E\u043C <em>(\u015Bar\u012Bra)</em>, \u0436\u0438\u0437\u043D\u0435\u043D\u043D\u043E\u0439 \u044D\u043D\u0435\u0440\u0433\u0438\u0435\u0439 <em>(pr\u0101\u1E47a)</em>, \u0438 \u0442.\u043F. <em>(\u0101di)</em><sup>1</sup>. [\u0421 \u0434\u0440\u0443\u0433\u043E\u0439 \u0441\u0442\u043E\u0440\u043E\u043D\u044B, \u0432 \u0442\u043E\u043C \u0436\u0435 \u0441\u043B\u043E\u0436\u043D\u043E\u043C \u0441\u043B\u043E\u0432\u0435 &quot;Bhedatirask\u0101re&quot;, \u0442\u0435\u0440\u043C\u0438\u043D &quot;tirask\u0101re&quot; \u043E\u0437\u043D\u0430\u0447\u0430\u0435\u0442] &quot;\u043F\u0440\u0438 \u0438\u0441\u0447\u0435\u0437\u043D\u043E\u0432\u0435\u043D\u0438\u0438&quot; <em>(tirask\u0101re)</em>, \u0442.\u0435. \u043A\u043E\u0433\u0434\u0430 \u0438\u043C\u0435\u0435\u0442 \u043C\u0435\u0441\u0442\u043E \u043E\u0442\u0431\u0440\u0430\u0441\u044B\u0432\u0430\u043D\u0438\u0435, \u0438\u043B\u0438 \u0443\u0441\u0442\u0440\u0430\u043D\u0435\u043D\u0438\u0435 <em>(apahastane sati)</em> \u0438\u043C\u0435\u044E\u0449\u0435\u0433\u043E\u0441\u044F [\u0440\u0430\u0437\u043B\u0438\u0447\u0438\u044F, \u0438\u043B\u0438 \u0434\u0432\u043E\u0439\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u0441\u0442\u0438] <em>(sthitasya api)</em> \u0438\u0437-\u0437\u0430 \u043F\u043E\u044F\u0432\u043B\u0435\u043D\u0438\u044F <em>(unmajjan\u0101t)</em> \u0441\u0432\u043E\u0435\u0439 \u0441\u0443\u0449\u043D\u043E\u0441\u0442\u043D\u043E\u0439 \u043F\u0438\u0440\u043E\u0434\u044B <em>(sva-bh\u0101va)</em>, \u044F\u0432\u043B\u044F\u044E\u0449\u0435\u0439\u0441\u044F \u043F\u043B\u043E\u0442\u043D\u043E\u0439 \u043C\u0430\u0441\u0441\u043E\u0439 <em>(ghana)</em> \u0421\u043E\u0437\u043D\u0430\u043D\u0438\u044F <em>(cit)</em>. [\u0412 \u043E\u0431\u0449\u0435\u043C, \u0432\u0441\u0435 \u0441\u043B\u043E\u0436\u043D\u043E\u0435 \u0441\u043B\u043E\u0432\u043E &quot;Bhedatirask\u0101re&quot;\u043E\u0437\u043D\u0430\u0447\u0430\u0435\u0442 &quot;\u041F\u0440\u0438 \u0438\u0441\u0447\u0435\u0437\u043D\u043E\u0432\u0435\u043D\u0438\u0438 \u0440\u0430\u0437\u043B\u0438\u0447\u0438\u044F, \u0438\u043B\u0438 \u0434\u0432\u043E\u0439\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u0441\u0442\u0438&quot;,] \u0442.\u0435. \u0432 \u043F\u043E\u0441\u0442\u0435\u043F\u0435\u043D\u043D\u043E\u043C \u0434\u043E\u0441\u0442\u0438\u0436\u0435\u043D\u0438\u0438 <em>(krame\u1E47a av\u0101ptau)</em> \u0435\u0433\u043E <em>(sva)</em> \u0432\u043E\u0437\u0432\u044B\u0448\u0435\u043D\u043D\u043E\u0433\u043E \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u044F <em>(m\u0101h\u0101tmya)</em>, \u043F\u0440\u043E\u044F\u0432\u043B\u044F\u044E\u0449\u0435\u0433\u043E\u0441\u044F \u0432 \u0444\u043E\u0440\u043C\u0435 <em>(\u0101tmaka)</em> [\u0432\u044B\u0441\u0448\u0438\u0445 \u0432\u043E\u0441\u043F\u0440\u0438\u043D\u0438\u043C\u0430\u044E\u0449\u0438\u0445, \u043D\u0430\u0437\u044B\u0432\u0430\u0435\u043C\u044B\u0445] Mantra <em>(mantra)</em>, Mantre\u015Bvara <em>(mantra-\u012B\u015Bvara)</em> [\u0438] Mantramahe\u015Bvara <em>(mantra-mah\u0101-\u012B\u015Bvara)</em>. [\u041A\u043E\u0433\u0434\u0430 \u0432\u0441\u0435 \u044D\u0442\u043E \u0441\u043B\u0443\u0447\u0430\u0435\u0442\u0441\u044F,][\u0443 \u043F\u0440\u043E\u0441\u0432\u0435\u0442\u043B\u0435\u043D\u043D\u043E\u0433\u043E yog\u012B] \u043F\u043E\u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F <em>(bhavati)</em> \u0441\u043F\u043E\u0441\u043E\u0431\u043D\u043E\u0441\u0442\u044C \u0441\u043E\u0432\u0435\u0440\u0448\u0438\u0442\u044C <em>(karmatvam)</em> \u0434\u0440\u0443\u0433\u043E\u0435 <em>(antara)</em> \u0422\u0432\u043E\u0440\u0435\u043D\u0438\u0435 <em>(sarga)</em>, [\u0442.\u0435.] \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u0435 \u0442\u0432\u043E\u0440\u0446\u0430 <em>(nirm\u0101t\u1E5Btvam)</em> [\u0434\u043B\u044F \u0441\u043E\u0437\u0438\u0434\u0430\u043D\u0438\u044F] \u0432\u0435\u0449\u0435\u0439 <em>(nirmeya)</em> \u0432 \u0441\u043E\u043E\u0442\u0432\u0435\u0442\u0441\u0442\u0432\u0438\u0438 \u0441\u043E \u0441\u0432\u043E\u0438\u043C\u0438 \u0436\u0435\u043B\u0430\u043D\u0438\u044F\u043C\u0438 <em>(yath\u0101-abhila\u1E63ita)</em>|</p><p>\u0422\u0430\u043A <em>(tath\u0101 ca)</em>, \u0432 \u0434\u043E\u0441\u0442\u043E\u0447\u0442\u0438\u043C\u043E\u043C Svacchandatantra <em>(\u015Br\u012B-svacchande)</em>, \u0438\u0441\u0447\u0435\u0437\u043D\u043E\u0432\u0435\u043D\u0438\u0435 <em>(tirask\u0101ram)</em> \u0440\u0430\u0437\u043B\u0438\u0447\u0438\u044F, \u0438\u043B\u0438 \u0434\u0432\u043E\u0439\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u0441\u0442\u0438 <em>(bheda)</em> \u0432 \u0435\u0433\u043E \u0441\u043B\u0443\u0447\u0430\u0435 <em>(asya)</em> \u0438\u0437-\u0437\u0430 \u043F\u043E\u0434\u043E\u0431\u0438\u044F <em>(s\u0101d\u1E5B\u015Byena)</em> \u0441\u043E Svacchanda --\u041D\u0435\u0437\u0430\u0432\u0438\u0441\u0438\u043C\u043E\u0433\u043E \u0413\u043E\u0441\u043F\u043E\u0434\u0430, \u043A\u0442\u043E \u0430\u0431\u0441\u043E\u043B\u044E\u0442\u043D\u043E \u0421\u0432\u043E\u0431\u043E\u0434\u0435\u043D-- <em>(svacchanda)</em> (\u0438\u043C\u0435\u0435\u043C) \u0447\u0435\u0440\u0435\u0437 [\u043C\u043E\u043B\u0447\u0430\u043B\u0438\u0432\u043E\u0435] \u0443\u043F\u043E\u043C\u0438\u043D\u0430\u043D\u0438\u0435 <em>(uktv\u0101)</em> [\u0432 \u0441\u043B\u0435\u0434\u0443\u044E\u0449\u0435\u0439 \u0441\u0442\u0440\u043E\u043A\u0435]:</p><blockquote><p>&quot;\u041F\u043E\u0441\u0440\u0435\u0434\u0441\u0442\u0432\u043E\u043C \u0442\u0440\u043E\u0439\u043D\u043E\u0439 <em>(trigu\u1E47ena tu)</em> \u0434\u0436\u0430\u043F\u044B <em>(japyena)</em><sup>2</sup> \u043E\u043D \u0441\u0442\u0430\u043D\u043E\u0432\u0438\u0442\u0441\u044F <em>(bhavet)</em> \u043F\u043E\u0434\u043E\u0431\u043D\u044B\u043C <em>(sad\u1E5B\u015Ba\u1E25)</em> Svacchanda --\u0421\u0432\u043E\u0431\u043E\u0434\u043D\u043E\u043C\u0443 \u0413\u043E\u0441\u043F\u043E\u0434\u0443-- <em>(svacchanda... iti)</em>&quot;||<br> [\u0421\u043C. \u043F\u0435\u0440\u0432\u0443\u044E \u0441\u0442\u0440\u043E\u043A\u0443 \u0432 VI, 54 \u0432 Svacchandatantra]</p></blockquote><p>[\u0441\u0440\u0430\u0437\u0443 \u043F\u043E\u0441\u043B\u0435 \u044D\u0442\u043E\u0433\u043E,] \u0431\u044B\u043B\u043E \u0441\u043A\u0430\u0437\u0430\u043D\u043E <em>(uktam)</em>:</p><blockquote><p>&quot;\u0421\u0440\u0435\u0434\u0438 \u0431\u043E\u0433\u043E\u0432 --\u0431\u043E\u0436\u0435\u0441\u0442\u0432\u0435\u043D\u043D\u044B\u0445 \u0441\u0443\u0449\u0435\u0441\u0442\u0432-- <em>(dev\u0101n\u0101m)</em> Brahm\u0101 <em>(brahma)</em>, Vi\u1E63\u1E47u <em>(vi\u1E63\u1E47u)</em> [\u0438] Indra <em>(indra)</em>, [\u0438 \u0442\u0430\u043A\u0436\u0435] \u0441\u0440\u0435\u0434\u0438 [\u043F\u043E\u043B\u0443\u0431\u043E\u0433\u043E\u0432, \u0438\u0437\u0432\u0435\u0441\u0442\u043D\u044B\u0445 \u043A\u0430\u043A] siddha-s --\u043D\u0435 \u0441\u043E\u0432\u0435\u0440\u0448\u0435\u043D\u043D\u044B\u0435 \u0441\u0443\u0449\u0435\u0441\u0442\u0432\u0430, \u0430 \u0432\u0438\u0434 \u0441\u0443\u0449\u043D\u043E\u0441\u0442\u0435\u0439, \u043F\u0440\u0435\u0432\u043E\u0441\u0445\u043E\u0434\u044F\u0449\u0438\u0445 \u043F\u0440\u043E\u0441\u0442\u044B\u0445 \u043F\u0440\u0438\u0437\u0440\u0430\u043A\u043E\u0432-- <em>(siddha)</em>, daitya-s --\u0434\u0435\u043C\u043E\u043D\u043E\u0432-- <em>(daitya)</em> [\u0438] urage\u015B\u012B-s --\u0437\u043C\u0435\u0438\u043D\u044B\u0445 \u043A\u043E\u0440\u043E\u043B\u0435\u0439-- <em>(uraga-\u012B\u015Bin\u0101m)</em>, \u043E\u043D \u0441\u0442\u0430\u043D\u043E\u0432\u0438\u0442\u0441\u044F <em>(bhavet)</em> \u0434\u0430\u044E\u0449\u0438\u043C <em>(d\u0101t\u0101)</em> \u0438 <em>(ca... ca)</em> \u0440\u0430\u0441\u0441\u0435\u0438\u0432\u0430\u044E\u0449\u0438\u043C <em>(hart\u0101)</em> \u0441\u0442\u0440\u0430\u0445 <em>(bhaya)</em> \u043F\u043E\u0441\u0440\u0435\u0434\u0441\u0442\u0432\u043E\u043C \u043F\u0440\u043E\u043A\u043B\u044F\u0442\u0438\u044F <em>(\u015B\u0101pa...k\u1E5Bt)</em> [\u0438] \u0434\u0430\u0440\u043E\u0432\u0430\u043D\u0438\u044F \u041C\u0438\u043B\u043E\u0441\u0442\u0438 <em>(anugraha-k\u1E5Bt)</em>, [\u0441\u043E\u043E\u0442\u0432\u0435\u0442\u0441\u0442\u0432\u0435\u043D\u043D\u043E]. \u041E\u043D \u0440\u0430\u0437\u0440\u0443\u0448\u0430\u0435\u0442 <em>(harati)</em> \u0433\u043E\u0440\u0434\u044B\u043D\u044E <em>(darpam)</em> K\u0101la --\u043A\u0430\u043A \u0441\u043C\u0435\u0440\u0442\u0438, \u0442\u0430\u043A \u0438 \u042F\u043C\u044B, \u043F\u043E\u0432\u0435\u043B\u0438\u0442\u0435\u043B\u044F \u0441\u043C\u0435\u0440\u0442\u0438-- <em>(k\u0101lasya)</em> [\u0438] \u0432\u044B\u0437\u044B\u0432\u0430\u0435\u0442 \u043F\u0430\u0434\u0435\u043D\u0438\u0435 <em>(p\u0101tayet)</em> \u0434\u0430\u0436\u0435 <em>(api)</em> \u0433\u043E\u0440 <em>(bh\u016Bdhar\u0101n... iti)</em>&quot;||<br> [\u0421\u043C. \u0437\u0430\u043A\u043B\u044E\u0447\u0438\u0442\u0435\u043B\u044C\u043D\u0443\u044E \u0447\u0430\u0441\u0442\u044C \u0432 VI, 54 \u0432\u043C\u0435\u0441\u0442\u0435 \u0441\u043E \u0432\u0441\u0435\u043C VI, 55 in Svacchandatantra]</p></blockquote><p>||36||</p><hr><ol><li><p>\u042D\u0442\u0430 \u0442\u0435\u043C\u0430 \u0443\u0436\u0435 \u043A\u0440\u0430\u0442\u043A\u043E \u043E\u0431\u044A\u044F\u0441\u043D\u044F\u043B\u0430\u0441\u044C \u043C\u043D\u043E\u0439 \u0432 \u043F\u043E\u044F\u0441\u043D\u0435\u043D\u0438\u0438 4 \u0432 III, 19. \u041D\u043E \u044F \u0434\u043E\u043B\u0436\u0435\u043D \u043F\u043E\u0432\u0442\u043E\u0440\u0438\u0442\u044C \u0441\u0432\u043E\u0435 \u043E\u0431\u044A\u044F\u0441\u043D\u0435\u043D\u0438\u0435 \u0437\u0434\u0435\u0441\u044C, \u043F\u043E\u0442\u043E\u043C\u0443 \u0447\u0442\u043E \u044F \u0441\u043A\u0430\u0436\u0443 \u043A\u043E\u0435-\u0447\u0442\u043E \u0435\u0449\u0435 \u043F\u043E \u044D\u0442\u043E\u043C\u0443 \u043F\u043E\u0432\u043E\u0434\u0443. \u0418\u043C\u0435\u0435\u0442\u0441\u044F \u0441\u0435\u043C\u044C \u0442\u0438\u043F\u043E\u0432 \u0432\u043E\u0441\u043F\u0440\u0438\u043D\u0438\u043C\u0430\u044E\u0449\u0438\u0445, \u0438\u043B\u0438 \u0441\u043A\u043E\u0440\u0435\u0435 \u0441\u0435\u043C\u044C \u044D\u0442\u0430\u043F\u043E\u0432 \u0434\u043B\u044F \u043E\u0434\u043D\u043E\u0433\u043E \u0432\u043E\u0441\u043F\u0440\u0438\u043D\u0438\u043C\u0430\u044E\u0449\u0435\u0433\u043E:</p><ol><li><p>\u015Aiva (\u0435\u0433\u043E \u0441\u0444\u0435\u0440\u0430 \u2014 \u044D\u0442\u043E \u015Aiva \u0438 \u015Aakti \u0442\u0430\u0442\u0442\u0432\u044B, \u043F\u0435\u0440\u0432\u044B\u0435 \u0434\u0432\u0435 \u043A\u0430\u0442\u0435\u0433\u043E\u0440\u0438\u0438) - \u041E\u043D \u2014 \u0412\u044B\u0441\u0448\u0438\u0439 \u0412\u043E\u0441\u043F\u0440\u0438\u043D\u0438\u043C\u0430\u044E\u0449\u0438\u0439, \u0432 \u0441\u0432\u043E\u0435\u0439 \u0441\u043E\u0431\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u0439 \u0441\u0443\u0449\u043D\u043E\u0441\u0442\u043D\u043E\u0439 \u043F\u0440\u0438\u0440\u043E\u0434\u0435. \u0412\u0441\u0435\u043B\u0435\u043D\u043D\u0430\u044F \u0437\u0434\u0435\u0441\u044C \u043E\u0442\u0441\u0443\u0442\u0441\u0442\u0432\u0443\u0435\u0442.</p></li><li><p>Mantramahe\u015Bvara (\u0435\u0433\u043E \u0441\u0444\u0435\u0440\u0430 \u2014 \u044D\u0442\u043E Sad\u0101\u015Biva-\u0442\u0430\u0442\u0442\u0432\u0430, \u0442\u0440\u0435\u0442\u044C\u044F \u043A\u0430\u0442\u0435\u0433\u043E\u0440\u0438\u044F) - \u0425\u043E\u0442\u044F \u0432\u0441\u0435\u043B\u0435\u043D\u043D\u0430\u044F \u0432\u043E\u0437\u043D\u0438\u043A\u043B\u0430, \u043E\u043D\u0430 \u0432\u0441\u0435 \u0435\u0449\u0435 \u043D\u0435 \u0447\u0435\u0442\u043A\u0430\u044F. \u0418\u0442\u0430\u043A, \u044D\u0442\u043E\u0442 \u0432\u043E\u0441\u043F\u0440\u0438\u043D\u0438\u043C\u0430\u044E\u0449\u0438\u0439 \u0435\u0449\u0435 \u043F\u043E\u043B\u043D\u043E\u0441\u0442\u044C\u044E \u043F\u043E\u0433\u043B\u043E\u0449\u0435\u043D \u0441\u0432\u043E\u0435\u0439 \u0441\u043E\u0431\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u0439 \u0421\u0430\u043C\u043E\u0441\u0442\u044C\u044E, \u0438\u043B\u0438 Aham (&quot;\u042F&quot;).</p></li><li><p>Mantre\u015Bvara (\u0435\u0433\u043E \u0441\u0444\u0435\u0440\u0430 \u2014 \u044D\u0442\u043E \u012A\u015Bvara-\u0442\u0430\u0442\u0442\u0432\u0430, \u0447\u0435\u0442\u0432\u0435\u0440\u0442\u0430\u044F \u043A\u0430\u0442\u0435\u0433\u043E\u0440\u0438\u044F) - \u0412\u0441\u0435\u043B\u0435\u043D\u043D\u0430\u044F \u0432\u043E\u0437\u043D\u0438\u043A\u0430\u0435\u0442 \u043A\u0430\u043A \u043E\u0442\u0447\u0435\u0442\u043B\u0438\u0432\u0430\u044F \u0440\u0435\u0430\u043B\u044C\u043D\u043E\u0441\u0442\u044C, \u0438 \u0432 \u0440\u0435\u0437\u0443\u043B\u044C\u0442\u0430\u0442\u0435 \u044D\u0442\u043E\u0442 \u0432\u043E\u0441\u043F\u0440\u0438\u043D\u0438\u043C\u0430\u044E\u0449\u0438\u0439 \u0441\u043E\u0432\u0435\u0440\u0448\u0435\u043D\u043D\u043E \u043F\u043E\u0433\u043B\u043E\u0449\u0430\u0435\u0442\u0441\u044F \u044D\u0442\u0438\u043C \u0434\u0438\u0432\u043E\u043C, \u043D\u043E \u043E\u043D \u0432\u0441\u0435 \u0435\u0449\u0435 \u0441\u043E\u0445\u0440\u0430\u043D\u044F\u0435\u0442 \u0441\u0432\u043E\u044E \u041E\u0441\u043E\u0437\u043D\u0430\u043D\u043D\u043E\u0441\u0442\u044C \u043D\u0435\u0437\u0430\u0442\u0440\u043E\u043D\u0443\u0442\u043E\u0439.</p></li><li><p>Mantra (\u0435\u0433\u043E \u0441\u0444\u0435\u0440\u0430 \u2014 \u044D\u0442\u043E Sadvidy\u0101, \u0438\u043B\u0438 \u015Auddhavidy\u0101 \u0442\u0430\u0442\u0442\u0432\u0430, \u043F\u044F\u0442\u0430\u044F \u043A\u0430\u0442\u0435\u0433\u043E\u0440\u0438\u044F) - \u0417\u0434\u0435\u0441\u044C \u0438\u043C\u0435\u0435\u0442 \u043C\u0435\u0441\u0442\u043E \u0431\u0430\u043B\u0430\u043D\u0441 \u043C\u0435\u0436\u0434\u0443 Aham (&quot;\u042F&quot;) \u0438 Idam (&quot;\u042D\u0442\u043E&quot;, \u0442.\u0435. \u0432\u0441\u0435\u043B\u0435\u043D\u043D\u0430\u044F). \u042D\u0442\u043E\u0442 \u0432\u043E\u0441\u043F\u0440\u0438\u043D\u0438\u043C\u0430\u044E\u0449\u0438\u0439 \u0432 \u0440\u0430\u0432\u043D\u043E\u0439 \u0441\u0442\u0435\u043F\u0435\u043D\u0438 \u043E\u0441\u043E\u0437\u043D\u0430\u0435\u0442 \u043E\u0431\u0430 \u0430\u0441\u043F\u0435\u043A\u0442\u0430 \u043E\u0434\u043D\u043E\u0432\u0440\u0435\u043C\u0435\u043D\u043D\u043E.</p><p>\u041F\u0440\u0435\u0434\u044B\u0434\u0443\u0449\u0438\u0435 \u0447\u0435\u0442\u044B\u0440\u0435 \u0432\u043E\u0441\u043F\u0440\u0438\u043D\u0438\u043C\u0430\u044E\u0449\u0438\u0435 \u044F\u0432\u043B\u044F\u044E\u0442\u0441\u044F \u0431\u043E\u0436\u0435\u0441\u0442\u0432\u0435\u043D\u043D\u044B\u043C\u0438, \u0438\u043B\u0438 \u0432\u044B\u0441\u0448\u0438\u043C\u0438. \u041E\u043D\u0438 \u043F\u043E\u043B\u043D\u043E\u0441\u0442\u044C\u044E \u043B\u0438\u0448\u0435\u043D\u044B mala, \u0438\u043B\u0438 \u0437\u0430\u0433\u0440\u044F\u0437\u043D\u0435\u043D\u0438\u044F. \u041D\u0430 \u0441\u0430\u043C\u043E\u043C \u0434\u0435\u043B\u0435, \u043F\u0435\u0440\u0432\u044B\u0439 \u0432\u043E\u0441\u043F\u0440\u0438\u043D\u0438\u043C\u0430\u044E\u0449\u0438\u0439 \u2014 \u044D\u0442\u043E \u0434\u0430\u0436\u0435 \u043D\u0435 \u0442\u0438\u043F \u0432\u043E\u0441\u043F\u0440\u0438\u043D\u0438\u043C\u0430\u044E\u0449\u0435\u0433\u043E, \u043D\u043E \u0421\u0430\u043C \u0413\u043E\u0441\u043F\u043E\u0434\u044C! \u0423 \u041D\u0435\u0433\u043E \u043E\u0442\u0441\u0443\u0442\u0441\u0442\u0432\u0443\u0435\u0442 \u0432\u0441\u0435\u043B\u0435\u043D\u043D\u0430\u044F \u0434\u043B\u044F \u0432\u043E\u0441\u043F\u0440\u0438\u044F\u0442\u0438\u044F, \u043F\u043E\u0442\u043E\u043C\u0443 \u0447\u0442\u043E \u041E\u043D \u0443\u043A\u043E\u0440\u0435\u043D\u0435\u043D \u0432 \u0421\u0435\u0431\u0435 \u0421\u0430\u043C\u043E\u043C, \u043A\u0430\u043A Aham, \u0438\u043B\u0438 &quot;\u042F&quot;, \u0430 \u0438\u043C\u0435\u043D\u043D\u043E \u0443 \u041D\u0435\u0433\u043E \u043D\u0435\u0442 &quot;Idam&quot; (&quot;\u042D\u0442\u043E&quot;), \u0438\u043B\u0438 \u0432\u0441\u0435\u043B\u0435\u043D\u043D\u043E\u0439 \u043A\u0430\u043A \u0415\u0433\u043E \u0441\u0444\u0435\u0440\u044B \u0432\u043E\u0441\u043F\u0440\u0438\u044F\u0442\u0438\u044F.</p><p>\u0422\u0435\u043F\u0435\u0440\u044C, \u0441\u043B\u0435\u0434\u0443\u044E\u0449\u0438\u0435 \u043E\u0441\u0442\u0430\u0432\u0448\u0438\u0435\u0441\u044F \u0432\u043E\u0441\u043F\u0440\u0438\u043D\u0438\u043C\u0430\u044E\u0449\u0438\u0435, \u043F\u043E\u0433\u0440\u0443\u0436\u0435\u043D\u043D\u044B\u0435 \u0432 \u0441\u0442\u0440\u0430\u0434\u0430\u043D\u0438\u044F, \u0442.\u0435. \u0432 bheda, \u0438\u043B\u0438 \u0434\u0432\u043E\u0439\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u0441\u0442\u044C:</p></li><li><p>Vij\xF1\u0101n\u0101kala (\u0435\u0433\u043E \u0441\u0444\u0435\u0440\u0430 \u043D\u0430\u0445\u043E\u0434\u0438\u0442\u0441\u044F \u043C\u0435\u0436\u0434\u0443 Sadvidy\u0101 \u0438 M\u0101y\u0101 \u0442\u0430\u0442\u0442\u0432\u0430\u043C\u0438, \u0442.\u0435. \u043C\u0435\u0436\u0434\u0443 \u043F\u044F\u0442\u043E\u0439 \u0438 \u0448\u0435\u0441\u0442\u043E\u0439 \u043A\u0430\u0442\u0435\u0433\u043E\u0440\u0438\u044F\u043C\u0438). \u041E\u043D \u043E\u0441\u043E\u0437\u043D\u0430\u0435\u0442, \u0447\u0442\u043E \u015Aiva \u2014 \u0435\u0433\u043E \u043D\u0430\u0441\u0442\u043E\u044F\u0449\u0435\u0435 &quot;\u042F&quot;, \u043D\u043E \u0438\u0441\u043F\u044B\u0442\u044B\u0432\u0430\u0435\u0442 \u043D\u0435\u0434\u043E\u0441\u0442\u0430\u0442\u043E\u043A \u0441\u0438\u043B\u044B (\u043E\u0442\u0441\u044E\u0434\u0430, \u043E\u043D \u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F &quot;akala&quot;) \u0438\u0437-\u0437\u0430 \u0100\u1E47avamala.</p></li><li><p>Pralay\u0101kala (\u0435\u0433\u043E \u0441\u0444\u0435\u0440\u0430 \u2014 \u044D\u0442\u043E M\u0101y\u0101 \u0438 \u0435\u0435 \u043F\u044F\u0442\u044C Ka\xF1cuka-s, \u0441 \u0448\u0435\u0441\u0442\u043E\u0439 \u043F\u043E \u043E\u0434\u0438\u043D\u043D\u0430\u0434\u0446\u0430\u0442\u0443\u044E \u043A\u0430\u0442\u0435\u0433\u043E\u0440\u0438\u0438). \u042D\u0442\u043E\u0442 \u0432\u043E\u0441\u043F\u0440\u0438\u043D\u0438\u043C\u0430\u044E\u0449\u0438\u0439 \u0442\u0430\u043A\u0436\u0435 \u043B\u0438\u0448\u0435\u043D \u0441\u0438\u043B\u044B (akala) \u0438 \u043F\u043E\u043B\u043D\u043E\u0441\u0442\u044C\u044E \u043E\u0442\u043E\u0436\u0434\u0435\u0441\u0442\u0432\u043B\u0435\u043D \u0441\u043E \u0441\u0432\u043E\u0435\u0439 \u0436\u0438\u0437\u043D\u0435\u043D\u043D\u043E\u0439 \u044D\u043D\u0435\u0440\u0433\u0438\u0435\u0439. \u0421\u043B\u0435\u0434\u043E\u0432\u0430\u0442\u0435\u043B\u044C\u043D\u043E, \u0432\u0441\u0435\u043B\u0435\u043D\u043D\u0430\u044F \u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F \u0435\u043C\u0443 \u0432 \u0440\u0430\u0441\u0442\u0432\u043E\u0440\u0435\u043D\u043D\u043E\u043C \u0432\u0438\u0434\u0435. \u0414\u0440\u0443\u0433\u0438\u043C\u0438 \u0441\u043B\u043E\u0432\u0430\u043C\u0438, \u043E\u043D \u0432\u043E\u0441\u043F\u0440\u0438\u043D\u0438\u043C\u0430\u0435\u0442 \u0435\u0435 \u043A\u0430\u043A \u043F\u0443\u0441\u0442\u043E\u0442\u0443. \u041E\u043D \u0441\u043E\u0445\u0440\u0430\u043D\u044F\u0435\u0442 \u0442\u0440\u0438 \u0437\u0430\u0433\u0440\u044F\u0437\u043D\u0435\u043D\u0438\u044F, \u0430 \u0438\u043C\u0435\u043D\u043D\u043E, \u0100\u1E47avamala, M\u0101y\u012Byamala \u0438 K\u0101rmamala, \u043D\u043E \u043F\u043E\u0441\u043B\u0435\u0434\u043D\u0438\u0435 \u0434\u0432\u0435 \u043D\u0435 \u0434\u0435\u0439\u0441\u0442\u0432\u0443\u044E\u0442, \u043F\u043E\u0441\u043A\u043E\u043B\u044C\u043A\u0443 \u0432\u0441\u0435\u043B\u0435\u043D\u043D\u0430\u044F \u043F\u0440\u0435\u0442\u0435\u0440\u043F\u0435\u043B\u0430 &quot;pralaya&quot;, \u0438\u043B\u0438 &quot;\u0440\u0430\u0441\u0442\u0432\u043E\u0440\u0435\u043D\u0438\u0435&quot;.</p></li><li><p>Sakala (\u0435\u0433\u043E \u0441\u0444\u0435\u0440\u0430 \u2014 \u043D\u0430\u0447\u0438\u043D\u0430\u044F \u0441 Puru\u1E63a --\u0434\u0432\u0435\u043D\u0430\u0434\u0446\u0430\u0442\u043E\u0439 \u043A\u0430\u0442\u0435\u0433\u043E\u0440\u0438\u0438-- \u0438 \u0437\u0430\u043A\u0430\u043D\u0447\u0438\u0432\u0430\u044F \u043F\u043E\u0441\u043B\u0435\u0434\u043D\u0435\u0439). \u0421 \u043E\u0434\u043D\u043E\u0439 \u0441\u0442\u043E\u0440\u043E\u043D\u044B, \u044D\u0442\u043E\u0442 \u0432\u043E\u0441\u043F\u0440\u0438\u043D\u0438\u043C\u0430\u044E\u0449\u0438\u0439 \u043D\u0435 \u043B\u0438\u0448\u0435\u043D \u0441\u0438\u043B\u044B (\u0432\u043E\u0442 \u043F\u043E\u0447\u0435\u043C\u0443 \u043E\u043D \u2014 &quot;sakala&quot;, \u0438\u043B\u0438 &quot;\u0441 \u0441\u0438\u043B\u043E\u0439&quot;), \u043D\u043E \u043E\u043D\u0430 \u043E\u0433\u0440\u0430\u043D\u0438\u0447\u0435\u043D\u0430 \u0432\u043E \u0432\u0441\u0435\u0445 \u043E\u0442\u043D\u043E\u0448\u0435\u043D\u0438\u044F\u0445, \u043E\u0441\u043E\u0431\u0435\u043D\u043D\u043E \u0432 \u043E\u0442\u043D\u043E\u0448\u0435\u043D\u0438\u0438 \u0435\u0433\u043E \u043A\u043E\u043D\u0446\u0435\u043F\u0446\u0438\u0438 &quot;\u042F&quot;. \u041E\u043D \u0443\u0431\u0435\u0436\u0434\u0435\u043D, \u0447\u0442\u043E \u0444\u0438\u0437\u0438\u0447\u0435\u0441\u043A\u043E\u0435 \u0442\u0435\u043B\u043E (\u0441\u043E\u0434\u0435\u0440\u0436\u0430\u0449\u0435\u0435 \u043F\u044F\u0442\u044C \u0433\u0440\u0443\u0431\u044B\u0445 \u044D\u043B\u0435\u043C\u0435\u043D\u0442\u043E\u0432) \u0438 \u0442\u043E\u043D\u043A\u043E\u0435 \u0442\u0435\u043B\u043E (\u0441\u043E\u0441\u0442\u043E\u044F\u0449\u0435\u0435 \u0438\u0437 \u0438\u043D\u0442\u0435\u043B\u043B\u0435\u043A\u0442\u0430, \u044D\u0433\u043E, \u0443\u043C\u0430 \u0438 \u0442\u043E\u043D\u043A\u0438\u0445 \u044D\u043B\u0435\u043C\u0435\u043D\u0442\u043E\u0432) \u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F \u0435\u0433\u043E \u043D\u0430\u0441\u0442\u043E\u044F\u0449\u0438\u043C &quot;\u042F&quot;. \u042D\u0442\u043E \u043E\u0448\u0438\u0431\u043E\u0447\u043D\u043E\u0435 \u043F\u043E\u043D\u044F\u0442\u0438\u0435 \u0437\u0430\u0441\u0442\u0430\u0432\u043B\u044F\u0435\u0442 \u0435\u0433\u043E \u0438\u0441\u043F\u043E\u043B\u044C\u0437\u043E\u0432\u0430\u0442\u044C \u0438 \u0431\u0435\u0437 \u0442\u043E\u0433\u043E \u0443\u0436\u0435 \u043E\u0433\u0440\u0430\u043D\u0438\u0447\u0435\u043D\u043D\u044B\u0435 \u0441\u0438\u043B\u044B \u0432\u043E\u043B\u0438, \u0437\u043D\u0430\u043D\u0438\u044F \u0438 \u0434\u0435\u0439\u0441\u0442\u0432\u0438\u044F \u043C\u043D\u043E\u0433\u0438\u043C\u0438 \u0431\u0435\u0441\u043F\u043E\u043B\u0435\u0437\u043D\u044B\u043C\u0438 \u0441\u043F\u043E\u0441\u043E\u0431\u0430\u043C\u0438. \u0412\u043C\u0435\u0441\u0442\u043E \u0442\u043E\u0433\u043E, \u0447\u0442\u043E\u0431\u044B \u0438\u0441\u043F\u043E\u043B\u044C\u0437\u043E\u0432\u0430\u0442\u044C \u0438\u0445 \u0434\u043B\u044F \u0434\u043E\u0441\u0442\u0438\u0436\u0435\u043D\u0438\u044F \u041E\u0441\u043E\u0437\u043D\u0430\u043D\u0438\u044F \u0441\u0432\u043E\u0435\u0433\u043E \u0418\u0441\u0442\u0438\u043D\u043D\u043E\u0433\u043E \u042F, \u043E\u043D, \u043A\u0430\u043A \u0441\u0443\u043C\u0430\u0441\u0448\u0435\u0434\u0448\u0438\u0439, \u0431\u0435\u0436\u0438\u0442 \u0437\u0430 \u0443\u0434\u043E\u0432\u043E\u043B\u044C\u0441\u0442\u0432\u0438\u044F\u043C\u0438 \u0438 \u043B\u044E\u0431\u043E\u0439 \u0446\u0435\u043D\u043E\u0439 \u0443\u0431\u0435\u0433\u0430\u0435\u0442 \u043E\u0442 \u0431\u043E\u043B\u0438, \u0432\u0441\u0435 \u0432\u0440\u0435\u043C\u044F \u0438\u0449\u0435\u0442 \u0412\u044B\u0441\u0448\u0435\u0435 \u0411\u043B\u0430\u0436\u0435\u043D\u0441\u0442\u0432\u043E, \u043D\u043E \u043F\u0440\u0438 \u044D\u0442\u043E\u043C \u0438\u0433\u043D\u043E\u0440\u0438\u0440\u0443\u044F \u043A\u0430\u043A \u0441\u0432\u043E\u0435 \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u0435 \u0438\u0441\u043A\u0430\u0442\u0435\u043B\u044F \u0412\u044B\u0441\u0448\u0435\u0433\u043E \u0411\u043B\u0430\u0436\u0435\u043D\u0441\u0442\u0432\u0430, \u0442\u0430\u043A \u0438 \u0440\u0435\u0430\u043B\u044C\u043D\u043E\u0435 \u043C\u0435\u0441\u0442\u043E, \u0433\u0434\u0435 \u044D\u0442\u043E \u0411\u043B\u0430\u0436\u0435\u043D\u0441\u0442\u0432\u043E \u043F\u0440\u0435\u0431\u044B\u0432\u0430\u0435\u0442 (\u0442.\u0435. \u0432 \u0435\u0433\u043E \u043D\u0430\u0441\u0442\u043E\u044F\u0449\u0435\u043C \u042F).</p></li></ol><p>OK, &quot;bheda&quot; \u0438\u043B\u0438 &quot;\u0440\u0430\u0437\u043B\u0438\u0447\u0438\u0435/\u0434\u0432\u043E\u0439\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u0441\u0442\u044C&quot; \u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F &quot;\u043F\u043E\u0434\u0445\u043E\u0434\u044F\u0449\u0438\u043C \u0434\u043B\u044F&quot; \u043A\u0430\u0436\u0434\u043E\u0433\u043E \u0432\u043E\u0441\u043F\u0440\u0438\u043D\u0438\u043C\u0430\u044E\u0449\u0435\u0433\u043E \u0432 \u0441\u043B\u0435\u0434\u0443\u044E\u0449\u0435\u043C \u0441\u043C\u044B\u0441\u043B\u0435: &quot;\u092A\u094D\u0930\u092E\u093E\u0924\u0944\u0923\u093E\u0902 \u092F\u0925\u093E\u0938\u094D\u0935\u0938\u094D\u0935\u092D\u093E\u0935\u0902 \u092D\u093F\u0928\u094D\u0928\u092A\u094D\u0930\u092E\u0947\u092F\u093E\u0924\u094D\u092E\u0915\u092D\u0947\u0926\u093E\u092D\u093E\u0938\u0903&quot; - &quot;Pram\u0101t\u1E5D\u1E47\u0101\u1E41 yath\u0101svasvabh\u0101va\u1E41 bhinnapramey\u0101tmakabhed\u0101bh\u0101sa\u1E25&quot; - &quot;\u041F\u0440\u043E\u044F\u0432\u043B\u0435\u043D\u0438\u0435 bheda, \u0438\u043B\u0438 \u0434\u0432\u043E\u0439\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u0441\u0442\u0438, \u0441\u043E\u0441\u0442\u043E\u044F\u0449\u0435\u0439 \u0438\u0437 \u0440\u0430\u0437\u043B\u0438\u0447\u043D\u044B\u0445 prameya-s, [\u043F\u0440\u043E\u0438\u0441\u0445\u043E\u0434\u0438\u0442] \u0432 \u0441\u043E\u043E\u0442\u0432\u0435\u0442\u0441\u0442\u0432\u0438\u0438 \u0441 \u0441\u0443\u0449\u043D\u043E\u0441\u0442\u043D\u043E\u0439 \u043F\u0440\u0438\u0440\u043E\u0434\u043E\u0439 \u0432\u043E\u0441\u043F\u0440\u0438\u043D\u0438\u043C\u0430\u044E\u0449\u0438\u0445&quot;. Prameya \u2014 \u044D\u0442\u043E \u0432\u0441\u0435, \u0447\u0442\u043E \u0432\u043E\u0441\u043F\u0440\u0438\u043D\u0438\u043C\u0430\u044E\u0449\u0438\u0439 \u043E\u0449\u0443\u0449\u0430\u0435\u0442/\u0440\u0430\u0437\u043B\u0438\u0447\u0430\u0435\u0442. \u041A\u0430\u0436\u0434\u044B\u0439 \u0432\u043E\u0441\u043F\u0440\u0438\u043D\u0438\u043C\u0430\u044E\u0449\u0438\u0439 \u0438\u043C\u0435\u0435\u0442 prameya, \u0438\u043B\u0438 \u043E\u0431\u043B\u0430\u0441\u0442\u044C \u0432\u043E\u0441\u043F\u0440\u0438\u044F\u0442\u0438\u044F, \u0441\u043E\u043E\u0442\u0432\u0435\u0442\u0441\u0442\u0432\u0443\u044E\u0449\u0443\u044E, \u0438\u043B\u0438 \u043F\u043E\u0434\u0445\u043E\u0434\u044F\u0449\u0443\u044E \u0435\u0433\u043E \u0441\u043E\u0431\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u0439 \u043F\u0440\u0438\u0440\u043E\u0434\u0435. \u041D\u0430\u043F\u0440\u0438\u043C\u0435\u0440, Sakala \u0438\u043C\u0435\u0435\u0442 \u0432\u0441\u0435\u043B\u0435\u043D\u043D\u0443\u044E, \u043E\u0431\u0440\u0430\u0437\u043E\u0432\u0430\u043D\u043D\u0443\u044E \u0440\u0430\u0437\u043D\u044B\u043C\u0438 \u0440\u0435\u0430\u043B\u0438\u044F\u043C\u0438, \u043E\u0442 \u0441\u0430\u043C\u043E\u0433\u043E \u0431\u043E\u0433\u0430 Brahm\u0101 \u0434\u043E \u043F\u043E\u0441\u043B\u0435\u0434\u043D\u0435\u0433\u043E \u0447\u0435\u0440\u0432\u044F, \u0432 \u0442\u043E \u0432\u0440\u0435\u043C\u044F \u043A\u0430\u043A \u0443 Pralay\u0101kala \u043F\u0440\u043E\u0441\u0442\u043E \u043E\u0442\u0441\u0443\u0442\u0441\u0442\u0432\u0443\u0435\u0442 \u043E\u0431\u043B\u0430\u0441\u0442\u044C \u0432\u043E\u0441\u043F\u0440\u0438\u044F\u0442\u0438\u044F, \u0438\u043B\u0438 prameya. .</p></li><li><p>\u0422\u0435\u0440\u043C\u0438\u043D &quot;japya&quot; \u0431\u0443\u043A\u0432\u0430\u043B\u044C\u043D\u043E \u043E\u0437\u043D\u0430\u0447\u0430\u0435\u0442 &quot;\u043F\u043E\u0432\u0442\u043E\u0440\u0435\u043D\u043D\u0430\u044F \u043C\u0430\u043D\u0442\u0440\u0430, \u0438\u043B\u0438 \u043C\u043E\u043B\u0438\u0442\u0432\u0430&quot;, \u0432 \u0442\u043E \u0432\u0440\u0435\u043C\u044F \u043A\u0430\u043A \u0445\u043E\u0440\u043E\u0448\u043E \u0438\u0437\u0432\u0435\u0441\u0442\u043D\u043E\u0435 \u0441\u043B\u043E\u0432\u043E &quot;japa&quot; \u0431\u0443\u043A\u0432\u0430\u043B\u044C\u043D\u043E \u043E\u0437\u043D\u0430\u0447\u0430\u0435\u0442 &quot;\u043F\u043E\u0432\u0442\u043E\u0440\u0435\u043D\u0438\u0435/\u043D\u0430\u0447\u0438\u0442\u044B\u0432\u0430\u043D\u0438\u0435 \u043C\u0430\u043D\u0442\u0440\u044B, \u0438\u043B\u0438 \u043C\u043E\u043B\u0438\u0442\u0432\u044B&quot;. \u0422\u0430\u043A, \u043F\u0435\u0440\u0432\u043E\u0435 \u0443\u043A\u0430\u0437\u044B\u0432\u0430\u0435\u0442 \u043D\u0430 \u0442\u043E, \u0447\u0442\u043E \u043F\u0440\u043E\u0447\u0438\u0442\u0430\u043D\u043E, \u0430 \u043F\u043E\u0441\u043B\u0435\u0434\u043D\u0435\u0435 \u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F \u0430\u043A\u0442\u043E\u043C \u043D\u0430\u0447\u0438\u0442\u044B\u0432\u0430\u043D\u0438\u044F. \u0412 \u043B\u044E\u0431\u043E\u043C \u0441\u043B\u0443\u0447\u0430\u0435, \u0432 \u044D\u0442\u043E\u043C \u043A\u043E\u043D\u0442\u0435\u043A\u0441\u0442\u0435 \u0432 \u0442\u0440\u0435\u0445\u043A\u0440\u0430\u0442\u043D\u043E\u043C japya \u043D\u0438 \u043E\u0434\u043D\u043E \u0438\u0437 \u044D\u0442\u0438\u0445 \u0431\u0443\u043A\u0432\u0430\u043B\u044C\u043D\u044B\u0445 \u0437\u043D\u0430\u0447\u0435\u043D\u0438\u0439 \u043D\u0435 \u0443\u043A\u0430\u0437\u044B\u0432\u0430\u0435\u0442\u0441\u044F. \u0421\u0443\u0449\u0435\u0441\u0442\u0432\u0443\u0435\u0442 \u0442\u0440\u0438 \u0442\u0438\u043F\u0430 japya: (1) \u015A\u0101mbhava, \u0433\u0434\u0435 \u0432\u044B \u0444\u0438\u043A\u0441\u0438\u0440\u0443\u0435\u0442\u0435 \u0441\u0432\u043E\u0435 \u0432\u043D\u0438\u043C\u0430\u043D\u0438\u0435 \u043D\u0430 \u0442\u043E\u0447\u043A\u0435 \u0441\u043E\u0435\u0434\u0438\u043D\u0435\u043D\u0438\u044F \u015Aiva \u0438 \u015Aakti (\u0413\u043E\u0441\u043F\u043E\u0434\u0430 \u0438 \u0415\u0433\u043E \u0421\u0438\u043B\u044B); (2) \u015A\u0101kta, \u0433\u0434\u0435 \u0432\u044B \u0444\u0438\u043A\u0441\u0438\u0440\u0443\u0435\u0442\u0435 \u0441\u0432\u043E\u0435 \u0432\u043D\u0438\u043C\u0430\u043D\u0438\u0435 \u043D\u0430 \u043F\u0435\u0440\u0435\u0445\u043E\u0434\u043D\u043E\u0439 \u0442\u043E\u0447\u043A\u0435 pram\u0101\u1E47a \u0438 prameya (\u0441\u0440\u0435\u0434\u0441\u0442\u0432\u0430 \u043F\u043E\u0437\u043D\u0430\u043D\u0438\u044F \u043F\u043B\u044E\u0441 \u0441\u0430\u043C\u043E\u0433\u043E \u0437\u043D\u0430\u043D\u0438\u044F, \u0438 \u043F\u043E\u0437\u043D\u0430\u0432\u0430\u0435\u043C\u043E\u0433\u043E --\u0442.\u0435. \u043E\u0431\u044A\u0435\u043A\u0442\u0430--) (3) \u0100\u1E47ava, \u0433\u0434\u0435 \u0432\u044B \u0444\u0438\u043A\u0441\u0438\u0440\u0443\u0435\u0442\u0435 \u0441\u0432\u043E\u0435 \u0432\u043D\u0438\u043C\u0430\u043D\u0438\u0435 \u043D\u0430 \u043F\u0435\u0440\u0435\u0445\u043E\u0434\u043D\u043E\u0439 \u0442\u043E\u0447\u043A\u0435 pr\u0101\u1E47a \u0438 ap\u0101na (\u0436\u0438\u0437\u043D\u0435\u043D\u043D\u044B\u0445 \u044D\u043D\u0435\u0440\u0433\u0438\u0439, \u0432\u044B\u0445\u043E\u0434\u044F\u0449\u0438\u0445 \u0438 \u0432\u0445\u043E\u0434\u044F\u0449\u0438\u0445 \u043D\u0430 \u0432\u044B\u0434\u043E\u0445\u0435 \u0438 \u0432\u0434\u043E\u0445\u0435, \u0441\u043E\u043E\u0442\u0432\u0435\u0442\u0441\u0442\u0432\u0435\u043D\u043D\u043E).</p><p>\u041A\u043E\u043D\u0435\u0447\u043D\u043E, \u0431\u043E\u043B\u044C\u0448\u0438\u043D\u0441\u0442\u0432\u043E \u0441\u0442\u0440\u0435\u043C\u044F\u0449\u0438\u0445\u0441\u044F \u043D\u0430\u0447\u043D\u0443\u0442 \u0441 \u043F\u0440\u043E\u0441\u0442\u0435\u0439\u0448\u0435\u0439 japya, \u0442.\u0435. \u0441 \u0445\u043E\u0440\u043E\u0448\u043E \u0437\u043D\u0430\u043A\u043E\u043C\u043E\u0439 \u043A\u043E\u043D\u0446\u0435\u043D\u0442\u0440\u0430\u0446\u0438\u0438 \u043D\u0430 \u043F\u0440\u043E\u043C\u0435\u0436\u0443\u0442\u043A\u0435 \u043C\u0435\u0436\u0434\u0443 \u0432\u044B\u0434\u043E\u0445\u043E\u043C \u0438 \u0432\u0434\u043E\u0445\u043E\u043C (\u0438\u043B\u0438 \u043D\u0430\u043E\u0431\u043E\u0440\u043E\u0442). \u0417\u0430\u0442\u0435\u043C \u043E\u043D\u0438 \u043F\u0440\u043E\u0434\u0432\u0438\u043D\u0443\u0442\u0441\u044F \u043D\u0430 \u0441\u043B\u0435\u0434\u0443\u044E\u0449\u0438\u0439 \u0443\u0440\u043E\u0432\u0435\u043D\u044C, \u043E\u0441\u043E\u0437\u043D\u0430\u0432\u0430\u044F \u0442\u043E\u0447\u043A\u0443 \u043F\u0435\u0440\u0435\u0445\u043E\u0434\u0430 \u043E\u0442 \u0443\u043C\u0430/\u0447\u0443\u0432\u0441\u0442\u0432/\u043F\u043E\u0437\u043D\u0430\u043D\u0438\u044F \u043A (\u043F\u043E\u0437\u043D\u0430\u0432\u0430\u0435\u043C\u043E\u043C\u0443) \u043E\u0431\u044A\u0435\u043A\u0442\u0443. \u041A\u0430\u0436\u0434\u044B\u0439 \u0440\u0430\u0437, \u043A\u043E\u0433\u0434\u0430 \u0432\u044B \u0447\u0442\u043E-\u0442\u043E \u0432\u043E\u0441\u043F\u0440\u0438\u043D\u0438\u043C\u0430\u0435\u0442\u0435 \u0441\u0432\u043E\u0438\u043C\u0438 \u0443\u043C\u043E\u043C/\u0447\u0443\u0432\u0441\u0442\u0432\u0430\u043C\u0438, \u0438\u043C\u0435\u0435\u0442 \u043C\u0435\u0441\u0442\u043E \u043F\u043E\u0437\u043D\u0430\u043D\u0438\u0435, \u0438\u043B\u0438 \u0437\u043D\u0430\u043D\u0438\u0435 \u043A\u0430\u043A \u0440\u0435\u0437\u0443\u043B\u044C\u0442\u0430\u0442 (\u043D\u0430\u043F\u0440\u0438\u043C\u0435\u0440, \u0432\u044B \u0432\u0438\u0434\u0438\u0442\u0435 \u0434\u0435\u0440\u0435\u0432\u043E \u0438 \u0434\u0443\u043C\u0430\u0435\u0442\u0435, &quot;\u041E, \u044D\u0442\u043E \u0434\u0435\u0440\u0435\u0432\u043E&quot;). \u041E\u0431\u044B\u0447\u043D\u044B\u0435 \u043B\u044E\u0434\u0438 (\u0442.\u0435. \u043F\u0440\u043E\u0441\u0442\u043E Sakala-s) \u043E\u0441\u043E\u0437\u043D\u0430\u044E\u0442 \u043B\u0438\u0431\u043E \u0441\u0430\u043C \u043E\u0431\u044A\u0435\u043A\u0442, \u043B\u0438\u0431\u043E \u0438\u0445 \u0443\u043C/\u0447\u0443\u0432\u0441\u0442\u0432\u0430/\u043F\u043E\u0437\u043D\u0430\u043D\u0438\u044F, \u043D\u043E yog\u012B-s \u043E\u0442\u043B\u0438\u0447\u0430\u044E\u0442\u0441\u044F \u0442\u0435\u043C, \u0447\u0442\u043E \u043E\u0441\u043E\u0437\u043D\u0430\u044E\u0442 \u0442\u043E\u0447\u043A\u0443 \u0441\u043E\u0435\u0434\u0438\u043D\u0435\u043D\u0438\u044F \u044D\u0442\u0438\u0445 \u0434\u0432\u0443\u0445 \u0432\u0435\u0449\u0435\u0439 (pram\u0101\u1E47a and prameya). \u0412 \u0437\u0430\u043A\u043B\u044E\u0447\u0435\u043D\u0438\u0435, \u043E\u0447\u0435\u043D\u044C \u043F\u0440\u043E\u0434\u0432\u0438\u043D\u0443\u0442\u044B\u0435 yog\u012B-s \u0434\u043E\u0441\u0442\u0438\u0433\u0430\u044E\u0442 \u0432\u044B\u0441\u0448\u0435\u0439 \u0444\u043E\u0440\u043C\u044B japya, \u0442.\u0435. \u015A\u0101mbhavajapya, \u0447\u0435\u0440\u0435\u0437 \u043E\u0441\u043E\u0437\u043D\u0430\u043D\u0438\u0435 \u043F\u0435\u0440\u0435\u0445\u043E\u0434\u043D\u043E\u0439 \u0442\u043E\u0447\u043A\u0438 \u043E\u0442 \u0413\u043E\u0441\u043F\u043E\u0434\u0430 \u043A \u0415\u0433\u043E \u0421\u0438\u043B\u0435. \u041A\u043E\u0440\u043E\u0447\u0435 \u0433\u043E\u0432\u043E\u0440\u044F, \u043E\u043D \u0441\u043E\u0441\u0440\u0435\u0434\u043E\u0442\u043E\u0447\u0438\u0432\u0430\u0435\u0442 \u0441\u0432\u043E\u0435 \u0432\u043D\u0438\u043C\u0430\u043D\u0438\u0435 \u043D\u0430 \u0441\u043E\u044E\u0437\u0435 \u043C\u0435\u0436\u0434\u0443 &quot;\u042F&quot;, \u0438\u043B\u0438 &quot;\u0421\u0430\u043C\u043E\u0441\u0442\u044C\u044E&quot; \u0438 \u0415\u0433\u043E &quot;\u042F-\u0441\u043E\u0437\u043D\u0430\u043D\u0438\u0435\u043C&quot;. \u041D\u0443, \u0435\u0441\u043B\u0438 \u0432\u0430\u043C \u0443\u0434\u0430\u0441\u0442\u0441\u044F \u0434\u043E\u0441\u0442\u0438\u0447\u044C \u0442\u0430\u043A\u043E\u0433\u043E \u0443\u0440\u043E\u0432\u043D\u044F \u0434\u0443\u0445\u043E\u0432\u043D\u043E\u0441\u0442\u0438, \u043C\u043E\u0438 \u043F\u043E\u0437\u0434\u0440\u0430\u0432\u043B\u0435\u043D\u0438\u044F, \u0432\u043E\u0437\u0432\u044B\u0448\u0435\u043D\u043D\u044B\u0435 Yog\u012B, \u0438\u043B\u0438 Yogin\u012B, \u043F\u043E\u0442\u043E\u043C\u0443 \u0447\u0442\u043E \u0441\u0434\u0435\u043B\u0430\u0442\u044C \u044D\u0442\u043E \u0442\u0430\u043A \u0441\u043B\u043E\u0436\u043D\u043E, \u0447\u0442\u043E \u044F \u043D\u0435 \u043C\u043E\u0433\u0443 \u043D\u0435 \u0441\u043C\u0435\u044F\u0442\u044C\u0441\u044F \u043A\u0430\u0436\u0434\u044B\u0439 \u0440\u0430\u0437, \u0434\u0443\u043C\u0430\u044F \u043E\u0431 \u044D\u0442\u043E\u043C! \u0422\u043E\u043B\u044C\u043A\u043E \u041C\u0438\u043B\u043E\u0441\u0442\u044C \u0413\u043E\u0441\u043F\u043E\u0434\u0430, \u043E\u0431\u0438\u043B\u044C\u043D\u043E \u0434\u0430\u0440\u043E\u0432\u0430\u043D\u043D\u0430\u044F \u0447\u0435\u043B\u043E\u0432\u0435\u043A\u0443, \u0441\u043F\u043E\u0441\u043E\u0431\u043D\u0430 \u0441\u0434\u0435\u043B\u0430\u0442\u044C \u0435\u0433\u043E \u043F\u0440\u0438\u0433\u043E\u0434\u043D\u044B\u043C \u0434\u043B\u044F \u015A\u0101mbhavajapya.</p></li></ol></div><div class="stanza"><a href="#s3.37" id="s3.37" class="num">3.37</a><div class="sans"><p>\u0928 \u091A\u0948\u0924\u0926\u0938\u094D\u092F\u093E\u0938\u092E\u094D\u092D\u093E\u0935\u094D\u092F\u0902 \u092F\u0924\u0903\u2014</p><blockquote><p><strong>\u0915\u0930\u0923\u0936\u0915\u094D\u0924\u093F\u0903 \u0938\u094D\u0935\u0924\u094B\u093D\u0928\u0941\u092D\u0935\u093E\u0924\u094D\u0965\u0969\u096D\u0965</strong></p></blockquote><p>\u0938\u094D\u0935\u0924\u0903 \u0938\u094D\u0935\u0938\u094D\u092E\u093E\u0926\u0947\u0935\u093E\u0928\u0941\u092D\u0935\u093E\u0924\u094D\u0938\u0919\u094D\u0915\u0932\u094D\u092A\u0938\u094D\u0935\u092A\u094D\u0928\u093E\u0926\u094C \u0915\u0930\u0923\u0936\u0915\u094D\u0924\u093F\u0903 \u0924\u0924\u094D\u0924\u0926\u0938\u093E\u0927\u093E\u0930\u0923\u093E\u0930\u094D\u0925\u0928\u093F\u0930\u094D\u092E\u093E\u0924\u0943\u0924\u094D\u0935\u092E\u093E\u0924\u094D\u092E\u0928\u0903 \u0938\u093F\u0926\u094D\u0927\u092E\u0947\u0935\u0964 \u0905\u0928\u0947\u0928\u0948\u0935\u093E\u0936\u092F\u0947\u0928 \u0936\u094D\u0930\u0940\u092A\u094D\u0930\u0924\u094D\u092F\u092D\u093F\u091C\u094D\u091E\u093E\u092F\u093E\u092E\u094D</p><blockquote><p>\u0905\u0924 \u090F\u0935 \u092F\u0925\u093E\u092D\u0940\u0937\u094D\u091F\u0938\u092E\u0941\u0932\u094D\u0932\u0947\u0916\u093E\u0935\u092D\u093E\u0938\u0928\u093E\u0924\u094D\u0964<br> \u091C\u094D\u091E\u093E\u0928\u0915\u094D\u0930\u093F\u092F\u0947 \u0938\u094D\u092B\u0941\u091F \u090F\u0935 \u0938\u093F\u0926\u094D\u0927\u0947 \u0938\u0930\u094D\u0935\u0938\u094D\u092F \u091C\u0940\u0935\u0924\u0903\u0965</p></blockquote><p>\u0907\u0924\u094D\u092F\u0941\u0915\u094D\u0924\u092E\u094D\u0964 \u0924\u0925\u093E\u0938\u092E\u094D\u092D\u0935\u093E\u0926\u094D\u092F\u0926\u093F \u091A\u0948\u0924\u0926\u094D\u0917\u093E\u0922\u093E\u092D\u093F\u0928\u093F\u0935\u0947\u0936\u0947\u0928 \u0935\u093F\u092E\u0943\u0936\u0924\u093F \u0924\u0926\u093E \u0938\u0930\u094D\u0935\u0938\u093E\u0927\u093E\u0930\u0923\u093E\u092D\u0940\u0937\u094D\u091F\u093E\u0930\u094D\u0925\u0928\u093F\u0930\u094D\u092E\u093E\u0924\u0943\u0924\u093E\u092A\u093F \u092D\u0935\u0924\u093F\u0964 \u0924\u0926\u0941\u0915\u094D\u0924\u0902 \u0924\u0924\u094D\u0924\u094D\u0935\u0917\u0930\u094D\u092D\u0947</p><blockquote><p>\u092F\u0926\u093E \u0924\u0941 \u0924\u0947\u093D\u092A\u093F \u0938\u0941\u0935\u094D\u092F\u0915\u094D\u0924\u0938\u094D\u0935\u0938\u093E\u092E\u0930\u094D\u0925\u094D\u092F\u0917\u0941\u0923\u094B\u091C\u094D\u091C\u094D\u0935\u0932\u093E\u0903\u0964<br> \u092D\u0935\u0947\u0926\u094D\u0926\u0943\u0922\u0924\u0930\u093E\u0926\u0942\u0930\u0926\u093E\u0930\u093F\u0924\u093E \u0926\u093E\u0930\u094D\u0922\u094D\u092F\u0926\u0940\u0928\u0924\u093E\u0964<br> \u0924\u0926\u093E \u091A \u0924\u0947\u0937\u093E\u0902 \u0938\u0919\u094D\u0915\u0932\u094D\u092A\u0903 \u0915\u0932\u094D\u092A\u092A\u093E\u0926\u092A\u0924\u093E\u0902 \u0935\u094D\u0930\u091C\u0947\u0924\u094D\u0965</p></blockquote><p>\u0907\u0924\u093F\u0965\u0969\u096D\u0965</p></div><hr><div class="trans"><p>Na caitadasy\u0101sambh\u0101vya\u1E41 yata\u1E25\u2014</p><blockquote><p><strong>Kara\u1E47a\u015Bakti\u1E25 svato&#39;nubhav\u0101t||37||</strong></p></blockquote><p>Svata\u1E25 svasm\u0101dev\u0101nubhav\u0101tsa\u1E45kalpasvapn\u0101dau kara\u1E47a\u015Bakti\u1E25 tattadas\u0101dh\u0101ra\u1E47\u0101rthanirm\u0101t\u1E5Btvam\u0101tmana\u1E25 siddhameva| Anenaiv\u0101\u015Bayena \u015Br\u012Bpratyabhij\xF1\u0101y\u0101m</p><blockquote><p>Ata eva yath\u0101bh\u012B\u1E63\u1E6Dasamullekh\u0101vabh\u0101san\u0101t|<br> J\xF1\u0101nakriye sphu\u1E6Da eva siddhe sarvasya j\u012Bvata\u1E25||</p></blockquote><p>ityuktam| Tath\u0101sambhav\u0101dyadi caitadg\u0101\u1E0Dh\u0101bhinive\u015Bena vim\u1E5B\u015Bati tad\u0101 sarvas\u0101dh\u0101ra\u1E47\u0101bh\u012B\u1E63\u1E6D\u0101rthanirm\u0101t\u1E5Bt\u0101pi bhavati| Tadukta\u1E41 tattvagarbhe</p><blockquote><p>Yad\u0101 tu te&#39;pi suvyaktasvas\u0101marthyagu\u1E47ojjval\u0101\u1E25|<br> Bhavedd\u1E5B\u1E0Dhatar\u0101d\u016Brad\u0101rit\u0101 d\u0101r\u1E0Dhyad\u012Bnat\u0101|<br> Tad\u0101 ca te\u1E63\u0101\u1E41 sa\u1E45kalpa\u1E25 kalpap\u0101dapat\u0101\u1E41 vrajet||</p></blockquote><p>iti||37||</p></div><hr><p>\u042D\u0442\u0430 [\u0441\u043E\u0437\u0438\u0434\u0430\u0442\u0435\u043B\u044C\u043D\u0430\u044F \u0441\u043F\u043E\u0441\u043E\u0431\u043D\u043E\u0441\u0442\u044C] <em>(etad)</em> \u043D\u0435 \u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F <em>(na ca)</em> \u043D\u0435\u0432\u043E\u0437\u043C\u043E\u0436\u043D\u043E\u0439 <em>(asambh\u0101vyam)</em> \u0434\u043B\u044F \u043D\u0435\u0433\u043E <em>(asya)</em>, \u043F\u043E\u0442\u043E\u043C\u0443 \u0447\u0442\u043E <em>(yatas)</em>\u2014</p><blockquote><p><strong>[\u041B\u044E\u0431\u043E\u0439 \u043C\u043E\u0436\u0435\u0442 \u043E\u0441\u043E\u0437\u043D\u0430\u0442\u044C \u0441\u0432\u043E\u044E] \u0441\u043E\u0437\u0438\u0434\u0430\u0442\u0435\u043B\u044C\u043D\u0443\u044E <em>(kara\u1E47a)</em> \u0441\u0438\u043B\u0443 <em>(\u015Bakti\u1E25)</em> \u043D\u0430 \u0441\u0432\u043E\u0435\u043C \u0441\u043E\u0431\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u043C <em>(svata\u1E25)</em> \u043E\u043F\u044B\u0442\u0435 <em>(anubhav\u0101t)</em>||37||</strong></p></blockquote><p>\u0415\u0433\u043E <em>(\u0101tmana\u1E25)</em> \u0441\u043E\u0437\u0438\u0434\u0430\u0442\u0435\u043B\u044C\u043D\u0430\u044F <em>(kara\u1E47a)</em> \u0441\u0438\u043B\u0430 <em>(\u015Bakti\u1E25)</em>, [\u0438\u043B\u0438] \u0441\u043F\u043E\u0441\u043E\u0431\u043D\u043E\u0441\u0442\u044C \u043A \u0442\u0432\u043E\u0440\u0435\u043D\u0438\u044E <em>(nirm\u0101t\u1E5Btvam)</em> \u0440\u0430\u0437\u043B\u0438\u0447\u043D\u044B\u0445 <em>(tad-tad)</em> \u043D\u0435\u043E\u0431\u044B\u0447\u0430\u0439\u043D\u044B\u0445 <em>(as\u0101dh\u0101ra\u1E47a)</em> \u0432\u0435\u0449\u0435\u0439 <em>(artha)</em> \u0434\u043E\u043A\u0430\u0437\u0430\u043D\u0430, \u0438\u043B\u0438 \u0443\u0441\u0442\u0430\u043D\u043E\u0432\u043B\u0435\u043D\u0430 <em>(siddham)</em> &quot;svato&#39;nubhav\u0101t&quot; <em>(svata\u1E25... anubhav\u0101t)</em>, \u0442.\u0435. \u0438\u0441\u0445\u043E\u0434\u044F \u0438\u0437 \u0435\u0433\u043E \u0441\u043E\u0431\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u0433\u043E <em>(svasm\u0101t eva)</em> \u043E\u043F\u044B\u0442\u0430 --anubhava-- <em>(anubhav\u0101t)</em> \u0432 \u043F\u0440\u043E\u0446\u0435\u0441\u0441\u0435 \u0432\u043E\u043E\u0431\u0440\u0430\u0436\u0435\u043D\u0438\u044F, \u0441\u043D\u0430 \u0438 \u0442.\u043F. <em>(sa\u1E45kalpa-svapna-\u0101dau)</em>|</p><p>\u0422\u0430 \u0436\u0435 \u0438\u0434\u0435\u044F <em>(anena eva \u0101\u015Bayena)</em>, \u0431\u044B\u043B\u0430 \u0432\u044B\u0441\u043A\u0430\u0437\u0430\u043D\u0430 <em>(uktam)</em> \u0432 \u0443\u0432\u0430\u0436\u0430\u0435\u043C\u043E\u0439 \u012A\u015Bvarapratyabhij\xF1\u0101 <em>(\u015Br\u012B-pratyabhij\xF1\u0101y\u0101m)</em>:</p><blockquote><p>&quot;\u041F\u043E \u044D\u0442\u043E\u0439 \u0441\u0430\u043C\u043E\u0439 \u043F\u0440\u0438\u0447\u0438\u043D\u0435 <em>(atas eva)</em>, \u0438\u0441\u0445\u043E\u0434\u044F \u0438\u0437 \u0441\u0438\u043B \u043A\u043E\u043D\u0446\u0435\u043F\u0442\u0443\u0430\u043B\u0438\u0437\u0430\u0446\u0438\u0438 \u0438 \u0432\u043E\u043F\u043B\u043E\u0449\u0435\u043D\u0438\u044F <em>(samullekha-avabh\u0101san\u0101t)</em> \u0432 \u0441\u043E\u043E\u0442\u0432\u0435\u0442\u0441\u0442\u0432\u0438\u0438 \u0441 \u0435\u0433\u043E \u0436\u0435\u043B\u0430\u043D\u0438\u0435\u043C <em>(yath\u0101-abh\u012B\u1E63\u1E6Da)</em>, [\u0441\u0438\u043B\u044B] \u0437\u043D\u0430\u043D\u0438\u044F \u0438 \u0434\u0435\u0439\u0441\u0442\u0432\u0438\u044F <em>(j\xF1\u0101na-kriye)</em> \u0432\u0441\u0435\u0445 \u0436\u0438\u0432\u044B\u0445 \u0441\u0443\u0449\u0435\u0441\u0442\u0432 <em>(sarvasya j\u012Bvata\u1E25)</em> [\u044F\u0432\u043B\u044F\u044E\u0442\u0441\u044F] \u044F\u0441\u043D\u043E <em>(sphu\u1E6De eva)</em> \u0434\u043E\u043A\u0430\u0437\u0430\u043D\u043D\u044B\u043C\u0438, \u0438\u043B\u0438 \u0443\u0441\u0442\u0430\u043D\u043E\u0432\u043B\u0435\u043D\u043D\u044B\u043C\u0438 <em>(siddhe... iti)</em><sup>1</sup>&quot;||<br> [\u0421\u043C. I, VI, 11 \u0432 \u012A\u015Bvarapratyabhij\xF1\u0101]</p></blockquote><p>\u0411\u043B\u0430\u0433\u043E\u0434\u0430\u0440\u044F \u0442\u0430\u043A\u043E\u0439 \u0432\u043E\u0437\u043C\u043E\u0436\u043D\u043E\u0441\u0442\u0438 <em>(tath\u0101-sambhav\u0101t)</em>, \u0435\u0441\u043B\u0438 <em>(yadi ca)</em> \u044D\u0442\u043E\u0442 [Yog\u012B] <em>(etad)</em>, \u0441 \u0442\u0432\u0435\u0440\u0434\u043E\u0439 \u0438 \u0441\u0438\u043B\u044C\u043D\u043E\u0439 \u0440\u0435\u0448\u0438\u043C\u043E\u0441\u0442\u044C\u044E <em>(g\u0101\u1E0Dha-abhinive\u015Bena)</em> \u0436\u0435\u043B\u0430\u0435\u0442 \u043F\u0440\u043E\u044F\u0432\u0438\u0442\u044C \u043F\u043E\u0441\u0440\u0435\u0434\u0441\u0442\u0432\u043E\u043C [\u0441\u0432\u043E\u0435\u0439] Vimar\u015Ba [\u0438\u043B\u0438 \u042F-\u0421\u043E\u0437\u043D\u0430\u043D\u0438\u044F] <em>(vim\u1E5B\u015Bati)</em>, \u0442\u043E\u0433\u0434\u0430 <em>(tad\u0101)</em> \u0442\u0430\u043A\u0436\u0435 <em>(api)</em> \u0432\u043E\u0437\u043D\u0438\u043A\u0430\u0435\u0442 <em>(bhavati)</em> \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u0435 \u0442\u0432\u043E\u0440\u0446\u0430 <em>(nirm\u0101t\u1E5Bt\u0101)</em> \u0432\u0435\u0449\u0435\u0439 <em>(artha)</em> \u0432 \u0441\u043E\u043E\u0442\u0432\u0435\u0442\u0441\u0442\u0432\u0438\u0438 \u0441 \u0435\u0433\u043E \u0436\u0435\u043B\u0430\u043D\u0438\u0435\u043C <em>(abh\u012B\u1E63\u1E6Da)</em>, \u043A\u043E\u0442\u043E\u0440\u043E\u0435 --\u0442.\u0435. \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u0435 \u0442\u0432\u043E\u0440\u0446\u0430-- \u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F \u043E\u0431\u0449\u0438\u043C <em>(s\u0101dh\u0101ra\u1E47\u0101)</em> \u0434\u043B\u044F \u0432\u0441\u0435\u0445 <em>(sarva)</em><sup>2</sup>|</p><p>\u0422\u0430\u043A <em>(tad)</em> \u0431\u044B\u043B\u043E \u043A\u043E\u043D\u0441\u0442\u0430\u0442\u0438\u0440\u043E\u0432\u0430\u043D\u043E <em>(uktam)</em> \u0432 Tattvagarbha <em>(tattvagarbhe)</em>:</p><blockquote><p>&quot;\u041A\u043E\u0433\u0434\u0430 <em>(yad\u0101 tu)</em> \u043E\u043D\u0438 --\u0432\u0435\u043B\u0438\u043A\u0438\u0435 Yog\u012B-s-- <em>(te api)</em> \u0441\u0438\u044F\u044E\u0442 --\u0431\u0443\u043A\u0432. \u0441\u0432\u0435\u0442\u044F\u0449\u0438\u0435\u0441\u044F-- <em>(ujjval\u0101\u1E25)</em> \u0441 \u0438\u0445 <em>(sva)</em> \u0441\u0432\u043E\u0439\u0441\u0442\u0432\u043E\u043C <em>(gu\u1E47a)</em> \u0434\u0435\u0439\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u0441\u0442\u0438 <em>(s\u0101marthya)</em> \u044F\u0441\u043D\u043E\u0433\u043E \u043F\u0440\u043E\u044F\u0432\u043B\u0435\u043D\u0438\u044F <em>(su-vyakta)</em>, [\u0432\u0441\u0435] \u043E\u0442\u0441\u0443\u0442\u0441\u0442\u0432\u0438\u0435 <em>(d\u012Bnat\u0101)</em> \u0441\u0442\u0430\u0431\u0438\u043B\u044C\u043D\u043E\u0441\u0442\u0438 \u0438 \u0441\u0438\u043B\u044B <em>(d\u0101r\u1E0Dhya)</em> \u0431\u044B\u0441\u0442\u0440\u043E <em>(ad\u016Bra)</em> [\u0438] \u043E\u0447\u0435\u043D\u044C \u0440\u0435\u0448\u0438\u0442\u0435\u043B\u044C\u043D\u043E <em>(d\u1E5B\u1E0Dhatara)</em> \u0441\u0442\u0430\u043D\u043E\u0432\u0438\u0442\u0441\u044F <em>(bhavet)</em> \u0440\u0430\u0441\u043A\u043E\u043B\u043E\u0442\u044B\u043C \u043D\u0430 \u043A\u0443\u0441\u043A\u0438 --\u0444\u0438\u0433\u0443\u0440\u0430\u043B\u044C\u043D\u043E \u0432\u044B\u0440\u0430\u0436\u0430\u044F\u0441\u044C-- <em>(d\u0101rit\u0101)</em>, \u0438 <em>(ca)</em> \u0442\u043E\u0433\u0434\u0430 <em>(tad\u0101)</em> \u0438\u0445 <em>(te\u1E63\u0101m)</em> \u0432\u043E\u043B\u044F --\u0441\u0438\u043B\u0430 \u0432\u043E\u043B\u0438-- <em>(sa\u1E45kalpa\u1E25)</em> \u0441\u0442\u0430\u043D\u043E\u0432\u0438\u0442\u0441\u044F <em>(vrajet)</em> Kalpap\u0101dapa, \u0438\u043B\u0438 Kalpataru --\u0434\u0435\u0440\u0435\u0432\u043E\u043C, \u0438\u0441\u043F\u043E\u043B\u043D\u044F\u044E\u0449\u0438\u043C \u0436\u0435\u043B\u0430\u043D\u0438\u044F-- <em>(kalpap\u0101dapat\u0101m... iti)</em><sup>3</sup>&quot;||</p></blockquote><p>||37||</p><hr><ol><li><p>\u0421\u043E\u0433\u043B\u0430\u0441\u043D\u043E Abhinavagupta, \u043A\u0430\u043A \u043E\u043D \u043F\u0438\u0448\u0435\u0442 \u0432 \u0441\u0432\u043E\u0435\u043C \u043A\u043E\u043C\u043C\u0435\u043D\u0442\u0430\u0440\u0438\u0438 \u043D\u0430 \u012A\u015Bvarapratyabhij\xF1\u0101, \u0438\u0437\u0432\u0435\u0441\u0442\u043D\u043E\u043C \u043A\u0430\u043A \u012A\u015Bvarapratyabhij\xF1\u0101vimar\u015Bin\u012B, &quot;Avabh\u0101sana&quot; (\u0441\u0438\u043B\u0430 \u043A\u043E\u043D\u0446\u0435\u043F\u0442\u0443\u0430\u043B\u0438\u0437\u0430\u0446\u0438\u0438) \u043E\u0437\u043D\u0430\u0447\u0430\u0435\u0442 &quot;J\xF1\u0101na\u015Bakti&quot; (\u0421\u0438\u043B\u0443 \u0417\u043D\u0430\u043D\u0438\u044F), \u0438 &quot;Samullekha&quot; (\u0441\u0438\u043B\u0430 \u0432\u043E\u043F\u043B\u043E\u0449\u0435\u043D\u0438\u044F) \u0443\u043A\u0430\u0437\u044B\u0432\u0430\u0435\u0442 \u043D\u0430 &quot;Kriy\u0101\u015Bakti&quot; (\u0421\u0438\u043B\u0443 \u0414\u0435\u0439\u0441\u0442\u0432\u0438\u044F). \u041F\u0435\u0440\u0432\u0430\u044F \u043F\u0440\u0435\u0434\u043F\u043E\u043B\u0430\u0433\u0430\u0435\u0442, \u0432 \u0442\u043E \u0432\u0440\u0435\u043C\u044F \u043A\u0430\u043A \u043F\u043E\u0441\u043B\u0435\u0434\u043D\u044F\u044F \u043E\u0441\u0443\u0449\u0435\u0441\u0442\u0432\u043B\u044F\u0435\u0442/\u0432\u043E\u043F\u043B\u043E\u0449\u0430\u0435\u0442, \u0430 \u0438\u043C\u0435\u043D\u043D\u043E, \u0432\u044B\u043F\u043E\u043B\u043D\u044F\u0435\u0442 \u0442\u043E, \u0447\u0442\u043E \u0431\u044B\u043B\u043E \u0437\u0430\u0434\u0443\u043C\u0430\u043D\u043E \u043F\u0435\u0440\u0432\u044B\u043C. \u0418\u0442\u0430\u043A, \u0421\u0438\u043B\u0430 \u0414\u0435\u0439\u0441\u0442\u0432\u0438\u044F \u0440\u0435\u0430\u043B\u0438\u0437\u0443\u0435\u0442 \u0432\u0441\u0435, \u0447\u0442\u043E \u0431\u044B\u043B\u043E \u0440\u0430\u043D\u0435\u0435 \u0437\u0430\u0434\u0443\u043C\u0430\u043D\u043E \u0421\u0438\u043B\u043E\u0439 \u0417\u043D\u0430\u043D\u0438\u044F. \u041F\u0440\u043E\u0441\u0442\u043E!</p><p>\u042F \u043F\u0435\u0440\u0435\u0432\u0435\u0434\u0443 \u0434\u043B\u044F \u0432\u0430\u0441 \u0432\u0435\u0441\u044C \u043A\u043E\u043C\u043C\u0435\u043D\u0442\u0430\u0440\u0438\u0439 \u043D\u0430 \u044D\u0442\u0443 \u0441\u0442\u0440\u043E\u0444\u0443, \u043D\u0435 \u0442\u043E\u043B\u044C\u043A\u043E \u0434\u043B\u044F \u0442\u043E\u0433\u043E, \u0447\u0442\u043E\u0431\u044B \u0434\u043E\u043A\u0430\u0437\u0430\u0442\u044C \u043C\u043E\u044E \u0442\u043E\u0447\u043A\u0443 \u0437\u0440\u0435\u043D\u0438\u044F, \u043D\u043E \u0442\u0430\u043A\u0436\u0435 \u0438 \u0434\u043B\u044F \u0442\u043E\u0433\u043E, \u0447\u0442\u043E\u0431\u044B \u0432\u044B \u043C\u043E\u0433\u043B\u0438 \u0433\u043B\u0443\u0431\u0436\u0435 \u043F\u043E\u043D\u044F\u0442\u044C \u0435\u0435. \u042F \u0441\u0434\u0435\u043B\u0430\u044E \u0432\u0441\u0435 \u0432\u043E\u0437\u043C\u043E\u0436\u043D\u043E\u0435, \u043F\u043E\u0442\u043E\u043C\u0443 \u0447\u0442\u043E Abhinavagupta \u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F \u0442\u0430\u043A\u0438\u043C \u0443\u0447\u0435\u043D\u044B\u043C \u0438 \u043C\u0430\u0441\u0441\u0438\u0432\u043D\u044B\u043C \u0443\u0447\u0438\u0442\u0435\u043B\u0435\u043C, \u0447\u0442\u043E \u0447\u0430\u0441\u0442\u043E \u043E\u0447\u0435\u043D\u044C \u0441\u043B\u043E\u0436\u043D\u043E \u043F\u043E\u043D\u044F\u0442\u044C \u0435\u0433\u043E \u0441\u043E\u0447\u0438\u043D\u0435\u043D\u0438\u044F \u0434\u043E\u043B\u0436\u043D\u044B\u043C \u043E\u0431\u0440\u0430\u0437\u043E\u043C. \u0418 \u043F\u043E\u0441\u043A\u043E\u043B\u044C\u043A\u0443 \u0441\u043F\u043E\u0441\u043E\u0431 \u043D\u0430\u043F\u0438\u0441\u0430\u043D\u0438\u044F \u044D\u0442\u043E\u0433\u043E \u043C\u0430\u0441\u0442\u0435\u0440\u0430 \u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F \u0438\u0437\u044B\u0441\u043A\u0430\u043D\u043D\u044B\u043C \u0438 \u0441\u043B\u043E\u0436\u043D\u044B\u043C, \u042F \u0431\u0443\u0434\u0443 \u0442\u0430\u043A\u0436\u0435 \u043E\u0431\u044A\u044F\u0441\u043D\u044F\u0442\u044C \u043A\u0430\u0436\u0434\u0443\u044E \u0447\u0430\u0441\u0442\u044C \u044D\u0442\u043E\u0433\u043E \u0442\u0435\u043A\u0441\u0442\u0430 \u043C\u0435\u0436\u0434\u0443 \u0434\u0432\u043E\u0439\u043D\u044B\u043C\u0438 \u0434\u0435\u0444\u0438\u0441\u0430\u043C\u0438 (--...--). \u0418\u0442\u0430\u043A, \u043D\u0430\u0447\u0430\u043B\u0438:</p><p>&quot;\u092F\u0926\u093F\u0926\u0902 \u092F\u0925\u093E\u092D\u0940\u0937\u094D\u091F\u0938\u094D\u092F \u092C\u0939\u093F\u0930\u0938\u0924\u094D\u0924\u094D\u0935\u093E\u0926\u0928\u0928\u0941\u092D\u0942\u0924\u0938\u094D\u092F\u093E\u092A\u093F \u0938\u092E\u094D\u092F\u0917\u0941\u0932\u094D\u0932\u0947\u0916\u0928\u092E\u0935\u092D\u093E\u0938\u0928\u0902 \u091A \u0935\u093F\u0915\u0932\u094D\u092A\u0938\u094D\u092F \u092A\u094D\u0930\u0938\u0919\u094D\u0917\u093E\u0926\u094D\u0926\u0930\u094D\u0936\u093F\u0924\u092E\u0938\u094D\u092E\u093E\u0926\u0947\u0935 \u0939\u0947\u0924\u094B\u0930\u093F\u0926\u092E\u092A\u093F \u0938\u093F\u0926\u094D\u0927\u094D\u092F\u0924\u093F\u2014 \u092F\u0903 \u0915\u0936\u094D\u091A\u093F\u0924\u094D\u0915\u0940\u091F\u094B \u0935\u093E \u092C\u094D\u0930\u0939\u094D\u092E\u093E \u0935\u093E \u091C\u0940\u0935\u0928\u0915\u094D\u0930\u093F\u092F\u093E\u0935\u093F\u0937\u094D\u091F\u0938\u094D\u0924\u0938\u094D\u092F\u093E\u0935\u092D\u093E\u0938\u0928\u0930\u0942\u092A\u093E \u091C\u094D\u091E\u093E\u0928\u0936\u0915\u094D\u0924\u093F\u0930\u0941\u0932\u094D\u0932\u0947\u0916\u0928\u0930\u0942\u092A\u093E \u091A \u0915\u094D\u0930\u093F\u092F\u093E\u0936\u0915\u094D\u0924\u093F\u0930\u094D\u0928\u0948\u0938\u0930\u094D\u0917\u093F\u0915\u0940 \u0924\u0924\u0938\u094D\u0924\u0938\u094D\u092F\u093E\u0902 \u092D\u0942\u092E\u094C \u0935\u094D\u092F\u0924\u093F\u0930\u093F\u0915\u094D\u0924\u0947\u0936\u094D\u0935\u0930\u094B\u092A\u0915\u0932\u094D\u092A\u093F\u0924\u092A\u0942\u0930\u094D\u0935\u0938\u093F\u0926\u094D\u0927\u0938\u0943\u0937\u094D\u091F\u094D\u092F\u0941\u092A\u091C\u0940\u0935\u0928\u0938\u092E\u094D\u092D\u093E\u0935\u0928\u093E\u092A\u093F \u0928\u093E\u0938\u094D\u0924\u0940\u0924\u093F \u0938\u094D\u0935\u092E\u0947\u0935\u0948\u0936\u094D\u0935\u0930\u094D\u092F\u0902 \u0938\u094D\u092B\u0941\u091F\u0902 \u092A\u094D\u0930\u0924\u094D\u092F\u092D\u093F\u091C\u094D\u091E\u0947\u092F\u0902 \u091C\u093E\u0928\u093E\u0924\u093F \u0915\u0930\u094B\u0924\u093F \u091A\u2014 \u0907\u0924\u093F \u091C\u094D\u091E\u093E\u0928\u0915\u094D\u0930\u093F\u092F\u093E\u0938\u094D\u0935\u093E\u0924\u0928\u094D\u0924\u094D\u0930\u094D\u092F\u0932\u0915\u094D\u0937\u0923\u092E\u0947\u0915\u0935\u091A\u0928\u0947\u0928 \u0938\u0930\u094D\u0935\u0938\u094D\u092F \u091C\u0940\u0935\u091C\u093E\u0924\u0938\u094D\u092F \u0935\u0938\u094D\u0924\u0941\u0924 \u090F\u0915\u0947\u0936\u094D\u0935\u0930\u0930\u0942\u092A\u0924\u093E\u0902 \u0938\u0942\u091A\u092F\u0924\u093F\u0964 \u0907\u0924\u093F \u0936\u093F\u0935\u092E\u094D\u0965\u0967\u0967\u0965&quot; -</p><p>&quot;Yadida\u1E41 yath\u0101bh\u012B\u1E63\u1E6Dasya bahirasattv\u0101dananubh\u016Btasy\u0101pi samyagullekhanamavabh\u0101sana\u1E41 ca vikalpasya prasa\u1E45g\u0101ddar\u015Bitamasm\u0101deva hetoridamapi siddhyati\u2014 Ya\u1E25 ka\u015Bcitk\u012B\u1E6Do v\u0101 brahm\u0101 v\u0101 j\u012Bvanakriy\u0101vi\u1E63\u1E6Dastasy\u0101vabh\u0101sanar\u016Bp\u0101 j\xF1\u0101na\u015Baktirullekhanar\u016Bp\u0101 ca kriy\u0101\u015Baktirnaisargik\u012B tatastasy\u0101\u1E41 bh\u016Bmau vyatirikte\u015Bvaropakalpitap\u016Brvasiddhas\u1E5B\u1E63\u1E6Dyupaj\u012Bvanasambh\u0101van\u0101pi n\u0101st\u012Bti svamevai\u015Bvarya\u1E41 sphu\u1E6Da\u1E41 pratyabhij\xF1eya\u1E41 j\u0101n\u0101ti karoti ca\u2014 Iti j\xF1\u0101nakriy\u0101sv\u0101tantryalak\u1E63a\u1E47amekavacanena sarvasya j\u012Bvaj\u0101tasya vastuta eke\u015Bvarar\u016Bpat\u0101\u1E41 s\u016Bcayati| Iti \u015Bivam||11||&quot; -</p><p>&quot;[\u0422\u0435\u0440\u043C\u0438\u043D &#39;samullekha&#39; \u0432 \u0441\u0442\u0440\u043E\u0444\u0435 \u043E\u0437\u043D\u0430\u0447\u0430\u0435\u0442] \u0442\u043E, \u043A\u043E\u0442\u043E\u0440\u043E\u0435 [\u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F] \u043F\u043E\u043B\u043D\u044B\u043C &#39;ullekha&#39; [\u0438\u043B\u0438] \u0438\u0441\u043F\u043E\u043B\u043D\u0435\u043D\u0438\u0435\u043C, \u0438\u043B\u0438 \u043F\u0440\u0438\u0434\u0430\u043D\u0438\u0435\u043C \u0444\u043E\u0440\u043C\u044B. [\u042D\u0442\u043E \u043E\u0437\u043D\u0430\u0447\u0430\u0435\u0442 \u0444\u043E\u0440\u043C\u0438\u0440\u043E\u0432\u0430\u0442\u044C] \u0447\u0442\u043E-\u043B\u0438\u0431\u043E \u043F\u043E \u0436\u0435\u043B\u0430\u043D\u0438\u044E, \u0447\u0442\u043E \u0435\u0449\u0435 \u043D\u0435 \u0431\u044B\u043B\u043E \u043F\u0435\u0440\u0435\u0436\u0438\u0442\u043E \u043D\u0430 \u043E\u043F\u044B\u0442\u0435, \u0442\u0430\u043A \u043A\u0430\u043A \u043D\u0435 \u0441\u0443\u0449\u0435\u0441\u0442\u0432\u043E\u0432\u0430\u043B\u043E \u0432\u043D\u0435\u0448\u043D\u0435. \u0418 [\u0442\u0435\u0440\u043C\u0438\u043D &#39;avabh\u0101sana&#39;, \u0438\u043B\u0438] \u0441\u0438\u043B\u0430 \u043A\u043E\u043D\u0446\u0435\u043F\u0442\u0443\u0430\u043B\u0438\u0437\u0430\u0446\u0438\u0438 \u043F\u043E\u043A\u0430\u0437\u0430\u043D\u0430 \u0432 \u0441\u043B\u0443\u0447\u0430\u0435 \u0441 vikalpa, \u0438\u043B\u0438 \u043C\u044B\u0441\u043B\u044C\u044E --\u0442.\u0435. \u044D\u0442\u043E \u043E\u0447\u0435\u0432\u0438\u0434\u043D\u043E \u0438\u0437 \u043F\u0440\u043E\u0441\u0442\u043E\u0433\u043E \u0441\u043E\u0437\u0435\u0440\u0446\u0430\u043D\u0438\u044F, \u043A\u0430\u043A \u0447\u044C\u0438-\u0442\u043E \u043C\u044B\u0441\u043B\u0438 \u043F\u0440\u0435\u0434\u0441\u0442\u0430\u0432\u043B\u044F\u044E\u0442 \u0441\u0435\u0431\u0435 \u043D\u043E\u0432\u044B\u0435 \u0432\u0435\u0449\u0438--. \u041F\u043E\u0441\u043B\u0435\u0434\u043D\u044F\u044F --\u0441\u0438\u043B\u0430 \u043A\u043E\u043D\u0446\u0435\u043F\u0442\u0443\u0430\u043B\u0438\u0437\u0430\u0446\u0438\u0438-- \u0434\u043E\u043A\u0430\u0437\u0430\u043D\u0430 \u043F\u043E\u0441\u0440\u0435\u0434\u0441\u0442\u0432\u043E\u043C [\u043D\u0430\u043B\u0438\u0447\u0438\u044F] \u043F\u0435\u0440\u0432\u043E\u0439 --\u0441\u0438\u043B\u044B \u0432\u043E\u043F\u043B\u043E\u0449\u0435\u043D\u0438\u044F; \u0442\u043E \u0435\u0441\u0442\u044C \u043F\u043E\u0441\u043A\u043E\u043B\u044C\u043A\u0443 \u0435\u0441\u043B\u0438 \u0447\u0442\u043E-\u0442\u043E \u0431\u044B\u043B\u043E \u0432\u044B\u043F\u043E\u043B\u043D\u0435\u043D\u043E, \u0438\u043B\u0438 \u0444\u0430\u043A\u0442\u0438\u0447\u0435\u0441\u043A\u0438 \u0441\u043E\u0437\u0434\u0430\u043D\u043E, \u044D\u0442\u043E \u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F \u043E\u0431\u043E\u0441\u043D\u043E\u0432\u0430\u043D\u043D\u044B\u043C \u0434\u043E\u043A\u0430\u0437\u0430\u0442\u0435\u043B\u044C\u0441\u0442\u0432\u043E\u043C \u0442\u043E\u0433\u043E, \u0447\u0442\u043E \u0432\u043D\u0430\u0447\u0430\u043B\u0435 \u043E\u043D\u043E \u0431\u044B\u043B\u043E \u0437\u0430\u0434\u0443\u043C\u0430\u043D\u043E-- \u2014 \u0412\u0441\u0451, \u0447\u0442\u043E \u043D\u0430\u0434\u0435\u043B\u0435\u043D\u043E \u0434\u0435\u044F\u0442\u0435\u043B\u044C\u043D\u043E\u0441\u0442\u044C\u044E \u0438 \u0436\u0438\u0437\u043D\u044C\u044E, \u0431\u0443\u0434\u044C \u0442\u043E \u0447\u0435\u0440\u0432\u044C \u0438\u043B\u0438 [\u0441\u0430\u043C] Brahm\u0101 --\u0441\u043E\u0437\u0434\u0430\u0442\u0435\u043B\u044C \u043C\u0430\u0442\u0435\u0440\u0438\u0430\u043B\u044C\u043D\u043E\u0439 \u0432\u0441\u0435\u043B\u0435\u043D\u043D\u043E\u0439--, \u0441\u0438\u043B\u0430 \u0437\u043D\u0430\u043D\u0438\u044F \u0438 \u0435\u0441\u0442\u0435\u0441\u0442\u0432\u0435\u043D\u043D\u0430\u044F \u0441\u0438\u043B\u0430 \u0434\u0435\u0439\u0441\u0442\u0432\u0438\u044F \u044D\u0442\u0438\u0445 [\u0436\u0438\u0432\u044B\u0445 \u0441\u0443\u0449\u0435\u0441\u0442\u0432] \u043F\u0440\u043E\u044F\u0432\u043B\u044F\u044E\u0442\u0441\u044F \u043F\u043E \u0441\u0432\u043E\u0435\u0439 \u043F\u0440\u0438\u0440\u043E\u0434\u0435 \u043A\u0430\u043A \u0441\u0438\u043B\u044B \u043A\u043E\u043D\u0446\u0435\u043F\u0442\u0443\u0430\u043B\u0438\u0437\u0430\u0446\u0438\u0438 \u0438 \u0432\u043E\u043F\u043B\u043E\u0449\u0435\u043D\u0438\u044F, [\u0441\u043E\u043E\u0442\u0432\u0435\u0442\u0441\u0442\u0432\u0435\u043D\u043D\u043E]. \u0421\u043B\u0435\u0434\u043E\u0432\u0430\u0442\u0435\u043B\u044C\u043D\u043E, \u043D\u0430 \u044D\u0442\u043E\u0439 \u043E\u0441\u043D\u043E\u0432\u0435 --\u0442.\u0435. \u043D\u0430 \u043E\u0441\u043D\u043E\u0432\u0435 \u0432\u043E\u043E\u0431\u0440\u0430\u0436\u0435\u043D\u0438\u044F, \u0438\u043C\u0435\u044E\u0449\u0435\u0433\u043E \u043C\u0435\u0441\u0442\u0430 \u0432 \u0441\u0444\u0435\u0440\u0435 \u0444\u0430\u043D\u0442\u0430\u0437\u0438\u0438 \u044D\u0442\u0438\u0445 \u0436\u0438\u0432\u044B\u0445 \u0441\u0443\u0449\u0435\u0441\u0442\u0432 \u0438 \u0442.\u0434.--, \u043D\u0435\u0442 \u0434\u0430\u0436\u0435 \u043F\u0440\u0435\u0434\u043F\u043E\u043B\u043E\u0436\u0435\u043D\u0438\u044F, \u0447\u0442\u043E \u0441\u0443\u0449\u0435\u0441\u0442\u0432\u043E\u0432\u0430\u043D\u0438\u0435 \u0442\u0432\u043E\u0440\u0435\u043D\u0438\u044F, \u043A\u043E\u0442\u043E\u0440\u043E\u0435 \u0440\u0430\u043D\u0435\u0435 \u0431\u044B\u043B\u043E \u043F\u0440\u0438\u0437\u043D\u0430\u043D\u043E \u0438\u0441\u0442\u0438\u043D\u043D\u044B\u043C, \u0431\u044B\u043B\u043E \u0441\u043E\u0437\u0434\u0430\u043D\u043E \u0434\u0440\u0443\u0433\u0438\u043C \u0432\u043B\u0430\u0434\u044B\u043A\u043E\u0439 --\u043A\u043E\u0440\u043E\u0447\u0435 \u0433\u043E\u0432\u043E\u0440\u044F, \u0438\u0441\u0445\u043E\u0434\u044F \u0438\u0437 \u043E\u043F\u044B\u0442\u0430 \u043B\u044E\u0431\u043E\u0433\u043E \u0436\u0438\u0432\u043E\u0433\u043E \u0441\u0443\u0449\u0435\u0441\u0442\u0432\u0430, \u0432\u0441\u0435, \u0447\u0442\u043E \u0437\u0430\u0434\u0443\u043C\u0430\u043D\u043E \u0438 \u0441\u043E\u0437\u0434\u0430\u043D\u043E \u0432 \u0435\u0433\u043E/\u0435\u0435 \u0443\u043C\u0435, \u043D\u0435 \u0442\u0440\u0435\u0431\u0443\u0435\u0442 \u043F\u0440\u0438\u0441\u0443\u0442\u0441\u0442\u0432\u0438\u044F \u0442\u0430\u043C \u0434\u0440\u0443\u0433\u043E\u0433\u043E \u0447\u0435\u043B\u043E\u0432\u0435\u043A\u0430 \u043A\u0440\u043E\u043C\u0435 \u0441\u0430\u043C\u043E\u0433\u043E \u0441\u0435\u0431\u044F/\u0441\u0430\u043C\u043E\u0439 \u0441\u0435\u0431\u044F--. \u0422\u0430\u043A\u0438\u043C \u043E\u0431\u0440\u0430\u0437\u043E\u043C, [\u0442\u0430\u043A\u043E\u0435 \u0436\u0438\u0432\u043E\u0435 \u0441\u0443\u0449\u0435\u0441\u0442\u0432\u043E] \u044F\u0441\u043D\u043E \u0437\u043D\u0430\u0435\u0442 \u0438 \u043E\u0441\u0443\u0449\u0435\u0441\u0442\u0432\u043B\u044F\u0435\u0442 \u0435\u0433\u043E/\u0435\u0435 \u0441\u043E\u0431\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u0435 \u0433\u043E\u0441\u043F\u043E\u0434\u0441\u0442\u0432\u043E, \u043A\u043E\u0442\u043E\u0440\u043E\u0435 \u0434\u043E\u043B\u0436\u043D\u043E \u0431\u044B\u0442\u044C \u043E\u0441\u043E\u0437\u043D\u0430\u043D\u043E--\u0442.\u0435. \u043E\u043D/\u043E\u043D\u0430 \u0437\u043D\u0430\u0435\u0442 \u0438 \u0441\u043E\u0437\u0434\u0430\u0435\u0442 \u0432\u0435\u0449\u0438 \u043A\u0430\u043A \u0432\u043B\u0430\u0434\u044B\u043A\u0430, \u043D\u043E \u0435\u0449\u0435 \u0434\u043E\u043B\u0436\u0435\u043D \u043E\u0441\u043E\u0437\u043D\u0430\u0442\u044C/\u043F\u0440\u0438\u0437\u043D\u0430\u0442\u044C \u0435\u0433\u043E/\u0435\u0435 \u0441\u043E\u0431\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u0435 \u0433\u043E\u0441\u043F\u043E\u0434\u0441\u0442\u0432\u043E-- \u2014 \u0412 \u044D\u0442\u043E\u043C \u0441\u043B\u0443\u0447\u0430\u0435, [\u044D\u0442\u043E \u0433\u043E\u0441\u043F\u043E\u0434\u0441\u0442\u0432\u043E] \u0445\u0430\u0440\u0430\u043A\u0442\u0435\u0440\u0438\u0437\u0443\u0435\u0442\u0441\u044F \u0437\u043D\u0430\u043D\u0438\u0435\u043C, \u0434\u0435\u0439\u0441\u0442\u0432\u0438\u0435\u043C \u0438 \u0441\u0432\u043E\u0431\u043E\u0434\u043E\u0439, \u0432 \u0435\u0434\u0438\u043D\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u043C \u0447\u0438\u0441\u043B\u0435 --\u0430 \u0438\u043C\u0435\u043D\u043D\u043E, \u0438\u043C\u0435\u0435\u0442 \u043C\u0435\u0441\u0442\u043E \u043E\u0434\u043D\u043E \u0433\u043E\u0441\u043F\u043E\u0434\u0441\u0442\u0432\u043E/\u0432\u043B\u0430\u0434\u044B\u0447\u0435\u0441\u0442\u0432\u043E, \u043D\u0435 \u0434\u0432\u0430 \u0438 \u0431\u043E\u043B\u0435\u0435--, \u0432 \u0441\u043B\u0443\u0447\u0430\u0435 \u0432\u0441\u0435\u0445 \u0442\u0435\u0445, \u043A\u0442\u043E \u043E\u0434\u0435\u0440\u0436\u0438\u043C \u0436\u0438\u0437\u043D\u044C\u044E --\u0442.\u0435. \u0436\u0438\u0432\u044B\u0445 \u0441\u0443\u0449\u0435\u0441\u0442\u0432--, \u0444\u0430\u043A\u0442\u0438\u0447\u0435\u0441\u043A\u0438 \u0443\u043A\u0430\u0437\u044B\u0432\u0430\u0435\u0442 \u043D\u0430 \u0438\u0445 \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u0435, \u043A\u0430\u043A \u0441\u0443\u0449\u0435\u0441\u0442\u0432, \u0441\u043E\u0437\u0434\u0430\u043D\u043D\u044B\u0445 \u0435\u0434\u0438\u043D\u0441\u0442\u0432\u0435\u043D\u043D\u044B\u043C \u0413\u043E\u0441\u043F\u043E\u0434\u043E\u043C --\u0432\u043A\u0440\u0430\u0442\u0446\u0435, \u0433\u043E\u0441\u043F\u043E\u0434\u0441\u0442\u0432\u043E/\u0432\u043B\u0430\u0434\u044B\u0447\u0435\u0441\u0442\u0432\u043E, \u043F\u0440\u043E\u044F\u0432\u043B\u044F\u0435\u043C\u043E\u0435 \u0436\u0438\u0432\u044B\u043C\u0438 \u0441\u0443\u0449\u0435\u0441\u0442\u0432\u0430\u043C\u0438, \u0431\u0443\u0434\u0443\u0447\u0438 \u0442\u043E\u043B\u044C\u043A\u043E \u043E\u0434\u043D\u0438\u043C \u0432 \u043A\u0430\u0436\u0434\u043E\u043C \u0438\u0437 \u043D\u0438\u0445, \u043D\u0430 \u0441\u0430\u043C\u043E\u043C \u0434\u0435\u043B\u0435 \u0443\u043A\u0430\u0437\u044B\u0432\u0430\u0435\u0442 \u043D\u0430 \u0442\u043E, \u0447\u0442\u043E \u0438\u0445 \u0441\u0443\u0449\u043D\u043E\u0441\u0442\u043D\u043E\u0439 \u043F\u0440\u0438\u0440\u043E\u0434\u043E\u0439 \u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F &#39;\u043E\u0434\u0438\u043D&#39; \u0413\u043E\u0441\u043F\u043E\u0434\u044C --.</p><p>\u0414\u0430 \u0431\u0443\u0434\u0435\u0442 \u0431\u043B\u0430\u0433\u043E\u0434\u0435\u043D\u0441\u0442\u0432\u0438\u0435 \u0434\u043B\u044F \u0432\u0441\u0435\u0445 \u0441\u0443\u0449\u0435\u0441\u0442\u0432!&quot;.</p><p>\u041D\u0430\u0434\u0435\u044E\u0441\u044C, \u0447\u0442\u043E \u044F \u043F\u0440\u0430\u0432\u0438\u043B\u044C\u043D\u043E \u0432\u0441\u0435 \u043F\u043E\u043D\u044F\u043B. Abhinavagupta \u2014 \u0442\u0430\u043A\u043E\u0439 \u0432\u0435\u043B\u0438\u043A\u0438\u0439 \u043C\u0430\u0441\u0442\u0435\u0440 \u0438 \u043C\u044B\u0441\u043B\u0438\u0442\u0435\u043B\u044C, \u0447\u0442\u043E \u043D\u0435\u043E\u0431\u0445\u043E\u0434\u0438\u043C\u043E \u043F\u0440\u0438\u0441\u0443\u0442\u0441\u0442\u0432\u0438\u0435 \u0443\u0447\u0435\u043D\u0438\u043A\u0430 \u043A\u0430\u043B\u0438\u0431\u0440\u0430 \u0441\u0430\u043C\u043E\u0433\u043E K\u1E63emar\u0101ja (\u0435\u0433\u043E \u0433\u043B\u0430\u0432\u043D\u043E\u0433\u043E \u0443\u0447\u0435\u043D\u0438\u043A\u0430) \u0434\u043B\u044F \u0442\u043E\u0433\u043E, \u0447\u0442\u043E\u0431\u044B \u0440\u0430\u0441\u0448\u0438\u0444\u0440\u043E\u0432\u0430\u0442\u044C \u0435\u0433\u043E \u0443\u0447\u0435\u043D\u0438\u044F \u043D\u0430 \u0441\u0430\u043D\u043A\u0440\u0438\u0442\u0435. \u0413\u043E\u0441\u043F\u043E\u0434\u0438, \u0431\u0443\u0434\u044C \u043C\u0438\u043B\u043E\u0441\u0435\u0440\u0434\u0435\u043D, \u0438 \u043F\u043E\u043C\u043D\u0438, \u0447\u0442\u043E \u044F \u2014 \u043E\u0434\u0438\u043D \u043D\u0430 \u043C\u043E\u0435\u0439 \u043C\u0430\u043B\u0435\u043D\u044C\u043A\u043E\u0439 \u043B\u043E\u0434\u043A\u0435 \u043F\u043E\u0441\u0440\u0435\u0434\u0438 \u043E\u043A\u0435\u0430\u043D\u0430 \u043F\u043E\u0434\u043B\u0438\u043D\u043D\u044B\u0445 \u041F\u0438\u0441\u0430\u043D\u0438\u0439, \u043A\u043E\u043C\u043C\u0435\u043D\u0442\u0430\u0440\u0438\u0435\u0432 \u0438 \u043E\u0431\u044A\u044F\u0441\u043D\u0435\u043D\u0438\u0439 \u0443\u0447\u0435\u043D\u044B\u0445 \u0441 \u043C\u0443\u0434\u0440\u043E\u0441\u0442\u044C\u044E \u0432\u0435\u0434\u0438\u0447\u0435\u0441\u043A\u0438\u0445 \u043F\u0440\u043E\u0432\u0438\u0434\u0446\u0435\u0432, \u0431\u043E\u043B\u044C\u0448\u0438\u043D\u0441\u0442\u0432\u043E \u0438\u0437 \u043A\u043E\u0442\u043E\u0440\u044B\u0445 \u043D\u0430\u043F\u0438\u0441\u0430\u043D\u044B \u043D\u0430 \u0447\u0438\u0441\u0442\u0435\u0439\u0448\u0435\u043C \u0441\u0430\u043D\u0441\u043A\u0440\u0438\u0442\u0435 (\u0434\u0430\u0436\u0435 \u043D\u0435 \u0432 \u0442\u0440\u0430\u043D\u0441\u043B\u0438\u0442\u0435\u0440\u0430\u0446\u0438\u0438). \u041A \u0441\u043E\u0436\u0430\u043B\u0435\u043D\u0438\u044E, \u0443 \u043C\u0435\u043D\u044F \u043D\u0435\u0442 \u043D\u0438\u043A\u043E\u0433\u043E, \u0444\u0438\u0437\u0438\u0447\u0435\u0441\u043A\u0438 \u0433\u043E\u0432\u043E\u0440\u044F, \u043A\u0442\u043E \u0431\u044B \u043D\u0430\u0448\u0435\u043F\u0442\u044B\u0432\u0430\u043B \u043F\u0435\u0440\u0435\u0432\u043E\u0434 \u043C\u043D\u0435 \u0432 \u0443\u0448\u0438. \u0411\u044B\u043B\u043E \u0431\u044B \u0437\u0434\u043E\u0440\u043E\u0432\u043E \u0438\u043C\u0435\u0442\u044C \u043A\u043E\u0433\u043E-\u043D\u0438\u0431\u0443\u0434\u044C. \u041E\u043A, \u0442\u0435\u043C \u0432\u0440\u0435\u043C\u0435\u043D\u0435\u043C \u044F \u0434\u043E\u043B\u0436\u0435\u043D \u043F\u0440\u043E\u0434\u043E\u043B\u0436\u0430\u0442\u044C \u0433\u0440\u0435\u0441\u0442\u0438.</p></li><li><p>\u041E\u0447\u0435\u0432\u0438\u0434\u043D\u043E, \u0447\u0442\u043E \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u0435 \u0442\u0432\u043E\u0440\u0446\u0430, \u043A\u043E\u0442\u043E\u0440\u043E\u0435 \u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F \u043E\u0431\u044B\u0447\u043D\u044B\u043C \u0434\u043B\u044F \u0432\u0441\u0435\u0445, \u0443\u043A\u0430\u0437\u044B\u0432\u0430\u0435\u0442 \u043D\u0430 \u0442\u043E, \u0447\u0442\u043E \u043E\u043D\u043E \u0443\u043D\u0438\u0432\u0435\u0440\u0441\u0430\u043B\u044C\u043D\u043E. \u042D\u0442\u043E \u043F\u0440\u0430\u0432\u0438\u043B\u044C\u043D\u043E \u0441 \u0442\u043E\u0447\u043A\u0438 \u0437\u0440\u0435\u043D\u0438\u044F, \u0447\u0442\u043E &quot;\u0432\u0441\u0435 \u0436\u0438\u0432\u044B\u0435 \u0441\u0443\u0449\u0435\u0441\u0442\u0432\u0430&quot; \u0438\u043C\u0435\u044E\u0442 \u0442\u0430\u043A\u043E\u0435 \u0436\u0435 \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u0435 \u0442\u0432\u043E\u0440\u0446\u0430, \u043A\u0430\u043A \u0438 \u043F\u0440\u043E\u0441\u0432\u0435\u0442\u043B\u0435\u043D\u043D\u044B\u0439 Yog\u012B, \u043F\u043E\u0442\u043E\u043C\u0443 \u0447\u0442\u043E \u0435\u0434\u0438\u043D\u0441\u0442\u0432\u0435\u043D\u043D\u044B\u0439 \u0413\u043E\u0441\u043F\u043E\u0434\u044C \u043F\u0440\u0435\u0431\u044B\u0432\u0430\u0435\u0442 \u0432\u043E \u0432\u0441\u0435\u0445 \u043E\u0434\u0438\u043D\u0430\u043A\u043E\u0432\u043E. \u0422\u0430\u043A \u0438\u043B\u0438 \u0438\u043D\u0430\u0447\u0435, \u0441\u043E\u0433\u043B\u0430\u0441\u043D\u043E \u043C\u0443\u0434\u0440\u0435\u0446\u0430\u043C, \u0432 \u044D\u0442\u043E\u043C \u043A\u043E\u043D\u043A\u0440\u0435\u0442\u043D\u043E\u043C \u043A\u043E\u043D\u0442\u0435\u043A\u0441\u0442\u0435, \u0438\u043D\u0442\u0435\u0440\u043F\u0440\u0435\u0442\u0430\u0446\u0438\u044F \u0444\u0440\u0430\u0437\u044B \u0442\u0430\u043A\u043E\u0432\u0430: &quot; \u0935\u093F\u092E\u0930\u094D\u0936\u093E\u0924\u093F\u0936\u092F\u0935\u0936\u093E\u0924\u094D\u0938\u0930\u094D\u0935\u091C\u0928\u0948\u0938\u094D\u0924\u0928\u094D\u0928\u093F\u0930\u094D\u092E\u093F\u0924\u093F\u0930\u094D\u0926\u094D\u0930\u0937\u094D\u091F\u0941\u0902 \u0936\u0915\u094D\u092F\u0924\u0947 &quot; - &quot;Vimar\u015B\u0101ti\u015Bayava\u015B\u0101tsarvajanaistannirmitirdra\u1E63\u1E6Du\u1E41 \u015Bakyate&quot; - &quot;\u0418\u0437-\u0437\u0430 \u043F\u0440\u0435\u043E\u0431\u043B\u0430\u0434\u0430\u043D\u0438\u044F Vimar\u015Ba, \u0438\u043B\u0438 \u042F-\u0441\u043E\u0437\u043D\u0430\u043D\u0438\u044F --\u0442.\u0435. \u015Aakti--, \u0435\u0433\u043E \u0442\u0432\u043E\u0440\u0435\u043D\u0438\u0435 \u043C\u043E\u0436\u0435\u0442 \u0431\u044B\u0442\u044C \u0432\u0438\u0434\u043D\u043E \u0432\u0441\u0435\u043C \u043B\u044E\u0434\u044F\u043C&quot;. \u0422\u0435\u043F\u0435\u0440\u044C \u0432\u0441\u0435 \u0441\u043E\u0432\u0435\u0440\u0448\u0435\u043D\u043D\u043E \u044F\u0441\u043D\u043E!</p></li><li><p>\u042D\u0442\u043E \u043E\u0442\u043D\u043E\u0441\u0438\u0442\u0441\u044F \u043A \u043E\u0434\u043D\u043E\u043C\u0443 \u0438\u0437 \u043F\u044F\u0442\u0438 \u0434\u0435\u0440\u0435\u0432\u044C\u0435\u0432 \u0440\u0430\u044F \u0431\u043E\u0433\u0430 \u0418\u043D\u0434\u0440\u044B. \u0413\u043E\u0432\u043E\u0440\u044F\u0442, \u0447\u0442\u043E \u044D\u0442\u043E\u0442 Kalpap\u0101dapa, \u0438\u043B\u0438 Kalpataru \u0438\u0441\u043F\u043E\u043B\u043D\u044F\u0435\u0442 \u0432\u0441\u0435 \u0436\u0435\u043B\u0430\u043D\u0438\u044F. \u0422\u043E\u0447\u043D\u043E \u0442\u0430\u043A \u0436\u0435, \u043A\u043E\u0433\u0434\u0430 \u0441\u0438\u043B\u0430 (\u0430 \u0438\u043C\u0435\u043D\u043D\u043E, \u0441\u043E\u0437\u0438\u0434\u0430\u0442\u0435\u043B\u044C\u043D\u0430\u044F \u0441\u0438\u043B\u0430) Yog\u012B-s \u043D\u0430\u0445\u043E\u0434\u0438\u0442\u0441\u044F \u043D\u0430 \u043F\u0438\u043A\u0435, \u0438\u0445 \u0441\u0438\u043B\u0430 \u0432\u043E\u043B\u0438 \u043C\u043E\u0436\u0435\u0442 \u0432\u044B\u043F\u043E\u043B\u043D\u0438\u0442\u044C \u043B\u044E\u0431\u043E\u0435 \u0436\u0435\u043B\u0430\u043D\u0438\u0435. \u041A\u0440\u0430\u0442\u043A\u043E: \u041E\u043D\u0438 \u043C\u043E\u0433\u0443\u0442 \u043F\u0440\u043E\u044F\u0432\u043B\u044F\u0442\u044C \u0432\u0441\u0435, \u0447\u0442\u043E \u0443\u0433\u043E\u0434\u043D\u043E \u043F\u043E \u0441\u0432\u043E\u0435\u043C\u0443 \u0436\u0435\u043B\u0430\u043D\u0438\u044E. \u042D\u0442\u043E \u043F\u043E\u0442\u043E\u043C\u0443, \u0447\u0442\u043E \u043E\u043D\u0438 \u043F\u043E\u0434\u043E\u0431\u043D\u044B \u0413\u043E\u0441\u043F\u043E\u0434\u0443 \u0432 \u044D\u0442\u043E \u0432\u0440\u0435\u043C\u044F. \u0427\u0442\u043E \u0432 \u044D\u0442\u043E\u043C \u0441\u043B\u0443\u0447\u0430\u0435 \u044F \u043C\u043E\u0433\u0443 \u0435\u0449\u0435 \u0441\u043A\u0430\u0437\u0430\u0442\u044C \u043E \u043D\u0438\u0445?</p></li></ol></div><div class="stanza"><a href="#s3.38" id="s3.38" class="num">3.38</a><div class="sans"><p>\u092F\u0924\u0936\u094D\u091A \u0915\u0930\u0923\u0936\u0915\u094D\u0924\u093F\u0936\u092C\u094D\u0926\u094B\u0915\u094D\u0924\u094D\u092F\u093E \u0924\u0941\u0930\u094D\u092F\u093E\u0924\u094D\u092E\u093E \u0938\u094D\u0935\u093E\u0924\u0928\u094D\u0924\u094D\u0930\u094D\u092F\u0936\u0915\u094D\u0924\u093F\u0930\u0947\u0935 \u092C\u094B\u0927\u0930\u0942\u092A\u0938\u094D\u092F \u092A\u094D\u0930\u092E\u093E\u0924\u0941\u0903 \u0938\u093E\u0930\u092E\u0924\u094B \u092E\u093E\u092F\u093E\u0936\u0915\u094D\u0924\u094D\u092F\u092A\u0939\u0938\u094D\u0924\u093F\u0924\u0924\u0924\u094D\u0938\u094D\u0935\u0930\u0942\u092A\u094B\u0924\u094D\u0924\u0947\u091C\u0928\u093E\u092F\u2014</p><blockquote><p><strong>\u0924\u094D\u0930\u093F\u092A\u0926\u093E\u0926\u094D\u092F\u0928\u0941\u092A\u094D\u0930\u093E\u0923\u0928\u092E\u094D\u0965\u0969\u096E\u0965</strong></p></blockquote><p>\u0924\u094D\u0930\u092F\u093E\u0923\u093E\u0902 \u092D\u093E\u0935\u094C\u0928\u094D\u092E\u0941\u0916\u094D\u092F\u0924\u0926\u092D\u093F\u0937\u094D\u0935\u0919\u094D\u0917\u0924\u0926\u0928\u094D\u0924\u0930\u094D\u092E\u0941\u0916\u0940\u092D\u093E\u0935\u0928\u093E\u092E\u092F\u093E\u0928\u093E\u0902 \u0938\u0943\u0937\u094D\u091F\u093F\u0938\u094D\u0925\u093F\u0924\u093F\u0932\u092F\u0936\u092C\u094D\u0926\u094B\u0915\u094D\u0924\u093E\u0928\u093E\u0902 \u092A\u0926\u093E\u0928\u093E\u092E\u0935\u0938\u094D\u0925\u093E\u0928\u093E\u0902 \u092F\u0926\u093E\u0926\u093F \u092A\u094D\u0930\u0927\u093E\u0928\u0902 \u0924\u094D\u0930\u093F\u091A\u092E\u0924\u094D\u0915\u0943\u0924\u093F\u0924\u094D\u0935\u0947\u0928\u093E\u0928\u0928\u094D\u0926\u0918\u0928\u0902 \u0924\u0941\u0930\u094D\u092F\u093E\u0916\u094D\u092F\u0902 \u092A\u0926\u0902 \u092E\u093E\u092F\u093E\u0936\u0915\u094D\u0924\u094D\u092F\u093E\u091A\u094D\u091B\u093E\u0926\u093F\u0924\u092E\u092A\u093F \u0924\u0924\u094D\u0924\u0926\u094D\u0935\u093F\u0937\u092F\u094B\u092A\u092D\u094B\u0917\u093E\u0926\u094D\u092F\u0935\u0938\u0930\u0947\u0937\u0941 \u0935\u093F\u0926\u094D\u092F\u0941\u0926\u094D\u0935\u0926\u093E\u092D\u093E\u0938\u092E\u093E\u0928\u0902 \u0924\u0947\u0928 \u0924\u0924\u094D\u0924\u0926\u0935\u0938\u0930\u0947\u0937\u0941 \u0915\u094D\u0937\u0923\u092E\u093E\u0924\u094D\u0930\u094B\u0926\u093F\u0924\u0947\u0928\u093E\u092A\u094D\u092F\u0928\u0941\u092A\u094D\u0930\u093E\u0923\u0928\u092E\u0928\u094D\u0924\u0930\u094D\u092E\u0941\u0916\u0924\u0926\u094D\u0935\u093F\u092E\u0930\u094D\u0936\u093E\u0935\u0938\u094D\u0925\u093F\u0924\u093F\u0924\u093E\u0930\u0924\u092E\u094D\u092F\u0947\u0928\u093E\u0928\u0941\u0917\u0924\u0924\u092F\u093E \u092A\u094D\u0930\u093E\u0923\u0928\u092E\u093E\u0924\u094D\u092E\u0928\u0938\u094D\u0924\u0947\u0928\u0948\u0935 \u091C\u0940\u0935\u093F\u0924\u0947\u0928\u093E\u092A\u093F \u091C\u0940\u0935\u093F\u0924\u0938\u094D\u092F\u094B\u0924\u094D\u0924\u0947\u091C\u0928\u0902 \u0915\u0941\u0930\u094D\u092F\u093E\u0924\u094D\u0964 \u0924\u0926\u0941\u0915\u094D\u0924\u0902 \u0936\u094D\u0930\u0940\u0935\u093F\u091C\u094D\u091E\u093E\u0928\u092D\u0948\u0930\u0935\u0947</p><blockquote><p>\u0905\u0928\u094D\u0924\u0903 \u0938\u094D\u0935\u093E\u0928\u0941\u092D\u0935\u093E\u0928\u0928\u094D\u0926\u093E \u0935\u093F\u0915\u0932\u094D\u092A\u094B\u0928\u094D\u092E\u0941\u0915\u094D\u0924\u0917\u094B\u091A\u0930\u093E\u0964<br> \u092F\u093E\u0935\u0938\u094D\u0925\u093E \u092D\u0930\u093F\u0924\u093E\u0915\u093E\u0930\u093E \u092D\u0948\u0930\u0935\u0940 \u092D\u0948\u0930\u0935\u093E\u0924\u094D\u092E\u0928\u0903\u0965<br> \u0924\u0926\u094D\u0935\u092A\u0941\u0938\u094D\u0924\u0924\u094D\u0924\u094D\u0935\u0924\u094B \u091C\u094D\u091E\u0947\u092F\u0902 \u0935\u093F\u092E\u0932\u0902 \u0935\u093F\u0936\u094D\u0935\u092A\u0942\u0930\u0923\u092E\u094D\u0964</p></blockquote><p>\u0907\u0924\u094D\u092F\u093E\u0926\u094D\u092F\u0941\u092A\u0915\u094D\u0930\u092E\u094D\u092F</p><blockquote><p>\u0936\u0915\u094D\u0924\u093F\u0938\u0919\u094D\u0917\u092E\u0938\u0919\u094D\u0915\u094D\u0937\u0941\u092C\u094D\u0927\u0936\u0915\u094D\u0924\u094D\u092F\u093E\u0935\u0947\u0936\u093E\u0935\u0938\u093E\u0928\u093F\u0915\u092E\u094D\u0964<br> \u092F\u0924\u094D\u0938\u0941\u0916\u0902 \u092C\u094D\u0930\u0939\u094D\u092E\u0924\u0924\u094D\u0924\u094D\u0935\u0938\u094D\u092F \u0924\u0924\u094D\u0938\u0941\u0916\u0902 \u0938\u094D\u0935\u093E\u0915\u094D\u092F\u092E\u0941\u091A\u094D\u092F\u0924\u0947\u0965<br> \u0932\u0947\u0939\u0928\u093E\u092E\u0928\u094D\u0925\u0928\u093E\u0915\u094B\u091F\u0948\u0903 \u0938\u094D\u0924\u094D\u0930\u0940\u0938\u0941\u0916\u0938\u094D\u092F \u092D\u0930\u093E\u0924\u094D\u0938\u094D\u092E\u0943\u0924\u0947\u0903\u0964<br> \u0936\u0915\u094D\u0924\u094D\u092F\u092D\u093E\u0935\u0947\u093D\u092A\u093F \u0926\u0947\u0935\u0947\u0936\u093F \u092D\u0935\u0947\u0926\u093E\u0928\u0928\u094D\u0926\u0938\u092E\u094D\u092A\u094D\u0932\u0935\u0903\u0965<br> \u0906\u0928\u0928\u094D\u0926\u0947 \u092E\u0939\u0924\u093F \u092A\u094D\u0930\u093E\u092A\u094D\u0924\u0947 \u0926\u0943\u0937\u094D\u091F\u0947 \u0935\u093E \u092C\u093E\u0928\u094D\u0927\u0935\u0947 \u091A\u093F\u0930\u093E\u0924\u094D\u0964<br> \u0906\u0928\u0928\u094D\u0926\u092E\u0941\u0926\u094D\u0917\u0924\u0902 \u0927\u094D\u092F\u093E\u0924\u094D\u0935\u093E \u0924\u0928\u094D\u092E\u092F\u0938\u094D\u0924\u0932\u094D\u0932\u092F\u0940\u092D\u0935\u0947\u0924\u094D\u0965<br> \u091C\u0917\u094D\u0927\u093F\u092A\u093E\u0928\u0915\u0943\u0924\u094B\u0932\u094D\u0932\u093E\u0938\u0930\u0938\u093E\u0928\u0928\u094D\u0926\u0935\u093F\u091C\u0943\u092E\u094D\u092D\u0923\u093E\u0924\u094D\u0964<br> \u092D\u093E\u0935\u092F\u0947\u0926\u094D\u092D\u0930\u093F\u0924\u093E\u0935\u0938\u094D\u0925\u093E\u0902 \u092E\u0939\u093E\u0928\u0928\u094D\u0926\u0938\u094D\u0924\u0924\u094B \u092D\u0935\u0947\u0924\u094D\u0965<br> \u0917\u0940\u0924\u093E\u0926\u093F\u0935\u093F\u0937\u092F\u093E\u0938\u094D\u0935\u093E\u0926\u093E\u0938\u092E\u0938\u094C\u0916\u094D\u092F\u0948\u0915\u0924\u093E\u0924\u094D\u092E\u0928\u0903\u0964<br> \u092F\u094B\u0917\u093F\u0928\u0938\u094D\u0924\u0928\u094D\u092E\u092F\u0924\u094D\u0935\u0947\u0928 \u092E\u0928\u094B\u0930\u0942\u0922\u0947\u0938\u094D\u0924\u0926\u093E\u0924\u094D\u092E\u0924\u093E\u0965</p></blockquote><p>\u0907\u0924\u094D\u092F\u093E\u0926\u093F\u0928\u094B\u092A\u093E\u092F\u092A\u094D\u0930\u0926\u0930\u094D\u0936\u0928\u0947\u0928 \u092A\u094D\u0930\u092A\u091E\u094D\u091A\u093F\u0924\u092E\u094D\u0964 \u090F\u0924\u091A\u094D\u091A</p><blockquote><p>\u0905\u0924\u093F\u0915\u094D\u0930\u0941\u0926\u094D\u0927\u0903 \u092A\u094D\u0930\u0939\u0943\u0937\u094D\u091F\u094B \u0935\u093E \u0915\u093F\u0902 \u0915\u0930\u094B\u092E\u0940\u0924\u093F \u0935\u093E \u092E\u0943\u0936\u0928\u094D\u0964<br> \u0927\u093E\u0935\u0928\u094D\u0935\u093E \u092F\u0924\u094D\u092A\u0926\u0902 \u0917\u091A\u094D\u091B\u0947\u0924\u094D\u0924\u0924\u094D\u0930 \u0938\u094D\u092A\u0928\u094D\u0926\u0903 \u092A\u094D\u0930\u0924\u093F\u0937\u094D\u0920\u093F\u0924\u0903\u0965</p></blockquote><p>\u0907\u0924\u094D\u092F\u093E\u0926\u093F\u0928\u093E</p><blockquote><p>... \u092A\u094D\u0930\u092C\u0941\u0926\u094D\u0927\u0903 \u0938\u094D\u092F\u093E\u0926\u0928\u093E\u0935\u0943\u0924\u0903\u0965</p></blockquote><p>\u0907\u0924\u094D\u092F\u0928\u094D\u0924\u0947\u0928 \u092A\u094D\u0930\u0926\u0930\u094D\u0936\u093F\u0924\u092E\u094D\u0964 \u090F\u0924\u0924\u094D\u0938\u094D\u092A\u0928\u094D\u0926\u0928\u093F\u0930\u094D\u0923\u092F\u0947 \u0928\u093F\u0930\u093E\u0915\u093E\u0919\u094D\u0915\u094D\u0937\u0902 \u092E\u092F\u0948\u0935 \u0928\u093F\u0930\u094D\u0923\u0940\u0924\u092E\u094D\u0964 \u0924\u094D\u0930\u093F\u0937\u0941 \u091A\u0924\u0941\u0930\u094D\u0925\u092E\u094D... (\u0969-\u0968\u0966) \u0907\u0924\u093F \u0938\u0942\u0924\u094D\u0930\u0947\u0923 \u091C\u093E\u0917\u0930\u093E\u0926\u094C \u0924\u0941\u0930\u094D\u092F\u093E\u0928\u0941\u092A\u094D\u0930\u093E\u0923\u0928\u092E\u0941\u0915\u094D\u0924\u092E\u094D\u0964 \u0905\u0928\u0947\u0928 \u0938\u0930\u094D\u0935\u0926\u0936\u093E\u0928\u0941\u0917\u0924\u093E\u0926\u093F\u092E\u0927\u094D\u092F\u093E\u0928\u094D\u0924\u0947\u0937\u0941 \u0938\u0943\u0937\u094D\u0924\u093F\u0938\u094D\u0925\u093F\u0924\u093F\u0938\u0902\u0939\u093E\u0930\u0928\u093F\u0930\u0942\u092A\u093F\u0924\u092F\u093E \u092D\u0919\u094D\u0917\u094D\u092F\u093E \u0928\u093F\u0930\u0942\u092A\u093F\u0924\u0947\u0937\u094D\u0935\u093F\u0924\u093F \u0935\u093F\u0936\u0947\u0937\u0903\u0965\u0969\u096E\u0965</p></div><hr><div class="trans"><p>Yata\u015Bca kara\u1E47a\u015Bakti\u015Babdokty\u0101 tury\u0101tm\u0101 sv\u0101tantrya\u015Baktireva bodhar\u016Bpasya pram\u0101tu\u1E25 s\u0101ramato m\u0101y\u0101\u015Baktyapahastitatatsvar\u016Bpottejan\u0101ya\u2014</p><blockquote><p><strong>Tripad\u0101dyanupr\u0101\u1E47anam||38||</strong></p></blockquote><p>Tray\u0101\u1E47\u0101\u1E41 bh\u0101vaunmukhyatadabhi\u1E63va\u1E45gatadantarmukh\u012Bbh\u0101van\u0101may\u0101n\u0101\u1E41 s\u1E5B\u1E63\u1E6Disthitilaya\u015Babdokt\u0101n\u0101\u1E41 pad\u0101n\u0101mavasth\u0101n\u0101\u1E41 yad\u0101di pradh\u0101na\u1E41 tricamatk\u1E5Btitven\u0101nandaghana\u1E41 tury\u0101khya\u1E41 pada\u1E41 m\u0101y\u0101\u015Bakty\u0101cch\u0101ditamapi tattadvi\u1E63ayopabhog\u0101dyavasare\u1E63u vidyudvad\u0101bh\u0101sam\u0101na\u1E41 tena tattadavasare\u1E63u k\u1E63a\u1E47am\u0101troditen\u0101pyanupr\u0101\u1E47anamantarmukhatadvimar\u015B\u0101vasthitit\u0101ratamyen\u0101nugatatay\u0101 pr\u0101\u1E47anam\u0101tmanastenaiva j\u012Bviten\u0101pi j\u012Bvitasyottejana\u1E41 kury\u0101t| Tadukta\u1E41 \u015Br\u012Bvij\xF1\u0101nabhairave</p><blockquote><p>Anta\u1E25 sv\u0101nubhav\u0101nand\u0101 vikalponmuktagocar\u0101|<br> Y\u0101vasth\u0101 bharit\u0101k\u0101r\u0101 bhairav\u012B bhairav\u0101tmana\u1E25||<br> Tadvapustattvato j\xF1eya\u1E41 vimala\u1E41 vi\u015Bvap\u016Bra\u1E47am|</p></blockquote><p>ity\u0101dyupakramya</p><blockquote><p>\u015Aaktisa\u1E45gamasa\u1E45k\u1E63ubdha\u015Bakty\u0101ve\u015B\u0101vas\u0101nikam|<br> Yatsukha\u1E41 brahmatattvasya tatsukha\u1E41 sv\u0101kyamucyate||<br> Lehan\u0101manthan\u0101ko\u1E6Dai\u1E25 str\u012Bsukhasya bhar\u0101tsm\u1E5Bte\u1E25|<br> \u015Aaktyabh\u0101ve&#39;pi deve\u015Bi bhaved\u0101nandasamplava\u1E25||<br> \u0100nande mahati pr\u0101pte d\u1E5B\u1E63\u1E6De v\u0101 b\u0101ndhave cir\u0101t|<br> \u0100nandamudgata\u1E41 dhy\u0101tv\u0101 tanmayastallay\u012Bbhavet||<br> Jagdhip\u0101nak\u1E5Btoll\u0101saras\u0101nandavij\u1E5Bmbha\u1E47\u0101t|<br> Bh\u0101vayedbharit\u0101vasth\u0101\u1E41 mah\u0101nandastato bhavet||<br> G\u012Bt\u0101divi\u1E63ay\u0101sv\u0101d\u0101samasaukhyaikat\u0101tmana\u1E25|<br> Yoginastanmayatvena manor\u016B\u1E0Dhestad\u0101tmat\u0101||</p></blockquote><p>ity\u0101dinop\u0101yapradar\u015Banena prapa\xF1citam| Etacca</p><blockquote><p>Atikruddha\u1E25 prah\u1E5B\u1E63\u1E6Do v\u0101 ki\u1E41 karom\u012Bti v\u0101 m\u1E5B\u015Ban|<br> Dh\u0101vanv\u0101 yatpada\u1E41 gacchettatra spanda\u1E25 prati\u1E63\u1E6Dhita\u1E25||</p></blockquote><p>ity\u0101din\u0101</p><blockquote><p>... prabuddha\u1E25 sy\u0101dan\u0101v\u1E5Bta\u1E25||</p></blockquote><p>ityantena pradar\u015Bitam| Etatspandanir\u1E47aye nir\u0101k\u0101\u1E45k\u1E63a\u1E41 mayaiva nir\u1E47\u012Btam| Tri\u1E63u caturtham... (3-20) iti s\u016Btre\u1E47a j\u0101gar\u0101dau tury\u0101nupr\u0101\u1E47anamuktam| Anena sarvada\u015B\u0101nugat\u0101dimadhy\u0101nte\u1E63u s\u1E5B\u1E63tisthitisa\u1E41h\u0101ranir\u016Bpitay\u0101 bha\u1E45gy\u0101 nir\u016Bpite\u1E63viti vi\u015Be\u1E63a\u1E25||38||</p></div><hr><p>\u0418 <em>(ca)</em> \u043F\u043E\u0441\u043A\u043E\u043B\u044C\u043A\u0443 <em>(yatas)</em> \u0447\u0435\u0440\u0435\u0437 \u0432\u044B\u0440\u0430\u0436\u0435\u043D\u0438\u0435 <em>(ukty\u0101)</em> \u0441\u043B\u043E\u0432\u0430 <em>(\u015Babda)</em> &quot;kara\u1E47a\u015Bakti&quot; --\u0441\u043E\u0437\u0438\u0434\u0430\u0442\u0435\u043B\u044C\u043D\u0430\u044F \u0441\u0438\u043B\u0430-- <em>(kara\u1E47a-\u015Bakti)</em>, [\u043D\u0435\u043E\u043F\u0440\u043E\u0432\u0435\u0440\u0436\u0438\u043C\u043E \u043F\u043E\u043A\u0430\u0437\u044B\u0432\u0430\u0435\u0442\u0441\u044F][\u0435\u0433\u043E] \u0421\u0438\u043B\u0430 <em>(\u015Bakti\u1E25)</em> \u0410\u0431\u0441\u043E\u043B\u044E\u0442\u043D\u043E\u0439 \u0421\u0432\u043E\u0431\u043E\u0434\u044B <em>(sv\u0101tantrya... eva)</em>, \u0447\u044C\u0435\u0439 \u043F\u0440\u0438\u0440\u043E\u0434\u043E\u0439 <em>(\u0101tm\u0101)</em> \u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F Turya --\u0427\u0435\u0442\u0432\u0435\u0440\u0442\u043E\u0435 \u0421\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u0435-- <em>(turya)</em>, [\u0431\u0443\u0434\u0443\u0447\u0438] \u0441\u0443\u0442\u044C\u044E <em>(s\u0101ram)</em> \u0432\u043E\u0441\u043F\u0440\u0438\u043D\u0438\u043C\u0430\u044E\u0449\u0435\u0433\u043E <em>(pram\u0101tu\u1E25)</em>, \u043A\u043E\u0442\u043E\u0440\u044B\u0439 \u0435\u0441\u0442\u044C \u043D\u0438\u0447\u0442\u043E \u0438\u043D\u043E\u0435 \u043A\u0430\u043A Bodha, \u0438\u043B\u0438 \u0421\u043E\u0437\u043D\u0430\u043D\u0438\u0435 <em>(bodha-r\u016Bpasya)</em>, \u043F\u043E\u044D\u0442\u043E\u043C\u0443 <em>(atas)</em>, \u0434\u043B\u044F \u0441\u0442\u0438\u043C\u0443\u043B\u044F\u0446\u0438\u0438 <em>(uttejan\u0101ya)</em> \u0441\u0443\u0449\u043D\u043E\u0441\u0442\u043D\u043E\u0439 \u043F\u0440\u0438\u0440\u043E\u0434\u044B <em>(sva-r\u016Bpa)</em> \u044D\u0442\u043E\u0439 [Turya] <em>(tad)</em>, \u043A\u043E\u0442\u043E\u0440\u0430\u044F \u0431\u044B\u043B\u0430 \u043E\u0442\u0432\u0435\u0440\u0433\u043D\u0443\u0442\u0430 <em>(apahastita)</em> m\u0101y\u0101\u015Bakti <em>(m\u0101y\u0101-\u015Bakti)</em><sup>1</sup>\u2014</p><blockquote><p>[\u0421\u043B\u0435\u0434\u0443\u0435\u0442 \u0432\u044B\u043F\u043E\u043B\u043D\u044F\u0442\u044C] \u043E\u0436\u0438\u0432\u043B\u0435\u043D\u0438\u0435 <em>(anupr\u0101\u1E47anam)</em> \u0442\u0440\u0435\u0445 \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u0439 --\u043F\u0440\u043E\u044F\u0432\u043B\u0435\u043D\u0438\u044F, \u043F\u043E\u0434\u0434\u0435\u0440\u0436\u0430\u043D\u0438\u044F \u0438 \u0440\u0430\u0441\u0442\u0432\u043E\u0440\u0435\u043D\u0438\u044F-- <em>(tri-pada)</em> \u0433\u043B\u0430\u0432\u043D\u044B\u043C <em>(\u0101di)</em>, [\u0434\u0440\u0443\u0433\u0438\u043C\u0438 \u0441\u043B\u043E\u0432\u0430\u043C\u0438, &quot;\u0447\u0435\u0442\u0432\u0435\u0440\u0442\u044B\u043C \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u0435\u043C \u0421\u043E\u0437\u043D\u0430\u043D\u0438\u044F, \u0421\u0432\u0438\u0434\u0435\u0442\u0435\u043B\u0435\u043C \u0442\u0440\u0435\u0445 \u0434\u0440\u0443\u0433\u0438\u0445, \u043F\u043E\u043B\u043D\u044B\u043C \u0442\u0440\u0430\u043D\u0441\u0446\u0435\u043D\u0434\u0435\u043D\u0442\u043D\u043E\u0433\u043E \u0411\u043B\u0430\u0436\u0435\u043D\u0441\u0442\u0432\u0430&quot;]||38||</p></blockquote><p>\u0418\u0437 \u0442\u0440\u0435\u0445 <em>(tray\u0101\u1E47\u0101m)</em> pada-s, \u0438\u043B\u0438 \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u0439 <em>(pad\u0101n\u0101m avasth\u0101n\u0101m)</em>, \u0443\u043F\u043E\u043C\u044F\u043D\u0443\u0442\u044B\u0445 <em>(ukt\u0101n\u0101m)</em> \u0441\u043B\u043E\u0432\u0430\u043C\u0438 <em>(\u015Babda)</em> \u043F\u0440\u043E\u044F\u0432\u043B\u0435\u043D\u0438\u0435 <em>(s\u1E5B\u1E63\u1E6Di)</em>, \u043F\u043E\u0434\u0434\u0435\u0440\u0436\u0430\u043D\u0438\u0435 <em>(sthiti)</em> [\u0438] \u0440\u0430\u0441\u0442\u0432\u043E\u0440\u0435\u043D\u0438\u0435 <em>(laya)</em> \u2014\u0445\u0430\u0440\u0430\u043A\u0442\u0435\u0440\u0438\u0437\u0443\u0435\u043C\u044B\u0445 <em>(may\u0101n\u0101m)</em> \u043E\u0440\u0438\u0435\u043D\u0442\u0430\u0446\u0438\u0435\u0439 <em>(aunmukhya)</em> \u043D\u0430 \u043E\u0431\u044A\u0435\u043A\u0442\u044B <em>(bh\u0101va)</em>, \u0438\u043D\u0442\u0435\u043D\u0441\u0438\u0432\u043D\u043E\u0439 \u043F\u0440\u0438\u0432\u044F\u0437\u0430\u043D\u043D\u043E\u0441\u0442\u044C\u044E <em>(abhi\u1E63va\u1E45ga)</em> \u043A \u043D\u0438\u043C <em>(tad)</em> [\u0438] \u0432\u043D\u0443\u0442\u0440\u0435\u043D\u043D\u0435\u0439 <em>(antarmukh\u012B)</em> \u0430\u0441\u0441\u0438\u043C\u0438\u043B\u044F\u0446\u0438\u0435\u0439 <em>(bh\u0101van\u0101)</em> \u044D\u0442\u0438\u0445 [\u0441\u0430\u043C\u044B\u0445 \u043E\u0431\u044A\u0435\u043A\u0442\u043E\u0432] <em>(tad)</em>, [\u0441\u043E\u043E\u0442\u0432\u0435\u0442\u0441\u0442\u0432\u0435\u043D\u043D\u043E]\u2014, \u0442\u043E, \u043A\u043E\u0442\u043E\u0440\u043E\u0435 <em>(yad)</em> [\u0435\u0441\u0442\u044C] \u0101di <em>(\u0101di)</em> [\u0438\u043B\u0438] \u0433\u043B\u0430\u0432\u043D\u043E\u0435 <em>(pradh\u0101nam)</em> [\u2014 \u044D\u0442\u043E] \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u0435 <em>(padam)</em>, \u043D\u0430\u0437\u044B\u0432\u0430\u0435\u043C\u043E\u0435 <em>(\u0101khyam)</em> \u0422\u0443\u0440\u044C\u044F (Turya) --\u0427\u0435\u0442\u0432\u0435\u0440\u0442\u043E\u0435-- <em>(turya)</em>, \u043A\u043E\u043C\u043F\u0430\u043A\u0442\u043D\u0430\u044F \u043C\u0430\u0441\u0441\u0430 <em>(ghana)</em> \u0411\u043B\u0430\u0436\u0435\u043D\u0441\u0442\u0432\u0430 <em>(\u0101nanda)</em>, \u043F\u043E\u0441\u043A\u043E\u043B\u044C\u043A\u0443 \u043E\u043D\u0430 \u043F\u0440\u043E\u043D\u0438\u0437\u044B\u0432\u0430\u0435\u0442, \u0438\u043B\u0438 \u043D\u0430\u043F\u043E\u043B\u043D\u044F\u0435\u0442 [\u0434\u0440\u0443\u0433\u0438\u0435] \u0442\u0440\u0438 --\u043F\u0440\u043E\u044F\u0432\u043B\u0435\u043D\u0438\u0435, \u043F\u043E\u0434\u0434\u0435\u0440\u0436\u0430\u043D\u0438\u0435 \u0438 \u0440\u0430\u0441\u0442\u0432\u043E\u0440\u0435\u043D\u0438\u0435-- \u0412\u044B\u0441\u0448\u0438\u043C \u041D\u0430\u0441\u043B\u0430\u0436\u0434\u0435\u043D\u0438\u0435\u043C <em>(tri-camatk\u1E5Btitvena)</em>. [Turya,] \u0445\u043E\u0442\u044F <em>(api)</em> \u0441\u043E\u043A\u0440\u044B\u0442\u0430, \u0438\u043B\u0438 \u0437\u0430\u043C\u0430\u0441\u043A\u0438\u0440\u043E\u0432\u0430\u043D\u0430 <em>(\u0101cch\u0101ditam)</em> m\u0101y\u0101\u015Bakti <em>(m\u0101y\u0101-\u015Bakti)</em>, \u0432\u043E\u0437\u043D\u0438\u043A\u0430\u0435\u0442 <em>(abh\u0101sam\u0101nam)</em> [\u043D\u0430 \u043C\u0433\u043D\u043E\u0432\u0435\u043D\u0438\u0435] \u043F\u043E\u0434\u043E\u0431\u043D\u043E <em>(vat)</em> \u043C\u043E\u043B\u043D\u0438\u0438 <em>(vidyut)</em> \u0432 \u0441\u043B\u0443\u0447\u0430\u0435 <em>(avasare\u1E63u)</em> \u043D\u0430\u0441\u043B\u0430\u0436\u0434\u0435\u043D\u0438\u044F <em>(upabhoga)</em> \u0440\u0430\u0437\u043B\u0438\u0447\u043D\u044B\u043C\u0438 <em>(tad-tad)</em> \u043E\u0431\u044A\u0435\u043A\u0442\u0430\u043C\u0438 <em>(vi\u1E63aya)</em> \u0438 \u0442.\u0434. <em>(\u0101di)</em>. \u0418\u0437-\u0437\u0430 \u044D\u0442\u043E\u0433\u043E <em>(tena)</em>, \u0432 \u0440\u0430\u0437\u043B\u0438\u0447\u043D\u044B\u0445 \u0441\u043B\u0443\u0447\u0430\u044F\u0445 <em>(tad-tad-avasare\u1E63u)</em>, [\u0432 \u043A\u043E\u0442\u043E\u0440\u044B\u0445 \u043F\u0440\u043E\u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F Turya], \u0434\u0430\u0436\u0435 \u0435\u0441\u043B\u0438 <em>(api)</em> \u044D\u0442\u043E \u0432\u043E\u0437\u043D\u0438\u043A\u043B\u043E <em>(uditena)</em> \u0442\u043E\u043B\u044C\u043A\u043E \u043D\u0430 \u043C\u0433\u043D\u043E\u0432\u0435\u043D\u0438\u0435 <em>(k\u1E63a\u1E47a-m\u0101tra)</em>, \u0441\u043B\u0435\u0434\u0443\u0435\u0442 \u0432\u044B\u043F\u043E\u043B\u043D\u044F\u0442\u044C <em>(kury\u0101t)</em> anupr\u0101\u1E47ana --\u043E\u0436\u0438\u0432\u043B\u0435\u043D\u0438\u0435-- <em>(anupr\u0101\u1E47anam)</em>, [\u0438\u043C\u0435\u043D\u0443\u0435\u043C\u043E\u0435, &quot;anugatatay\u0101 pr\u0101\u1E47ana&quot;, \u0438\u043B\u0438] \u0432\u043E\u0441\u0441\u0442\u0430\u043D\u043E\u0432\u043B\u0435\u043D\u0438\u0435 <em>(pr\u0101\u1E47anam)</em>, \u0441\u043B\u0435\u0434\u0443\u044F <em>(anugatatay\u0101)</em> \u0432 \u0440\u0430\u0437\u043D\u043E\u0439 \u0441\u0442\u0435\u043F\u0435\u043D\u0438 <em>(t\u0101ratamyena)</em> \u043D\u0435\u0438\u0437\u043C\u0435\u043D\u043D\u043E\u0441\u0442\u0438, \u0438\u043B\u0438 \u043F\u043E\u0441\u0442\u043E\u044F\u043D\u0441\u0442\u0432\u0443 <em>(avasthiti)</em> \u0432 \u043E\u0441\u043E\u0437\u043D\u0430\u043D\u0438\u0438 <em>(vimar\u015Ba)</em> \u044D\u0442\u043E\u0439 [\u043A\u043E\u043C\u043F\u0430\u043A\u0442\u043D\u043E\u0439 \u043C\u0430\u0441\u0441\u044B \u0411\u043B\u0430\u0436\u0435\u043D\u0441\u0442\u0432\u0430] <em>(tad)</em>, \u043D\u0430\u0445\u043E\u0434\u044F\u0449\u0435\u0439\u0441\u044F \u0432\u043D\u0443\u0442\u0440\u0438 <em>(antarmukha)</em>. [\u041A\u043E\u0440\u043E\u0447\u0435 \u0433\u043E\u0432\u043E\u0440\u044F, \u0441\u043B\u0435\u0434\u0443\u0435\u0442 \u0432\u044B\u043F\u043E\u043B\u043D\u044F\u0442\u044C] \u0441\u0442\u0438\u043C\u0443\u043B\u044F\u0446\u0438\u044E <em>(uttejanam)</em> [\u0442\u0430\u043A\u043E\u0439] \u0436\u0438\u0437\u043D\u0435\u043D\u043D\u043E\u0439 \u0441\u0438\u043B\u044B <em>(j\u012Bvitasya)</em> \u0447\u0435\u0440\u0435\u0437 \u043E\u0436\u0438\u0432\u043B\u0435\u043D\u0438\u0435 <em>(j\u012Bvitena api)</em> \u0441\u0435\u0431\u044F <em>(\u0101tmana\u1E25)</em> \u044D\u0442\u043E\u0439 \u0436\u0438\u0437\u043D\u0435\u0441\u043F\u043E\u0441\u043E\u0431\u043D\u043E\u0441\u0442\u044C\u044E <em>(tena eva j\u012Bvitena api)</em>|</p><p>\u0422\u043E \u0436\u0435 <em>(tad)</em> \u0431\u044B\u043B\u043E \u0441\u043A\u0430\u0437\u0430\u043D\u043E <em>(uktam)</em> \u0432 \u0443\u0432\u0430\u0436\u0430\u0435\u043C\u043E\u043C Vij\xF1\u0101nabhairava <em>(\u015Br\u012B-vij\xF1\u0101nabhairave)</em>, \u043D\u0430\u0447\u0438\u043D\u0430\u044F \u0441 <em>(upakramya)</em> --\u0441\u0435\u0439\u0447\u0430\u0441 \u041F\u0438\u0441\u0430\u043D\u0438\u0435 \u0431\u0443\u0434\u0435\u0442 \u043E\u0431\u044A\u044F\u0441\u043D\u044F\u0442\u044C Par\u0101 (\u0442\u0435\u0440\u043C\u0438\u043D, \u0436\u0435\u043D\u0441\u043A\u043E\u0433\u043E \u0440\u043E\u0434\u0430, \u043A\u043E\u0442\u043E\u0440\u044B\u0439 \u0431\u0443\u043A\u0432\u0430\u043B\u044C\u043D\u043E \u043E\u0437\u043D\u0430\u0447\u0430\u0435\u0442 &quot;\u0412\u044B\u0441\u0448\u0430\u044F&quot;, \u0442.\u0435. \u0412\u044B\u0441\u0448\u0435\u0435 \u0421\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u0435, \u0438\u043B\u0438 \u0412\u044B\u0441\u0448\u0430\u044F \u0411\u043E\u0433\u0438\u043D\u044F), \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u0435, \u0442\u0430\u043A\u0436\u0435 \u0438\u0437\u0432\u0435\u0441\u0442\u043D\u043E\u0435 \u043A\u0430\u043A Tury\u0101t\u012Bta (\u0421\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u0435 \u0437\u0430 \u043F\u0440\u0435\u0434\u0435\u043B\u0430\u043C\u0438 \u0427\u0435\u0442\u0432\u0435\u0440\u0442\u043E\u0433\u043E)--:</p><blockquote><p>&quot;[Par\u0101, \u0412\u044B\u0441\u0448\u0435\u0435 \u0421\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u0435, \u0438\u043B\u0438 \u0412\u044B\u0441\u0448\u0430\u044F \u0411\u043E\u0433\u0438\u043D\u044F \u2014 \u044D\u0442\u043E] \u0411\u043B\u0430\u0436\u0435\u043D\u0441\u0442\u0432\u043E <em>(\u0101nand\u0101)</em>, \u043A\u043E\u0442\u043E\u0440\u043E\u0435 \u043C\u043E\u0436\u043D\u043E \u0438\u0441\u043F\u044B\u0442\u0430\u0442\u044C --\u0442.\u0435. \u043D\u0430 \u0441\u043E\u0431\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u043C \u043E\u043F\u044B\u0442\u0435-- <em>(sva-anubhava)</em> \u0432\u043D\u0443\u0442\u0440\u0438 --\u0432 \u042F-\u0421\u043E\u0437\u043D\u0430\u043D\u0438\u0438-- <em>(antar)</em>, [\u0415\u0451] \u043F\u043E\u043B\u0435 \u0434\u0435\u0439\u0441\u0442\u0432\u0438\u044F <em>(gocar\u0101)</em> \u0441\u0432\u043E\u0431\u043E\u0434\u043D\u043E \u043E\u0442 <em>(unmukta)</em> \u043C\u044B\u0441\u043B\u0435\u0439 <em>(vikalpa)</em> --\u0442.\u0435. \u0447\u0435\u043B\u043E\u0432\u0435\u043A \u0434\u043E\u043B\u0436\u0435\u043D \u043E\u0441\u0432\u043E\u0431\u043E\u0434\u0438\u0442\u044C\u0441\u044F \u043E\u0442 \u043C\u044B\u0441\u043B\u0435\u0439, \u0447\u0442\u043E\u0431\u044B \u0438\u0441\u043F\u044B\u0442\u0430\u0442\u044C \u0442\u0430\u043A\u043E\u0435 \u0421\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u0435, \u0438\u043B\u0438 \u0411\u043E\u0433\u0438\u043D\u044E--, \u044D\u0442\u043E \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u0435 <em>(y\u0101 avasth\u0101)</em> \u0441\u0432\u043E\u0435\u0439 \u0441\u043E\u0431\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u0439 \u0421\u0430\u043C\u043E\u0441\u0442\u0438 <em>(\u0101tmana\u1E25)</em>, \u043A\u043E\u0442\u043E\u0440\u0430\u044F \u0435\u0441\u0442\u044C Bhairava --\u015Aiva, \u0438\u043B\u0438 \u0413\u043E\u0441\u043F\u043E\u0434\u044C-- <em>(bhairava)</em>, [\u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F] Bhairav\u012B --\u015Aakti, \u0438\u043B\u0438 \u0431\u043E\u0436\u0435\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u0439 \u0421\u0438\u043B\u043E\u0439 Bhairava-- <em>(bhairav\u012B)</em>, \u0447\u044C\u044F \u0444\u043E\u0440\u043C\u0430 <em>(\u0101k\u0101r\u0101)</em> \u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F \u043F\u043E\u043B\u043D\u043E\u0439 <em>(bharita)</em> --\u0442.\u0435. \u041E\u043D\u0430 \u043D\u0430\u043F\u043E\u043B\u043D\u0435\u043D\u0430 \u0412\u044B\u0441\u0448\u0438\u043C \u041D\u0430\u0441\u043B\u0430\u0436\u0434\u0435\u043D\u0438\u0435\u043C, \u043F\u043E\u043B\u0443\u0447\u0435\u043D\u043D\u044B\u043C \u043E\u0442 \u043E\u043F\u044B\u0442\u0430 \u0435\u0434\u0438\u043D\u0441\u0442\u0432\u0430 \u0441\u043E \u0432\u0441\u0435\u043B\u0435\u043D\u043D\u043E\u0439--.</p></blockquote><blockquote><p>\u042D\u0442\u043E [\u0412\u044B\u0441\u0448\u0435\u0435 \u0421\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u0435, \u0438\u043B\u0438 \u0411\u043E\u0433\u0438\u043D\u044F] <em>(tad)</em> \u0434\u043E\u043B\u0436\u043D\u043E \u0431\u044B\u0442\u044C \u0432 \u0434\u0435\u0439\u0441\u0442\u0432\u0438\u0442\u0435\u043B\u044C\u043D\u043E\u0441\u0442\u0438 \u0438\u0437\u0432\u0435\u0441\u0442\u043D\u043E \u043A\u0430\u043A <em>(tattvatas j\xF1eyam)</em> \u0447\u0438\u0441\u0442\u0430\u044F <em>(vimalam)</em> \u0444\u043E\u0440\u043C\u0430 --\u0441\u0443\u0449\u043D\u043E\u0441\u0442\u043D\u0430\u044F \u043F\u0440\u0438\u0440\u043E\u0434\u0430-- <em>(vapus)</em>, \u043A\u043E\u0442\u043E\u0440\u0430\u044F \u043D\u0430\u043F\u043E\u043B\u043D\u044F\u0435\u0442 <em>(p\u016Bra\u1E47am)</em> \u0432\u0441\u0435\u043B\u0435\u043D\u043D\u0443\u044E <em>(vi\u015Bva)</em>\u2014 \u0438 \u0442.\u0434. <em>(iti \u0101di)</em>&quot;||</p></blockquote><p>[\u0418 \u0432\u043F\u043E\u0441\u043B\u0435\u0434\u0441\u0442\u0432\u0438\u0438 \u044D\u0442\u043E\u0442 \u043F\u0440\u0435\u0434\u043C\u0435\u0442] \u0440\u0430\u0441\u0441\u043C\u0430\u0442\u0440\u0438\u0432\u0430\u0435\u0442\u0441\u044F \u043F\u043E\u0434\u0440\u043E\u0431\u043D\u043E [\u0432 Vij\xF1\u0101nabhairava] <em>(prapa\xF1citam)</em> \u043F\u043E\u0441\u0440\u0435\u0434\u0441\u0442\u0432\u043E\u043C [\u0441\u0435\u0440\u0438\u0438 \u0441\u0442\u0440\u043E\u0444], \u043F\u043E\u043A\u0430\u0437\u044B\u0432\u0430\u044E\u0449\u0438\u0445 <em>(pradar\u015Banena)</em> \u0441\u043F\u043E\u0441\u043E\u0431\u044B [\u043F\u0440\u0438\u0431\u043B\u0438\u0436\u0435\u043D\u0438\u044F \u043A \u044D\u0442\u043E\u043C\u0443 \u0412\u044B\u0441\u0448\u0435\u043C\u0443 \u0421\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u044E, \u0438\u043B\u0438 \u0411\u043E\u0433\u0438\u043D\u0435] <em>(up\u0101ya)</em>:</p><blockquote><p>&quot;\u042D\u0442\u043E \u043D\u0430\u0441\u043B\u0430\u0436\u0434\u0435\u043D\u0438\u0435, \u043A\u043E\u0442\u043E\u0440\u043E\u0435 <em>(yad sukham)</em> [\u0438\u043C\u0435\u0435\u0442 \u043C\u0435\u0441\u0442\u043E] \u0432 \u043A\u043E\u043D\u0446\u0435 <em>(\u0101vas\u0101nikam)</em> \u043F\u043E\u0433\u0440\u0443\u0436\u0435\u043D\u0438\u044F <em>(\u0101ve\u015Ba)</em> \u0432 \u0421\u0438\u043B\u0443 \u0411\u043B\u0430\u0436\u0435\u043D\u0441\u0442\u0432\u0430 <em>(\u015Bakti)</em>, \u043A\u043E\u0442\u043E\u0440\u043E\u0435 --\u0442.\u0435. \u043F\u043E\u0433\u0440\u0443\u0436\u0435\u043D\u0438\u0435-- \u0432\u044B\u0437\u044B\u0432\u0430\u0435\u0442\u0441\u044F <em>(sa\u1E45k\u1E63ubdha)</em> \u0447\u0435\u0440\u0435\u0437 \u043F\u043E\u043B\u043E\u0432\u043E\u0439 \u0430\u043A\u0442 <em>(sa\u1E45gama)</em> \u0441 \u0436\u0435\u043D\u0449\u0438\u043D\u043E\u0439 <em>(\u015Bakti)</em> --\u043A\u0440\u0430\u0442\u043A\u043E, &#39;\u044D\u0442\u043E \u043D\u0430\u0441\u043B\u0430\u0436\u0434\u0435\u043D\u0438\u0435, \u0441\u043B\u0443\u0447\u0430\u044E\u0449\u0435\u0435\u0441\u044F \u0432\u043E \u0432\u0440\u0435\u043C\u044F \u043E\u0440\u0433\u0430\u0437\u043C\u0430&#39;--, \u044D\u0442\u043E, \u043A\u0430\u043A \u0441\u0447\u0438\u0442\u0430\u0435\u0442\u0441\u044F <em>(ucyate)</em> \u2014 \u043D\u0430\u0441\u043B\u0430\u0436\u0434\u0435\u043D\u0438\u0435 <em>(tad sukham)</em> \u0412\u044B\u0441\u0448\u0435\u0433\u043E \u0411\u0440\u0430\u0445\u043C\u044B --\u0410\u0431\u0441\u043E\u043B\u044E\u0442\u0430-- <em>(brahmatattvasya)</em>, \u0442.\u0435. [\u044D\u0442\u043E \u043D\u0430\u0441\u043B\u0430\u0436\u0434\u0435\u043D\u0438\u0435], \u0441\u0432\u044F\u0437\u0430\u043D\u043D\u043E\u0435 \u0441\u043E \u0441\u0432\u043E\u0435\u0439 \u0441\u043E\u0431\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u0439 \u0421\u0430\u043C\u043E\u0441\u0442\u044C\u044E <em>(sv\u0101kyam)</em><sup>2</sup>.</p></blockquote><blockquote><p>\u041E \u0411\u043E\u0433\u0438\u043D\u044F <em>(deva-\u012B\u015Bi)</em>!, \u0434\u0430\u0436\u0435 <em>(api)</em> \u043F\u0440\u0438 \u043E\u0442\u0441\u0443\u0442\u0441\u0442\u0432\u0438\u0438 <em>(abh\u0101ve)</em> \u0436\u0435\u043D\u0449\u0438\u043D\u044B <em>(\u015Bakti)</em> \u043F\u0440\u043E\u0438\u0441\u0445\u043E\u0434\u0438\u0442 <em>(bhavet)</em> \u0438\u0437\u043E\u0431\u0438\u043B\u0438\u0435, \u0438\u043B\u0438 \u043F\u043E\u0442\u043E\u043A <em>(samplava\u1E25)</em> \u0431\u043B\u0430\u0436\u0435\u043D\u0441\u0442\u0432\u0430 <em>(\u0101nanda)</em> \u043E\u0442 \u0432\u043E\u0441\u043F\u043E\u043C\u0438\u043D\u0430\u043D\u0438\u044F <em>(sm\u1E5Bte\u1E25)</em>, \u0432 \u043F\u043E\u043B\u043D\u043E\u0439 \u043C\u0435\u0440\u0435 <em>(bhar\u0101t)</em>, \u043E \u043D\u0430\u0441\u043B\u0430\u0436\u0434\u0435\u043D\u0438\u0438 <em>(sukhasya)</em>, \u0438\u0441\u043F\u044B\u0442\u044B\u0432\u0430\u0435\u043C\u043E\u043C \u0441 \u0436\u0435\u043D\u0449\u0438\u043D\u043E\u0439 <em>(str\u012B)</em> \u0432 \u0444\u043E\u0440\u043C\u0435 \u043A\u0440\u0435\u043F\u043A\u0438\u0445 \u043F\u043E\u0446\u0435\u043B\u0443\u0435\u0432, \u043E\u0431\u044A\u044F\u0442\u0438\u0439 \u0438 \u043F\u0440\u0438\u0436\u0438\u043C\u0430\u043D\u0438\u0439 <em>(lehana-\u0101manthana-\u0101ko\u1E6Dai\u1E25)</em><sup>3</sup>.</p></blockquote><blockquote><p>\u041A\u043E\u0433\u0434\u0430 \u043F\u0440\u0438\u0445\u043E\u0434\u0438\u0442 \u0432\u0435\u043B\u0438\u043A\u0430\u044F \u0440\u0430\u0434\u043E\u0441\u0442\u044C <em>(\u0101nande mahati pr\u0101pte)</em>, \u0438\u043B\u0438 <em>(v\u0101)</em> \u043A\u043E\u0433\u0434\u0430 \u0432\u0438\u0434\u0438\u0442\u0435 \u0440\u043E\u0434\u0441\u0442\u0432\u0435\u043D\u043D\u0438\u043A\u0430, \u0434\u0440\u0443\u0433\u0430 \u0438 \u0442.\u043F. <em>(d\u1E5B\u1E63\u1E6De... b\u0101ndhave)</em> \u043F\u043E\u0441\u043B\u0435 \u0434\u043E\u043B\u0433\u043E\u0439 \u0440\u0430\u0437\u043B\u0443\u043A\u0438 <em>(cir\u0101t)</em>, (\u0438\u043B\u0438) \u043F\u043E\u0441\u043B\u0435 \u0441\u043E\u0437\u0435\u0440\u0446\u0430\u043D\u0438\u044F <em>(dhy\u0101tv\u0101)</em> \u0440\u0430\u0434\u043E\u0441\u0442\u0438 <em>(\u0101nandam)</em>, \u043A\u043E\u0442\u043E\u0440\u0430\u044F \u0432\u043E\u0437\u043D\u0438\u043A\u043B\u0430 <em>(udgatam)</em>, \u0432\u044B \u0441\u0442\u0430\u043D\u043E\u0432\u0438\u0442\u0435\u0441\u044C \u0442\u043E\u0436\u0434\u0435\u0441\u0442\u0432\u0435\u043D\u043D\u044B\u043C <em>(maya\u1E25)</em> \u0441 \u043D\u0435\u0439 --\u0441 \u044D\u0442\u043E\u0439 \u0440\u0430\u0434\u043E\u0441\u0442\u044C\u044E-- <em>(tad)</em> [\u0438] \u0440\u0430\u0441\u0442\u0432\u043E\u0440\u044F\u0435\u0442\u0435\u0441\u044C <em>(lay\u012Bbhavet)</em> \u0432 \u043D\u0435\u0439 <em>(tad)</em><sup>4</sup>.</p></blockquote><blockquote><p>\u041F\u0440\u0438 \u0440\u0430\u0441\u043F\u0440\u043E\u0441\u0442\u0440\u0430\u043D\u0435\u043D\u0438\u0438 <em>(vij\u1E5Bmbha\u1E47\u0101t)</em> \u0443\u0434\u043E\u0432\u043E\u043B\u044C\u0441\u0442\u0432\u0438\u044F <em>(\u0101nanda)</em>, \u043E\u0442\u043D\u043E\u0441\u044F\u0449\u0435\u0433\u043E\u0441\u044F \u043A\u043E \u0432\u043A\u0443\u0441\u0443, \u0438\u043B\u0438 \u0430\u0440\u043E\u043C\u0430\u0442\u0443 <em>(rasa)</em>, \u0432\u043E\u0437\u043D\u0438\u043A\u0430\u044E\u0449\u0435\u0433\u043E <em>(ull\u0101sa)</em> \u043F\u0440\u0438 \u0443\u043F\u043E\u0442\u0440\u0435\u0431\u043B\u0435\u043D\u0438\u0438 <em>(k\u1E5Bta)</em> \u0435\u0434\u044B <em>(jagdhi)</em> [\u0438] \u043F\u0438\u0442\u044C\u044F <em>(p\u0101na)</em>, \u0441\u043B\u0435\u0434\u0443\u0435\u0442 \u0441\u043A\u043E\u043D\u0446\u0435\u043D\u0442\u0440\u0438\u0440\u043E\u0432\u0430\u0442\u044C\u0441\u044F --\u0432 \u0441\u043C\u044B\u0441\u043B\u0435 \u0444\u0438\u043A\u0441\u0430\u0446\u0438\u0438 \u0441\u0432\u043E\u0435\u0433\u043E \u0432\u043D\u0438\u043C\u0430\u043D\u0438\u044F-- <em>(bh\u0101vayet)</em> \u043D\u0430 \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u0438 <em>(avasth\u0101)</em> \u043F\u043E\u043B\u043D\u043E\u0442\u044B [\u044D\u0442\u043E\u0433\u043E \u0443\u0434\u043E\u0432\u043E\u043B\u044C\u0441\u0442\u0432\u0438\u044F] <em>(bharita)</em>; [\u0438] \u0442\u043E\u0433\u0434\u0430 <em>(tatas)</em> \u043F\u043E\u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F <em>(bhavet)</em> \u0432\u0435\u043B\u0438\u043A\u043E\u0435 <em>(mah\u0101)</em> \u0431\u043B\u0430\u0436\u0435\u043D\u0441\u0442\u0432\u043E <em>(\u0101nanda\u1E25)</em> <sup>5</sup>.</p></blockquote><blockquote><p>\u0412 \u0441\u043B\u0443\u0447\u0430\u0435 Yog\u012B <em>(yogina\u1E25)</em>, \u043A\u043E\u0442\u043E\u0440\u044B\u0439 \u043F\u0440\u0435\u0431\u044B\u0432\u0430\u0435\u0442 <em>(\u0101tmana\u1E25)</em> \u0432 \u0435\u0434\u0438\u043D\u0441\u0442\u0432\u0435 <em>(ekat\u0101)</em> \u0441 \u043D\u0435\u0441\u0440\u0430\u0432\u043D\u0438\u043C\u044B\u043C <em>(asama)</em> \u0432\u043E\u0441\u0442\u043E\u0440\u0433\u043E\u043C <em>(saukhya)</em>, [\u043F\u043E\u0440\u043E\u0436\u0434\u0435\u043D\u043D\u044B\u043C] \u043D\u0430\u0441\u043B\u0430\u0436\u0434\u0435\u043D\u0438\u0435\u043C <em>(\u0101sv\u0101da)</em> \u043E\u0431\u044A\u0435\u043A\u0442\u0430\u043C\u0438 <em>(vi\u1E63aya)</em>, [\u0442\u0430\u043A\u0438\u043C\u0438 \u043A\u0430\u043A] \u043F\u0435\u043D\u0438\u0435 <em>(g\u012Bt\u0101)</em>, \u0438 \u0442.\u043F. <em>(\u0101di)</em>, \u0438\u0437-\u0437\u0430 \u0432\u043E\u0437\u0432\u044B\u0448\u0435\u043D\u0438\u044F <em>(r\u016B\u1E0Dhe\u1E25)</em> [\u0435\u0433\u043E] \u0443\u043C\u0430 <em>(manas)</em> [\u043F\u0440\u043E\u0438\u0441\u0445\u043E\u0434\u0438\u0442] \u043E\u0442\u043E\u0436\u0434\u0435\u0441\u0442\u0432\u043B\u0435\u043D\u0438\u0435 <em>(mayatvena)</em> \u0441 \u043D\u0438\u043C --\u0441 \u043D\u0435\u0441\u0440\u0430\u0432\u043D\u0438\u043C\u044B\u043C \u0432\u043E\u0441\u0442\u043E\u0440\u0433\u043E\u043C-- <em>(tad)</em>, [\u0438 \u0438\u0437-\u0437\u0430 \u044D\u0442\u043E\u0433\u043E,][\u0432\u043E\u0437\u043D\u0438\u043A\u0430\u0435\u0442] \u043E\u0442\u043E\u0436\u0434\u0435\u0441\u0442\u0432\u043B\u0435\u043D\u0438\u0435 \u0441 \u0422\u0435\u043C --\u0441 \u0412\u044B\u0441\u0448\u0438\u043C \u0411\u0440\u0430\u0445\u043C\u043E\u0439, \u0410\u0431\u0441\u043E\u043B\u044E\u0442\u043E\u043C-- <em>(tad-\u0101tmat\u0101)</em> <sup>6</sup>\u2014 \u0438 \u0442.\u0434. <em>(iti \u0101din\u0101)</em>&quot;||</p></blockquote><p>\u042D\u0442\u0430 \u0436\u0435 [\u0441\u0430\u043C\u0430\u044F \u0438\u0441\u0442\u0438\u043D\u0430] <em>(etad ca)</em> \u0431\u044B\u043B\u0430 \u043F\u043E\u043A\u0430\u0437\u0430\u043D\u0430 [\u0432 Spandak\u0101rik\u0101-s] <em>(pradar\u015Bitam)</em>, \u043D\u0430\u0447\u0438\u043D\u0430\u044F \u0441 <em>(\u0101din\u0101)</em>:</p><blockquote><p>&quot;Spanda <em>(spanda\u1E25)</em> \u043F\u0440\u043E\u0447\u043D\u043E \u0437\u0430\u043A\u043B\u044E\u0447\u0435\u043D\u0430 <em>(prati\u1E63\u1E6Dhita\u1E25)</em> \u0432 \u044D\u0442\u043E\u043C <em>(tatra)</em> \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u0438 <em>(padam)</em>, \u0432 \u043A\u043E\u0442\u043E\u0440\u043E\u0435 <em>(yad)</em> [\u0447\u0435\u043B\u043E\u0432\u0435\u043A] \u0432\u0445\u043E\u0434\u0438\u0442 <em>(gacchet)</em>, [\u043A\u043E\u0433\u0434\u0430 \u043E\u043D] \u0447\u0440\u0435\u0437\u0432\u044B\u0447\u0430\u0439\u043D\u043E \u0440\u0430\u0437\u0433\u043D\u0435\u0432\u0430\u043D <em>(atikruddha\u1E25)</em>, \u043D\u0435\u0432\u0435\u0440\u043E\u044F\u0442\u043D\u043E \u0434\u043E\u0432\u043E\u043B\u0435\u043D, \u0438\u043B\u0438 \u0432\u043E\u0441\u0445\u0438\u0449\u0435\u043D <em>(prah\u1E5B\u1E63\u1E6Da\u1E25)</em>, \u0440\u0430\u0437\u043C\u044B\u0448\u043B\u044F\u0435\u0442 <em>(m\u1E5B\u015Ban)</em> &quot;\u0447\u0442\u043E <em>(kim)</em> \u044F \u0434\u0435\u043B\u0430\u044E <em>(karomi iti)</em>?&quot;, \u0438\u043B\u0438 <em>(v\u0101.. v\u0101... v\u0101)</em> \u0443\u0431\u0435\u0433\u0430\u0435\u0442 [\u0440\u0430\u0434\u0438 \u0441\u043F\u0430\u0441\u0435\u043D\u0438\u044F \u0441\u0432\u043E\u0435\u0439 \u0436\u0438\u0437\u043D\u0438] <em>(dh\u0101van... iti)</em>&quot;||<br> [\u0421\u043C. Spandak\u0101rik\u0101-s I, 22]</p></blockquote><p>\u0438 \u0437\u0430\u043A\u0430\u043D\u0447\u0438\u0432\u0430\u044F \u0441 <em>(antena)</em>:</p><blockquote><p>&quot;... [\u041E\u0434\u043D\u0430\u043A\u043E Yog\u012B, \u043A\u043E\u0442\u043E\u0440\u044B\u0439] \u043D\u0435 \u043E\u0445\u0432\u0430\u0447\u0435\u043D [\u0442\u044C\u043C\u043E\u0439 \u043D\u0435\u0432\u0435\u0434\u0435\u043D\u0438\u044F] <em>(an\u0101v\u1E5Bta\u1E25)</em>, \u043E\u0441\u0442\u0430\u0435\u0442\u0441\u044F <em>(sy\u0101t)</em> \u043F\u0440\u043E\u0431\u0443\u0436\u0434\u0435\u043D\u043D\u044B\u043C \u0438 \u043F\u0440\u043E\u0441\u0432\u0435\u0442\u043B\u0435\u043D\u043D\u044B\u043C <em>(prabuddha\u1E25... iti)</em> [\u0432 \u044D\u0442\u0438\u0445 \u0441\u0430\u043C\u044B\u0445 \u0443\u0441\u043B\u043E\u0432\u0438\u044F\u0445]&quot;||<br> [\u0421\u043C. Spandak\u0101rik\u0101-s I, 25 - \u043F\u043E\u0441\u043B\u0435\u0434\u043D\u044F\u044F \u0447\u0430\u0441\u0442\u044C]</p></blockquote><p>\u042D\u0442\u043E\u0442 [\u043F\u0440\u0435\u0434\u043C\u0435\u0442] <em>(etad)</em> \u0431\u044B\u043B \u0438\u0441\u0441\u043B\u0435\u0434\u043E\u0432\u0430\u043D <em>(nir\u1E47\u012Btam)</em> \u043C\u043D\u043E\u044E <em>(may\u0101 eva)</em> \u0432 Spandanir\u1E47aya <em>(spandanir\u1E47aye)</em> \u0431\u0435\u0437 \u043D\u0435\u043E\u0431\u0445\u043E\u0434\u0438\u043C\u043E\u0441\u0442\u0438 \u0434\u043E\u0431\u0430\u0432\u043B\u044F\u0442\u044C \u0442\u0443\u0434\u0430 [\u0435\u0449\u0451] \u0445\u043E\u0442\u044C \u043E\u0434\u043D\u043E \u0441\u043B\u043E\u0432\u043E \u0434\u043B\u044F \u0437\u0430\u0432\u0435\u0440\u0448\u0435\u043D\u0438\u044F [\u0442\u0430\u043A\u043E\u0433\u043E \u0438\u0441\u0441\u043B\u0435\u0434\u043E\u0432\u0430\u043D\u0438\u044F] <em>(nis-\u0101k\u0101\u1E45k\u1E63am)</em> --\u0432 \u0442\u043E\u043C \u0441\u043C\u044B\u0441\u043B\u0435, \u0447\u0442\u043E \u043F\u0440\u0435\u0434\u043C\u0435\u0442 \u0431\u044B\u043B &quot;\u0442\u0449\u0430\u0442\u0435\u043B\u044C\u043D\u043E&quot; \u0438\u0441\u0441\u043B\u0435\u0434\u043E\u0432\u0430\u043D \u0442\u0430\u043C, \u0432 Spandanir\u1E47aya, \u0435\u0433\u043E \u043D\u0430\u0443\u0447\u043D\u043E\u043C \u043A\u043E\u043C\u043C\u0435\u043D\u0442\u0430\u0440\u0438\u0438 \u043D\u0430 Spandak\u0101rik\u0101-s--|</p><p>\u041F\u043E\u0441\u0440\u0435\u0434\u0441\u0442\u0432\u043E\u043C \u0430\u0444\u043E\u0440\u0438\u0437\u043C\u0430 <em>(s\u016Btre\u1E47a)</em> &quot;\u0427\u0435\u0442\u0432\u0435\u0440\u0442\u043E\u0435 \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u0435 \u0441\u043E\u0437\u043D\u0430\u043D\u0438\u044F, [\u043A\u043E\u0442\u043E\u0440\u043E\u0435 \u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F \u0421\u0432\u0438\u0434\u0435\u0442\u0435\u043B\u0435\u043C] <em>(caturtham)</em>, [\u0441\u043B\u0435\u0434\u0443\u0435\u0442 \u0432\u043B\u0438\u0432\u0430\u0442\u044C \u043F\u043E\u0434\u043E\u0431\u043D\u043E [\u043D\u0435\u043F\u0440\u0435\u0440\u044B\u0432\u043D\u043E\u043C\u0443 \u043F\u043E\u0442\u043E\u043A\u0443] \u043C\u0430\u0441\u043B\u0430] \u0432 [\u0434\u0440\u0443\u0433\u0438\u0435] \u0442\u0440\u0438 <em>(tri\u1E63u)</em>, [\u0442\u043E \u0435\u0441\u0442\u044C, \u0432 \u0431\u043E\u0434\u0440\u0441\u0442\u0432\u043E\u0432\u0430\u043D\u0438\u0435, \u0441\u043E\u043D \u0441\u043E \u0441\u043D\u043E\u0432\u0438\u0434\u0435\u043D\u0438\u044F\u043C\u0438 \u0438 \u0433\u043B\u0443\u0431\u043E\u043A\u0438\u0439 \u0441\u043E\u043D]. (III, 20) [\u0432 \u044D\u0442\u043E\u043C \u041F\u0438\u0441\u0430\u043D\u0438\u0438] <em>(3-20 iti)</em>&quot; --\u043E\u0441\u0442\u0430\u043B\u044C\u043D\u0430\u044F \u0447\u0430\u0441\u0442\u044C \u0446\u0438\u0442\u0438\u0440\u0443\u0435\u043C\u043E\u0433\u043E \u0430\u0444\u043E\u0440\u0438\u0437\u043C\u0430 \u0431\u044B\u043B\u0430 \u0434\u043E\u0431\u0430\u0432\u043B\u0435\u043D\u0430 \u0432 \u0441\u043A\u043E\u0431\u043A\u0438--, \u0431\u044B\u043B\u043E \u0443\u043F\u043E\u043C\u044F\u043D\u0443\u0442\u043E <em>(uktam)</em> \u043E\u0436\u0438\u0432\u043B\u0435\u043D\u0438\u0435 <em>(anupr\u0101\u1E47anam)</em> \u043F\u043E\u0441\u0440\u0435\u0434\u0441\u0442\u0432\u043E\u043C Turya --\u0427\u0435\u0442\u0432\u0435\u0440\u0442\u043E\u0433\u043E \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u044F-- <em>(turya)</em> \u0432 \u043E\u0442\u043D\u043E\u0448\u0435\u043D\u0438\u0438 \u0431\u043E\u0434\u0440\u0441\u0442\u0432\u043E\u0432\u0430\u043D\u0438\u044F \u0438 \u0442.\u0434. <em>(j\u0101gar\u0101-\u0101dau)</em> --\u0442.\u0435. \u0431\u043E\u0434\u0440\u0441\u0442\u0432\u043E\u0432\u0430\u043D\u0438\u044F, \u0441\u043D\u0430 \u0441\u043E \u0441\u043D\u043E\u0432\u0438\u0434\u0435\u043D\u0438\u044F\u043C\u0438 \u0438 \u0433\u043B\u0443\u0431\u043E\u043A\u043E\u0433\u043E \u0441\u043D\u0430-- |</p><p>\u0412 \u044D\u0442\u043E\u043C \u0430\u0444\u043E\u0440\u0438\u0437\u043C\u0435 --\u043A\u043E\u0442\u043E\u0440\u044B\u0439 \u0441\u0435\u0439\u0447\u0430\u0441 \u0438\u0437\u0443\u0447\u0430\u0435\u0442\u0441\u044F-- <em>(anena)</em>, [\u043E\u0436\u0438\u0432\u043B\u0435\u043D\u0438\u0435 \u043F\u043E\u0441\u0440\u0435\u0434\u0441\u0442\u0432\u043E\u043C Turya \u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F] \u0441\u0441\u044B\u043B\u043A\u043E\u0439 \u043D\u0430 \u043D\u0430\u0447\u0430\u043B\u044C\u043D\u044B\u0435, \u043F\u0440\u043E\u043C\u0435\u0436\u0443\u0442\u043E\u0447\u043D\u044B\u0435 \u0438 \u043A\u043E\u043D\u0435\u0447\u043D\u044B\u0435 \u0442\u043E\u0447\u043A\u0438 <em>(\u0101di-madhya-ante\u1E63u)</em>, \u043F\u0440\u0438\u0441\u0443\u0442\u0441\u0442\u0432\u0443\u044E\u0449\u0438\u0435 <em>(anugata)</em> \u0432\u043E \u0432\u0441\u0435\u0445 <em>(sarva)</em> \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u044F\u0445 <em>(da\u015B\u0101)</em> --\u043F\u0440\u0438 \u0431\u043E\u0434\u0440\u0441\u0442\u0432\u043E\u0432\u0430\u043D\u0438\u0438, \u0441\u043D\u0435 \u0438 \u0433\u043B\u0443\u0431\u043E\u043A\u043E\u043C \u0441\u043D\u0435--, [\u043D\u043E] \u043E\u043F\u0440\u0435\u0434\u0435\u043B\u044F\u044E\u0449\u0438\u0435\u0441\u044F \u0438 \u0443\u0434\u043E\u0441\u0442\u043E\u0432\u0435\u0440\u044F\u044E\u0449\u0438\u0435\u0441\u044F <em>(nir\u016Bpite\u1E63u)</em> \u043A\u043E\u0441\u0432\u0435\u043D\u043D\u043E, \u043A\u0430\u043A <em>(nir\u016Bpitay\u0101 bha\u1E45gy\u0101)</em> \u043F\u0440\u043E\u044F\u0432\u043B\u0435\u043D\u0438\u0435 <em>(s\u1E5B\u1E63ti)</em>, \u043F\u043E\u0434\u0434\u0435\u0440\u0436\u0430\u043D\u0438\u0435 <em>(sthiti)</em> [\u0438] \u0440\u0430\u0441\u0442\u0432\u043E\u0440\u0435\u043D\u0438\u0435 <em>(sa\u1E41h\u0101ra)</em>. \u0422\u0430\u043A\u043E\u0432\u043E \u0440\u0430\u0437\u043B\u0438\u0447\u0438\u0435 <em>(iti vi\u015Be\u1E63a\u1E25)</em>||38||</p><hr><ol><li><p>\u0421\u043B\u043E\u0432\u043E &quot;m\u0101y\u0101\u015Bakti&quot; \u043D\u0435 \u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F \u0441\u0438\u043D\u043E\u043D\u0438\u043C\u043E\u043C &quot;m\u0101y\u0101tattva&quot; (\u0445\u043E\u0440\u043E\u0448\u043E \u0438\u0437\u0432\u0435\u0441\u0442\u043D\u043E\u0439 6<sup> \u043E\u0439 </sup> \u043A\u0430\u0442\u0435\u0433\u043E\u0440\u0438\u0438 \u0432 \u043F\u0440\u043E\u0446\u0435\u0441\u0441\u0435 \u0443\u043D\u0438\u0432\u0435\u0440\u0441\u0430\u043B\u044C\u043D\u043E\u0433\u043E \u043F\u0440\u043E\u044F\u0432\u043B\u0435\u043D\u0438\u044F), \u043F\u043E\u0441\u043A\u043E\u043B\u044C\u043A\u0443 \u043F\u0435\u0440\u0432\u0430\u044F \u2014 \u044D\u0442\u043E &quot;\u0441\u0438\u043B\u0430&quot;, \u0430 \u0432\u0442\u043E\u0440\u0430\u044F \u2014 &quot;\u043F\u0440\u043E\u044F\u0432\u043B\u0435\u043D\u0438\u0435&quot;. \u041F\u043E\u044D\u0442\u043E\u043C\u0443, m\u0101y\u0101\u015Bakti \u0435\u0441\u0442\u044C \u0441\u0438\u043B\u0430, \u043F\u043E\u0441\u0440\u0435\u0434\u0441\u0442\u0432\u043E\u043C \u043A\u043E\u0442\u043E\u0440\u043E\u0439 \u0413\u043E\u0441\u043F\u043E\u0434\u044C \u0441\u043F\u043E\u0441\u043E\u0431\u0435\u043D \u043F\u0440\u043E\u0440\u043E\u0436\u0434\u0430\u0442\u044C \u0440\u0430\u0437\u043B\u0438\u0447\u0438\u0435, \u0438\u043B\u0438 \u0434\u0432\u043E\u0439\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u0441\u0442\u044C. \u041E\u043D \u0438\u0441\u043F\u043E\u043B\u044C\u0437\u0443\u0435\u0442 \u0421\u0432\u043E\u044E \u0441\u043E\u0431\u0441\u0442\u0432\u0435\u043D\u043D\u0443\u044E m\u0101y\u0101\u015Bakti, \u0447\u0442\u043E\u0431\u044B \u0441\u043A\u0440\u044B\u0442\u044C \u0415\u0433\u043E \u0441\u0443\u0449\u043D\u043E\u0441\u0442\u043D\u0443\u044E \u043F\u0440\u0438\u0440\u043E\u0434\u0443 \u043E\u0442 \u0421\u0430\u043C\u043E\u0433\u043E \u0421\u0435\u0431\u044F. \u041A\u0430\u043A\u043E\u0439 \u043F\u0430\u0440\u0430\u0434\u043E\u043A\u0441! \u041A\u043E\u043D\u0435\u0447\u043D\u043E, \u044D\u0442\u043E \u0432\u0441\u0435 \u043F\u0440\u043E \u0442\u0435\u0431\u044F, \u0447\u0438\u0442\u0430\u0442\u0435\u043B\u044C! \u042D\u0442\u043E \u043F\u0440\u043E\u0438\u0441\u0445\u043E\u0434\u0438\u0442 \u043F\u0440\u044F\u043C\u043E \u0441\u0435\u0439\u0447\u0430\u0441 (\u0430 \u043D\u0435 \u0432 \u0434\u0430\u043B\u0435\u043A\u043E\u0439 \u0433\u0430\u043B\u0430\u043A\u0442\u0438\u043A\u0435!)... \u043F\u043E\u0441\u043C\u043E\u0442\u0440\u0438, \u043A\u0430\u043A \u0442\u0432\u043E\u044F \u0441\u043E\u0431\u0441\u0442\u0432\u0435\u043D\u043D\u0430\u044F m\u0101y\u0101\u015Bakti \u0441\u043A\u0440\u044B\u0432\u0430\u0435\u0442 \u0442\u0432\u043E\u0451 \u0438\u0441\u0442\u0438\u043D\u043D\u043E\u0435 &quot;\u042F&quot; \u0438 \u0437\u0430\u043C\u0435\u043D\u044F\u0435\u0442 \u0435\u0433\u043E \u0442\u0435\u043C, \u0447\u0442\u043E \u0438\u0437\u0432\u0435\u0441\u0442\u043D\u043E \u043A\u0430\u043A \u044D\u0433\u043E, \u0438\u043B\u0438 \u043B\u043E\u0436\u043D\u043E\u0435 &quot;\u042F&quot;. \u0422\u044B \u2014 \u044D\u0442\u043E \u043D\u0435 \u0442\u043E\u043D\u043A\u043E\u0435 \u0442\u0435\u043B\u043E, \u0441\u043E\u0441\u0442\u043E\u044F\u0449\u0435\u0435 \u0438\u0437 \u0438\u043D\u0442\u0435\u043B\u043B\u0435\u043A\u0442\u0430, \u044D\u0433\u043E, \u0443\u043C\u0430 \u0438 \u0442\u043E\u043D\u043A\u0438\u0445 \u044D\u043B\u0435\u043C\u0435\u043D\u0442\u043E\u0432, \u0434\u0430\u0436\u0435 \u043D\u0435 \u043A\u0430\u0443\u0437\u0430\u043B\u044C\u043D\u043E\u0435, \u043F\u0440\u043E\u0438\u0437\u0432\u0435\u0434\u0435\u043D\u043D\u043E\u0435 \u0438\u0437 \u0436\u0438\u0437\u043D\u0435\u043D\u043D\u043E\u0439 \u044D\u043D\u0435\u0440\u0433\u0438\u0438. \u0422\u044B \u0435\u0441\u0442\u044C \u041E\u043D! \u041A\u043E\u0433\u0434\u0430 \u0442\u044B \u043E\u0441\u043E\u0437\u043D\u0430\u0451\u0448\u044C \u044D\u0442\u043E, &quot;\u0442\u044B \u043D\u0430\u0445\u043E\u0434\u0438\u0448\u044C\u0441\u044F \u0432 \u043F\u0440\u0430\u0432\u0438\u043B\u044C\u043D\u043E\u043C \u0421\u043E\u0441\u043E\u0442\u043E\u044F\u043D\u0438\u0438&quot;, \u0441\u043E\u0433\u043B\u0430\u0441\u043D\u043E \u0422\u0440\u0438\u043A\u0435, \u0433\u0434\u0435 \u0431\u044B \u043D\u0438 \u043D\u0430\u0445\u043E\u0434\u0438\u043B\u043E\u0441\u044C \u0442\u0432\u043E\u0435 \u0442\u0435\u043B\u043E, \u043A\u0443\u0434\u0430 \u0431\u044B \u043D\u0435 \u043D\u0430\u043F\u0440\u0430\u0432\u0438\u043B\u0441\u044F \u0442\u0432\u043E\u0439 \u0443\u043C, \u0438 \u043A\u0430\u043A\u043E\u0432 \u0431\u044B \u043D\u0438 \u0431\u044B\u043B \u0442\u0432\u043E\u0439 \u0436\u0438\u0437\u043D\u0435\u043D\u043D\u044B\u0439 \u0441\u0442\u0430\u0442\u0443\u0441.</p><p>\u0417\u0430\u043A\u0440\u043E\u0439 \u0433\u043B\u0430\u0437\u0430 \u043D\u0430 \u043C\u0433\u043D\u043E\u0432\u0435\u043D\u0438\u0435. \u0422\u0435\u043F\u0435\u0440\u044C \u043E\u0442\u043A\u0440\u043E\u0439. \u0418 \u0434\u0435\u0440\u0436\u0438 \u0441\u0432\u043E\u0438 \u0433\u043B\u0430\u0437\u0430 \u043E\u0442\u043A\u0440\u044B\u0442\u044B\u043C\u0438 \u0438 \u0441\u043E\u0437\u0435\u0440\u0446\u0430\u0439 \u043E\u0431\u044A\u0435\u043A\u0442\u044B \u043F\u0435\u0440\u0435\u0434 \u0441\u043E\u0431\u043E\u0439. \u042D\u0442\u043E \u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F \u0415\u0433\u043E \u043F\u0440\u043E\u044F\u0432\u043B\u0435\u043D\u0438\u0435\u043C \u043E\u0431\u044A\u0435\u043A\u0442\u043E\u0432. \u041D\u0430\u043A\u043E\u043D\u0435\u0446, \u0437\u0430\u043A\u0440\u043E\u0439 \u0433\u043B\u0430\u0437\u0430 \u0441\u043D\u043E\u0432\u0430. \u042D\u0442\u043E \u0415\u0433\u043E \u0440\u0430\u0441\u0442\u0432\u043E\u0440\u0435\u043D\u0438\u0435 \u043E\u0431\u044A\u0435\u043A\u0442\u043E\u0432. \u0417\u0430\u0442\u0435\u043C, \u043F\u043E\u0432\u0442\u043E\u0440\u0438 \u043F\u0440\u043E\u0446\u0435\u0441\u0441, \u0444\u0438\u043A\u0441\u0438\u0440\u0443\u044F \u0441\u0432\u043E\u0451 \u0432\u043D\u0438\u043C\u0430\u043D\u0438\u0435 \u043D\u0430 &quot;\u042F&quot; (\u0421\u0432\u0438\u0434\u0435\u0442\u0435\u043B\u0435, \u0438\u043B\u0438 \u041F\u043E\u0437\u043D\u0430\u044E\u0449\u0435\u043C), \u0430 \u043D\u0435 \u043D\u0430 \u043E\u0431\u044A\u0435\u043A\u0442\u0430\u0445. \u041D\u0443, \u044D\u0442\u043E \u0435\u0441\u0442\u044C Turya. \u0421\u043E \u0432\u0440\u0435\u043C\u0435\u043D\u0435\u043C, \u0435\u0441\u043B\u0438 \u0432\u044B \u0434\u0435\u043B\u0430\u0435\u0442\u0435 \u044D\u0442\u043E \u043F\u0440\u0430\u0432\u0438\u043B\u044C\u043D\u043E, \u0432\u044B \u0438\u0441\u043F\u044B\u0442\u0430\u0435\u0442\u0435 \u0412\u044B\u0441\u0448\u0435\u0435 \u041D\u0430\u0441\u043B\u0430\u0436\u0434\u0435\u043D\u0438\u0435, \u043F\u043E\u0442\u043E\u043C\u0443 \u0447\u0442\u043E \u0442\u0430\u043A\u043E\u0432\u0430 \u043F\u0440\u0438\u0440\u043E\u0434\u0430 Turya. \u0412\u0441\u0435 \u044D\u0442\u043E \u041D\u0430\u0441\u043B\u0430\u0436\u0434\u0435\u043D\u0438\u0435 \u0441\u0443\u0449\u0435\u0441\u0442\u0432\u0443\u0435\u0442 \u0432 \u043E\u0434\u043D\u043E\u043C \u043C\u0435\u0441\u0442\u0435, \u0430 \u0438\u043C\u0435\u043D\u043D\u043E, \u0432 \u0422\u0435\u0431\u0435, \u0421\u0432\u0438\u0434\u0435\u0442\u0435\u043B\u0435, \u0438\u043B\u0438 \u041F\u043E\u0437\u043D\u0430\u044E\u0449\u0435\u043C. \u0422\u044B \u0438\u0441\u043F\u044B\u0442\u044B\u0432\u0430\u0435\u0448\u044C \u0443\u0434\u043E\u0432\u043E\u043B\u044C\u0441\u0442\u0432\u0438\u0435 \u0432 \u0442\u0440\u0435\u0445 \u0434\u0440\u0443\u0433\u0438\u0445 \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u044F\u0445, \u043F\u043E\u0441\u043A\u043E\u043B\u044C\u043A\u0443 \u043A\u0440\u043E\u0448\u0435\u0447\u043D\u0430\u044F \u0447\u0430\u0441\u0442\u044C \u044D\u0442\u043E\u0433\u043E \u0412\u044B\u0441\u0448\u0435\u0433\u043E \u041D\u0430\u0441\u043B\u0430\u0436\u0434\u0435\u043D\u0438\u044F \u0444\u0438\u043B\u044C\u0442\u0440\u0443\u0435\u0442\u0441\u044F \u0447\u0435\u0440\u0435\u0437 \u0441\u0435\u0442\u044C, \u0441\u043E\u0442\u043A\u0430\u043D\u043D\u0443\u044E m\u0101y\u0101\u015Bakti. \u041A\u043E\u0433\u0434\u0430 \u044D\u0442\u0430 \u0441\u0435\u0442\u044C \u0443\u0434\u0430\u043B\u044F\u0435\u0442\u0441\u044F, \u0442\u044B \u0438\u0441\u043F\u044B\u0442\u044B\u0432\u0430\u0435\u0448\u044C \u0432\u0441\u044E \u0441\u0443\u0449\u0435\u0441\u0442\u0432\u0443\u044E\u0449\u0443\u044E \u0420\u0430\u0434\u043E\u0441\u0442\u044C \u043E\u0434\u043D\u043E\u0432\u0440\u0435\u043C\u0435\u043D\u043D\u043E. \u041E\u0433\u0440\u043E\u043C\u043D\u043E\u0435 \u041D\u0430\u0441\u043B\u0430\u0436\u0434\u0435\u043D\u0438\u0435 \u0437\u0430\u0442\u043E\u043F\u043B\u044F\u0435\u0442 \u0442\u0435\u0431\u044F \u0432 \u043A\u0430\u0436\u0434\u044B\u0439 \u043C\u043E\u043C\u0435\u043D\u0442 \u0432\u0440\u0435\u043C\u0435\u043D\u0438. \u041A\u043E\u043D\u0435\u0447\u043D\u043E, \u043F\u0440\u043E\u0446\u0435\u0441\u0441 \u043F\u043E\u043B\u0443\u0447\u0435\u043D\u0438\u044F \u044D\u0442\u043E\u0433\u043E \u043A\u043E\u043B\u043E\u0441\u0441\u0430\u043B\u044C\u043D\u043E\u0433\u043E \u0411\u043B\u0430\u0436\u0435\u043D\u0441\u0442\u0432\u0430 \u0431\u0443\u0434\u0435\u0442 \u043F\u043E\u0441\u0442\u0435\u043F\u0435\u043D\u043D\u044B\u043C \u0438 \u0432 \u0441\u043E\u043E\u0442\u0432\u0435\u0442\u0441\u0442\u0432\u0438\u0438 \u0441 \u0442\u0432\u043E\u0438\u043C\u0438 \u0441\u043E\u0431\u0441\u0442\u0432\u0435\u043D\u043D\u044B\u043C\u0438 \u0432\u043E\u0437\u043C\u043E\u0436\u043D\u043E\u0441\u0442\u044F\u043C\u0438. \u0422\u044B \u043F\u0440\u0435\u0434\u043F\u043E\u0447\u0442\u0435\u0448\u044C \u044D\u0442\u043E \u0438\u043B\u0438 \u0436\u0430\u043B\u043A\u043E\u0435 \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u0435 \u0421\u0430\u043A\u0430\u043B\u044B, \u0432\u0441\u0435 \u0432\u0440\u0435\u043C\u044F \u043F\u0440\u043E\u0441\u044F\u0449\u0435\u0433\u043E \u043E \u043A\u0430\u043A\u043E\u043C-\u0442\u043E \u0441\u0447\u0430\u0441\u0442\u044C\u0435?</p><p>\u041D\u043E, \u0434\u0430\u0436\u0435 \u043F\u043E\u0441\u043B\u0435 \u043F\u043E\u043B\u0443\u0447\u0435\u043D\u0438\u044F \u0432\u0441\u0435\u0433\u043E \u0441\u0443\u0449\u0435\u0441\u0442\u0432\u0443\u044E\u0449\u0435\u0433\u043E, \u0438\u043B\u0438 \u0432\u043E\u0437\u043C\u043E\u0436\u043D\u043E\u0433\u043E \u041D\u0430\u0441\u043B\u0430\u0436\u0434\u0435\u043D\u0438\u044F (\u0442.\u0435. Turya), \u0442\u044B \u043C\u043E\u0436\u0435\u0448\u044C \u0438\u0434\u0442\u0438 \u0435\u0449\u0435 \u0434\u0430\u043B\u044C\u0448\u0435, \u043A Tury\u0101t\u012Bta (\u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u044E \u0437\u0430 \u043F\u0440\u0435\u0434\u0435\u043B\u0430\u043C\u0438 Turya, \u0438\u043B\u0438 \u0427\u0435\u0442\u0432\u0435\u0440\u0442\u043E\u0433\u043E). \u0412 \u044D\u0442\u043E\u043C \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u0438 \u0442\u044B \u0438\u0441\u043F\u044B\u0442\u044B\u0432\u0430\u0435\u0448\u044C \u0442\u043E\u043B\u044C\u043A\u043E \u0447\u0438\u0441\u0442\u043E\u0435 \u0421\u043E\u0437\u043D\u0430\u043D\u0438\u0435, \u0438 \u0442\u044B \u043F\u043E\u043B\u043D\u043E\u0441\u0442\u044C\u044E \u043D\u0435\u0443\u044F\u0437\u0432\u0438\u043C. \u0422\u0435\u043C \u043D\u0435 \u043C\u0435\u043D\u0435\u0435, \u0440\u0435\u0447\u044C \u0438\u0434\u0435\u0442 \u043D\u0435 \u043E \u0442\u043E\u043C, \u0447\u0442\u043E \u0442\u044B \u043D\u0435\u0443\u044F\u0437\u0432\u0438\u043C \u0432 \u0441\u043C\u044B\u0441\u043B\u0435 \u0441\u0432\u043E\u0435\u0433\u043E \u0440\u043E\u0434\u0430 \u0441\u0432\u0435\u0440\u0445\u0447\u0435\u043B\u043E\u0432\u0435\u043A\u0430, \u043A\u043E\u0442\u043E\u0440\u044B\u0439 \u043E\u0441\u0442\u0430\u043D\u0430\u0432\u043B\u0438\u0432\u0430\u0435\u0442 \u043F\u0443\u043B\u0438 \u0433\u043E\u043B\u044B\u043C\u0438 \u0440\u0443\u043A\u0430\u043C\u0438... \u043D\u0435\u0442... \u044D\u0442\u043E \u043D\u0435 \u043E \u0442\u043E\u043C \u0436\u0435 \u0436\u0430\u043B\u043A\u043E\u043C \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u0438 \u0421\u0430\u043A\u0430\u043B\u044B, \u0430 \u043E &quot;\u043F\u0435\u0440\u0435\u0437\u0430\u0440\u044F\u0436\u0435\u043D\u043D\u043E\u043C&quot;, \u043E \u043D\u043E\u0432\u043E\u043C \u0432\u0438\u0434\u0435 \u0441\u0443\u0449\u0435\u0441\u0442\u0432\u043E\u0432\u0430\u043D\u0438\u044F. \u0422\u044B \u043D\u0435\u0443\u044F\u0437\u0432\u0438\u043C, \u043F\u043E\u0442\u043E\u043C\u0443 \u0447\u0442\u043E \u043D\u0435 \u0437\u0430\u0432\u0438\u0441\u0438\u0448\u044C \u043E\u0442 \u0447\u0435\u0433\u043E-\u043B\u0438\u0431\u043E \u0435\u0449\u0435 \u0432 &quot;\u0431\u044B\u0442\u0438\u0438&quot;. \u0422\u044B \u0432\u0441\u0435\u0433\u0434\u0430 \u0442\u0430\u043A\u043E\u0432, \u043D\u043E \u0432 Tury\u0101t\u012Bta \u0443 \u0442\u0435\u0431\u044F \u0435\u0441\u0442\u044C \u0440\u0435\u0430\u043B\u044C\u043D\u043E\u0435 \u043E\u0441\u043E\u0437\u043D\u0430\u043D\u0438\u0435 \u0442\u043E\u0433\u043E, \u0447\u0442\u043E \u044D\u0442\u043E \u0430\u0431\u0441\u043E\u043B\u044E\u0442\u043D\u043E \u0432\u0435\u0440\u043D\u043E. \u041F\u043E\u043A\u0430 \u0442\u044B \u0443\u0434\u0435\u0440\u0436\u0438\u0432\u0430\u0435\u0448\u044C \u044D\u0442\u043E \u043E\u0441\u043E\u0437\u043D\u0430\u043D\u0438\u0435, \u0442\u044B &quot;\u0431\u0435\u0437 \u0432\u0441\u044F\u043A\u043E\u0433\u043E \u0441\u043E\u043C\u043D\u0435\u043D\u0438\u044F&quot; \u043E\u0449\u0443\u0449\u0430\u0435\u0448\u044C, \u0447\u0442\u043E \u044F\u0432\u043B\u044F\u0435\u0448\u044C\u0441\u044F \u0412\u044B\u0441\u0448\u0438\u043C \u0421\u0443\u0449\u0435\u0441\u0442\u0432\u043E\u043C, \u043D\u0435\u0437\u0430\u0432\u0438\u0441\u0438\u043C\u043E \u043E\u0442 \u0442\u043E\u0433\u043E, \u0436\u0438\u0432\u043E \u0438\u043B\u0438 \u043C\u0435\u0440\u0442\u0432\u043E \u0442\u0432\u043E\u0435 \u0442\u0435\u043B\u043E, \u0440\u0430\u0431\u043E\u0442\u0430\u0435\u0442 \u0442\u0432\u043E\u0439 \u0443\u043C \u0438\u043B\u0438 \u043E\u0441\u0442\u0430\u043D\u043E\u0432\u043B\u0435\u043D, \u0436\u0438\u0432\u0435\u0448\u044C \u043B\u0438 \u0442\u044B \u0432 \u041C\u043B\u0435\u0447\u043D\u043E\u043C \u041F\u0443\u0442\u0438 \u0438\u043B\u0438 \u0432 \u0441\u0430\u043C\u043E\u0439 \u0434\u0430\u043B\u044C\u043D\u0435\u0439 \u0433\u0430\u043B\u0430\u043A\u0442\u0438\u043A\u0435 \u0432\u0441\u0435\u043B\u0435\u043D\u043D\u043E\u0439 \u0438 \u0442.\u0434. \u042D\u0442\u043E \u043D\u0435 \u043F\u0440\u043E\u0441\u0442\u043E \u0431\u0435\u0437\u0440\u0430\u0437\u043B\u0438\u0447\u0438\u0435 \u0438\u043B\u0438 \u043F\u0440\u0435\u0442\u0435\u043D\u0446\u0438\u043E\u0437\u043D\u043E\u0441\u0442\u044C (\u043F\u043E\u0441\u043A\u043E\u043B\u044C\u043A\u0443 \u043E\u043D\u0438 \u0432\u0441\u0435 \u0435\u0449\u0435 \u043D\u0430\u0445\u043E\u0434\u044F\u0442\u0441\u044F \u0432 \u0446\u0430\u0440\u0441\u0442\u0432\u0435 \u0443\u043C\u0430), \u043D\u043E \u0438\u0441\u0442\u0438\u043D\u043D\u0430\u044F \u0430\u0431\u0441\u043E\u043B\u044E\u0442\u043D\u0430\u044F \u043D\u0435\u043F\u0440\u0438\u0432\u044F\u0437\u0430\u043D\u043D\u043E\u0441\u0442\u044C \u043A \u0447\u0435\u043C\u0443 \u0431\u044B \u0442\u043E \u043D\u0438 \u0431\u044B\u043B\u043E (\u0438\u043D\u0434\u0438\u0432\u0438\u0434\u0443\u0430\u043B\u044C\u043D\u043E\u0441\u0442\u0438, \u0443\u043C\u0443, \u0442\u0435\u043B\u0443, \u0436\u0438\u0437\u043D\u0438, \u0441\u043C\u0435\u0440\u0442\u0438, \u0432\u0440\u0435\u043C\u0435\u043D\u0438, \u0441\u0442\u0440\u0430\u0445\u0443... \u043A\u043E \u0432\u0441\u0435\u043C\u0443!). \u0422\u044B \u043E\u0441\u0442\u0430\u0435\u0448\u044C\u0441\u044F \u0447\u0438\u0441\u0442\u044B\u043C \u0421\u043E\u0437\u043D\u0430\u043D\u0438\u0435\u043C \u0432 \u0410\u0431\u0441\u043E\u043B\u044E\u0442\u043D\u043E\u0439 \u0421\u0432\u043E\u0431\u043E\u0434\u0435!</p><p>\u041F\u043E\u043D\u0430\u0447\u0430\u043B\u0443, \u044D\u0442\u043E\u0442 \u043E\u043F\u044B\u0442 \u0434\u043B\u0438\u0442\u0441\u044F \u0442\u043E\u043B\u044C\u043A\u043E \u043C\u0433\u043D\u043E\u0432\u0435\u043D\u0438\u0435 \u0438 \u0441\u043B\u0443\u0447\u0430\u0435\u0442\u0441\u044F \u0431\u043B\u0430\u0433\u043E\u0434\u0430\u0440\u044F \u0415\u0433\u043E \u041C\u0438\u043B\u043E\u0441\u0442\u0438, \u043D\u043E \u043F\u043E \u043C\u0435\u0440\u0435 \u0441\u0442\u0430\u0431\u0438\u043B\u0438\u0437\u0430\u0446\u0438\u0438 \u0432 Turya, \u0448\u0430\u043D\u0441\u044B \u0432\u043E\u0439\u0442\u0438 \u0432 \u043A\u043E\u043D\u0442\u0430\u043A\u0442 \u0441 Tury\u0101t\u012Bta \u0441\u043E\u043E\u0442\u0432\u0435\u0442\u0441\u0442\u0432\u0435\u043D\u043D\u043E \u0443\u0432\u0435\u043B\u0438\u0447\u0438\u0432\u0430\u044E\u0442\u0441\u044F. \u042D\u0442\u043E\u0442 \u043E\u043F\u044B\u0442 \u0430\u0431\u0441\u043E\u043B\u044E\u0442\u043D\u043E \u043E\u0448\u0435\u043B\u043E\u043C\u043B\u044F\u044E\u0449\u0438\u0439 \u0438 \u043D\u0435 \u043F\u043E\u0434\u0434\u0430\u0435\u0442\u0441\u044F \u043E\u043F\u0438\u0441\u0430\u043D\u0438\u044E. \u0418\u043D\u0442\u0435\u0440\u0435\u0441\u0435\u043D \u043C\u043E\u043C\u0435\u043D\u0442, \u043A\u043E\u0433\u0434\u0430 \u0442\u044B \u0432\u043F\u0435\u0440\u0432\u044B\u0435 \u0434\u043E\u0441\u0442\u0438\u0433\u0430\u0435\u0448\u044C Tury\u0101t\u012Bta. \u042D\u0442\u043E \u0434\u043B\u0438\u0442\u0441\u044F \u043C\u0433\u043D\u043E\u0432\u0435\u043D\u0438\u0435, \u043D\u043E \u043D\u0435\u0432\u043E\u0437\u043C\u043E\u0436\u043D\u043E \u0441\u043A\u0430\u0437\u0430\u0442\u044C, &quot;\u043A\u0430\u043A \u0434\u043E\u043B\u0433\u043E \u044D\u0442\u043E \u0431\u044B\u043B\u043E&quot;, \u043F\u043E\u0441\u043A\u043E\u043B\u044C\u043A\u0443 \u0432\u0440\u0435\u043C\u044F \u0438 \u043F\u0440\u043E\u0441\u0442\u0440\u0430\u043D\u0441\u0442\u0432\u043E \u043E\u0442\u0441\u0443\u0442\u0441\u0442\u0432\u0443\u044E\u0442 \u0432 Tury\u0101t\u012Bta, \u043D\u0435\u0441\u043C\u043E\u0442\u0440\u044F \u043D\u0430 \u0442\u043E, \u0447\u0442\u043E \u0442\u044B \u043C\u043E\u0436\u0435\u0448\u044C \u0441\u043E\u0445\u0440\u0430\u043D\u044F\u0442\u044C \u0432\u043E\u0441\u043F\u0440\u0438\u044F\u0442\u0438\u0435 \u0441\u0432\u043E\u0435\u0433\u043E \u0442\u0435\u043B\u0430, \u0432\u043D\u0435\u0448\u043D\u0438\u0445 \u043E\u0431\u044A\u0435\u043A\u0442\u043E\u0432 \u0438 \u0442.\u0434. \u041D\u0430 \u0441\u0430\u043C\u043E\u043C \u0434\u0435\u043B\u0435, \u0442\u044B \u043C\u043E\u0436\u0435\u0448\u044C \u043F\u0440\u043E\u0434\u043E\u043B\u0436\u0430\u0442\u044C \u0441\u0432\u043E\u044E \u043E\u0431\u044B\u0447\u043D\u0443\u044E \u0434\u0435\u044F\u0442\u0435\u043B\u044C\u043D\u043E\u0441\u0442\u044C, \u043F\u0440\u0435\u0431\u044B\u0432\u0430\u044F \u0432 Tury\u0101t\u012Bta. \u0422\u0435\u043C \u043D\u0435 \u043C\u0435\u043D\u0435\u0435, \u0445\u043E\u0442\u044F \u0442\u044B \u0432\u043E\u0441\u043F\u0440\u0438\u043D\u0438\u043C\u0430\u0435\u0448\u044C \u043F\u0440\u043E\u0441\u0442\u0440\u0430\u043D\u0441\u0442\u0432\u043E, \u0432\u0440\u0435\u043C\u044F, \u0434\u0432\u0438\u0436\u0435\u043D\u0438\u0435 \u0438 \u0442.\u043F., \u043D\u0438\u0447\u0435\u0433\u043E \u044D\u0442\u043E\u0433\u043E \u043D\u0435 \u0441\u0443\u0449\u0435\u0441\u0442\u0432\u0443\u0435\u0442 \u043F\u043E-\u043F\u0440\u0435\u0436\u043D\u0435\u043C\u0443 (\u0442.\u0435. \u0434\u043E \u0442\u0430\u043A\u043E\u0439 \u0440\u0435\u0430\u043B\u0438\u0437\u0430\u0446\u0438\u0438). \u041E\u0447\u0435\u0432\u0438\u0434\u043D\u043E, \u044F \u043D\u0435 \u043C\u043E\u0433\u0443 \u043E\u0431\u044A\u044F\u0441\u043D\u0438\u0442\u044C \u044D\u0442\u043E \u0434\u043E\u043B\u0436\u043D\u044B\u043C \u043E\u0431\u0440\u0430\u0437\u043E\u043C, \u0438\u0441\u043F\u043E\u043B\u044C\u0437\u0443\u044F \u0441\u043B\u043E\u0432\u0430. \u042F \u043C\u043E\u0433 \u0431\u044B \u043D\u0430\u043F\u0438\u0441\u0430\u0442\u044C \u0446\u0435\u043B\u0443\u044E \u043A\u043D\u0438\u0433\u0443, \u0438 \u0432\u0441\u0435 \u0436\u0435 \u043C\u043E\u0438 \u043E\u0431\u044A\u044F\u0441\u043D\u0435\u043D\u0438\u044F \u0431\u044B\u043B\u0438 \u0431\u044B \u043D\u0435 \u0442\u043E\u0447\u043D\u044B\u043C\u0438, \u043F\u043E\u0441\u043A\u043E\u043B\u044C\u043A\u0443 \u0441\u043B\u043E\u0432\u0430 \u0440\u043E\u0436\u0434\u0430\u044E\u0442\u0441\u044F \u043F\u043E\u0441\u043B\u0435 Tury\u0101t\u012Bta, \u0430 \u043D\u0435 \u0434\u043E \u041D\u0435\u0435. \u0418\u0442\u0430\u043A, \u0441\u043D\u0430\u0447\u0430\u043B\u0430 \u041E\u043D\u0430 \u043F\u0440\u043E\u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F \u0432\u043D\u0435\u0437\u0430\u043F\u043D\u043E \u0438 \u0442\u0443\u0442 \u0436\u0435 \u0443\u0445\u043E\u0434\u0438\u0442, \u0438 \u044D\u0442\u043E \u0432\u0441\u0435, \u0447\u0442\u043E \u0442\u044B \u043E\u0431\u043D\u0430\u0440\u0443\u0436\u0438\u0432\u0430\u0435\u0448\u044C. \u041F\u043E\u0441\u043B\u0435 \u0442\u0430\u043A\u043E\u0433\u043E \u0434\u043E\u0441\u0442\u0438\u0436\u0435\u043D\u0438\u044F, \u0442\u044B \u0437\u0430\u0434\u0430\u0451\u0448\u044C\u0441\u044F \u0432\u043E\u043F\u0440\u043E\u0441\u043E\u043C, \u0430 \u0447\u0442\u043E \u0442\u044B \u0434\u0435\u043B\u0430\u043B \u0434\u043E \u044D\u0442\u043E\u0433\u043E. \u041F\u043E \u0441\u0440\u0430\u0432\u043D\u0435\u043D\u0438\u044E \u0441 \u044D\u0442\u0438\u043C \u0432\u043E\u0437\u0432\u044B\u0448\u0435\u043D\u043D\u044B\u043C \u0421\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u0435\u043C, \u0432\u0441\u0435, \u0447\u0442\u043E \u0442\u044B \u0438\u0441\u043F\u044B\u0442\u044B\u0432\u0430\u043B \u0440\u0430\u043D\u0435\u0435, \u043F\u043E\u0445\u043E\u0436\u0435 \u043D\u0430 &quot;\u043F\u044B\u043B\u044C&quot;. \u041D\u0443, \u044D\u0442\u043E \u043F\u0440\u043E\u0441\u0442\u043E \u0431\u044B\u043B\u0430 \u0438\u0433\u0440\u0430 \u0421\u043E\u0437\u043D\u0430\u043D\u0438\u044F, \u0442\u044B \u0437\u043D\u0430\u0435\u0448\u044C. \u0422\u0430\u043A \u0438\u043B\u0438 \u0438\u043D\u0430\u0447\u0435, \u0432 \u043F\u0440\u043E\u0446\u0435\u0441\u0441\u0435 Tury\u0101t\u012Bta \u0432\u0441\u0435 \u043A\u0430\u0436\u0435\u0442\u0441\u044F \u043F\u0440\u043E\u043D\u0438\u0437\u0430\u043D\u043D\u044B\u043C \u0430\u0431\u0441\u043E\u043B\u044E\u0442\u043D\u044B\u043C \u0441\u043F\u043E\u043A\u043E\u0439\u0441\u0442\u0432\u0438\u0435\u043C, \u0442\u043E \u0435\u0441\u0442\u044C \u043D\u0438\u043A\u0430\u043A\u0438\u0445 \u043C\u043D\u0435\u043D\u0438\u0439 \u0437\u0430 \u0438 \u043F\u0440\u043E\u0442\u0438\u0432 \u0447\u0435\u0433\u043E-\u043B\u0438\u0431\u043E. \u041D\u0435\u0441\u043C\u043E\u0442\u0440\u044F \u043D\u0430 \u0442\u043E, \u0447\u0442\u043E \u0434\u0435\u0439\u0441\u0442\u0432\u0438\u044F \u043F\u0440\u043E\u0434\u043E\u043B\u0436\u0430\u044E\u0442 \u0432\u044B\u043F\u043E\u043B\u043D\u044F\u0442\u044C\u0441\u044F, \u043C\u044B\u0441\u043B\u0438 \u043F\u0440\u043E\u0434\u043E\u043B\u0436\u0430\u044E\u0442 \u043F\u043E\u044F\u0432\u043B\u044F\u0442\u044C\u0441\u044F, \u043F\u043E\u043B\u043D\u044B\u0435 \u043C\u043D\u0435\u043D\u0438\u0439 \u0438 \u0442\u043E\u043C\u0443 \u043F\u043E\u0434\u043E\u0431\u043D\u044B\u0445 \u0432\u0435\u0449\u0435\u0439, \u0442\u044B \u043E\u0441\u0442\u0430\u0451\u0448\u044C\u0441\u044F \u043F\u043E\u043B\u043D\u043E\u0441\u0442\u044C\u044E \u0431\u0435\u0441\u043F\u0440\u0438\u0441\u0442\u0440\u0430\u0441\u0442\u043D\u044B\u043C \u043A \u044D\u0442\u043E\u043C\u0443. \u042D\u0442\u043E \u043F\u0440\u043E\u0441\u0442\u043E &quot;\u0411\u044B\u0442\u0438\u0435&quot; \u0437\u0430 \u043F\u0440\u0435\u0434\u0435\u043B\u0430\u043C\u0438 \u0432\u0441\u0435\u0445 &quot;\u0436\u0435\u043B\u0430\u043D\u0438\u0439&quot;, &quot;\u0437\u043D\u0430\u043D\u0438\u0439&quot; \u0438 &quot;\u0434\u0435\u044F\u043D\u0438\u0439&quot;. \u041D\u0435\u0432\u0435\u0440\u043E\u044F\u0442\u043D\u043E! \u0418, \u043A\u043E\u043D\u0435\u0447\u043D\u043E, \u0442\u044B \u0436\u0435\u043B\u0430\u0435\u0448\u044C \u044D\u0442\u043E\u0433\u043E \u0431\u043E\u043B\u044C\u0448\u0435. \u042D\u0442\u043E \u0442\u0432\u043E\u0435 \u0421\u043E\u043A\u0440\u043E\u0432\u0438\u0449\u0435, \u0438 \u043A\u0430\u043A \u0442\u043E\u043B\u044C\u043A\u043E \u0442\u044B \u043E\u0431\u043D\u0430\u0440\u0443\u0436\u0438\u0432\u0430\u0435\u0448\u044C \u0435\u0433\u043E, \u043D\u0435\u0432\u043E\u0437\u043C\u043E\u0436\u043D\u043E \u043E\u0441\u0442\u0430\u0432\u0438\u0442\u044C \u0438 \u0437\u0430\u0431\u044B\u0442\u044C \u043E \u043D\u0435\u043C. \u041D\u0435\u0442, \u0442\u044B \u0445\u043E\u0447\u0435\u0448\u044C \u0432\u043E \u0447\u0442\u043E \u0431\u044B \u0442\u043E \u043D\u0438 \u0441\u0442\u0430\u043B\u043E \u043E\u0431\u0440\u0435\u0441\u0442\u0438 Tury\u0101t\u012Bta \u0441\u043D\u043E\u0432\u0430, \u043F\u043E\u0442\u043E\u043C\u0443 \u0447\u0442\u043E \u044D\u0442\u043E \u0441\u0430\u043C\u043E\u0435 \u0432\u0430\u0436\u043D\u043E\u0435 \u0432 \u0442\u0432\u043E\u0435\u0439 \u0436\u0438\u0437\u043D\u0438 (&quot;\u043D\u0438\u0447\u0435\u0433\u043E \u0431\u043E\u043B\u0435\u0435 \u0432\u0430\u0436\u043D\u043E\u0433\u043E, \u0447\u0435\u043C \u0434\u043E\u0441\u0442\u0438\u0447\u044C \u044D\u0442\u043E \u0441\u043D\u043E\u0432\u0430&quot;, \u044D\u0442\u043E \u0442\u0430\u043A, \u043A\u0430\u043A \u0442\u044B \u0441\u0435\u0431\u044F \u0447\u0443\u0432\u0441\u0442\u0432\u0443\u0435\u0448\u044C, \u0438 \u0434\u0430!, \u0447\u0442\u043E \u043C\u043E\u0436\u0435\u0442 \u0431\u044B\u0442\u044C \u0431\u043E\u043B\u0435\u0435 \u0432\u0430\u0436\u043D\u044B\u043C, \u0447\u0435\u043C \u0442\u0432\u043E\u044F \u0421\u0432\u043E\u0431\u043E\u0434\u0430?)... \u043D\u043E... \u0442\u044B \u043E\u0441\u043E\u0437\u043D\u0430\u0435\u0448\u044C, \u0447\u0442\u043E \u043D\u0435 \u043C\u043E\u0436\u0435\u0448\u044C \u043F\u043E\u043B\u0443\u0447\u0438\u0442\u044C \u044D\u0442\u043E &quot;\u043F\u043E \u0436\u0435\u043B\u0430\u043D\u0438\u044E&quot;. \u042D\u0442\u043E \u0432\u0441\u0435\u0433\u0434\u0430 \u043E \u0415\u0433\u043E \u041C\u0438\u043B\u043E\u0441\u0442\u0438, \u0445\u043E\u0442\u044F, \u043A\u0430\u043A \u044D\u0442\u043E \u043D\u0438 \u043F\u0430\u0440\u0430\u0434\u043E\u043A\u0441\u0430\u043B\u044C\u043D\u043E, \u043D\u043E \u0422\u044B \u0435\u0441\u0442\u044C \u041E\u043D.</p><p>\u0412 \u044D\u0442\u043E\u0442 \u043C\u043E\u043C\u0435\u043D\u0442, \u0442\u044B \u0434\u043E\u043B\u0436\u0435\u043D \u0431\u044B\u0442\u044C \u0442\u0435\u0440\u043F\u0435\u043B\u0438\u0432 \u0438 \u043F\u0440\u043E\u0434\u043E\u043B\u0436\u0430\u0442\u044C \u043D\u0430\u0441\u043B\u0430\u0436\u0434\u0430\u0442\u044C\u0441\u044F Turya \u0438 \u0435\u0435 \u043A\u043E\u043C\u043F\u0430\u043A\u0442\u043D\u043E\u0439 \u043C\u0430\u0441\u0441\u043E\u0439 \u0411\u043B\u0430\u0436\u0435\u043D\u0441\u0442\u0432\u0430 \u0432\u0441\u0435 \u0431\u043E\u043B\u044C\u0448\u0435 \u0438 \u0431\u043E\u043B\u044C\u0448\u0435, \u043F\u043E\u043A\u0430 \u041E\u043D\u0430 \u043D\u0435 \u0437\u0430\u043F\u043E\u043B\u043D\u0438\u0442 \u0432\u0441\u044E \u0442\u0432\u043E\u044E \u0436\u0438\u0437\u043D\u044C. \u041F\u043E\u0441\u0442\u0435\u043F\u0435\u043D\u043D\u043E, Tury\u0101t\u012Bta \u0431\u0443\u0434\u0435\u0442 \u043F\u043E\u0441\u0435\u0449\u0438\u0442\u044C \u0442\u0435\u0431\u044F \u0432\u0441\u0435 \u0447\u0430\u0449\u0435 \u0438 \u0447\u0430\u0449\u0435, \u043F\u043E\u043A\u0430 \u0442\u044B \u043D\u0435 \u0441\u0442\u0430\u043D\u0435\u0448\u044C \u043E\u0441\u0432\u043E\u0431\u043E\u0436\u0434\u0435\u043D\u043D\u044B\u043C \u043F\u043E\u043B\u043D\u043E\u0441\u0442\u044C\u044E, \u0442.\u0435. \u043F\u043E\u043B\u043D\u043E\u0441\u0442\u044C\u044E \u0421\u0432\u043E\u0431\u043E\u0434\u043D\u044B\u043C, \u043A\u0430\u043A \u0413\u043E\u0441\u043F\u043E\u0434\u044C. \u041C\u043E\u0439 \u0441\u043E\u0431\u0441\u0442\u0432\u0435\u043D\u043D\u044B\u0439 \u0413\u0443\u0440\u0443 \u043F\u0435\u0440\u0435\u0434\u0430\u043B \u043C\u043D\u0435 \u044D\u0442\u0443 \u0438\u0441\u0442\u0438\u043D\u0443: &quot;\u0411\u043E\u0433 \u043E\u0431\u0438\u0442\u0430\u0435\u0442 \u0432 \u0442\u0435\u0431\u0435, \u043A\u0430\u043A \u0442\u044B&quot;, \u0438 \u044D\u0442\u043E \u0442\u043E, \u0447\u0442\u043E \u0442\u044B \u043E\u0431\u043D\u0430\u0440\u0443\u0436\u0438\u0432\u0430\u0435\u0448\u044C \u0440\u0430\u043D\u043E \u0438\u043B\u0438 \u043F\u043E\u0437\u0434\u043D\u043E, \u0435\u0441\u043B\u0438 \u0431\u0443\u0434\u0435\u0448\u044C \u043D\u0430\u0441\u0442\u043E\u0439\u0447\u0438\u0432. \u0411\u0443\u0434\u044C \u0443\u0432\u0435\u0440\u0435\u043D, \u0447\u0442\u043E \u043F\u043E\u043B\u043D\u0430\u044F \u0432\u0441\u0442\u0440\u0435\u0447\u0430 \u0441 \u0411\u043E\u0433\u043E\u043C \u2014 \u044D\u0442\u043E \u0441\u0430\u043C\u044B\u0439 \u0443\u0434\u0438\u0432\u0438\u0442\u0435\u043B\u044C\u043D\u044B\u0439 \u043E\u043F\u044B\u0442, \u043A\u043E\u0442\u043E\u0440\u044B\u0439 \u043C\u043E\u0436\u0435\u0442 \u0438\u043C\u0435\u0442\u044C \u0447\u0435\u043B\u043E\u0432\u0435\u043A! \u041A\u0435\u043C \u0431\u044B \u043D\u0438 \u0431\u044B\u043B \u0447\u0438\u0442\u0430\u0442\u0435\u043B\u044C, \u0413\u043E\u0441\u043F\u043E\u0434\u044C \u0441\u0438\u044F\u0435\u0442 \u0432\u043E \u0432\u0441\u0435\u043C \u0421\u0432\u043E\u0435\u043C \u0412\u0435\u043B\u0438\u043A\u043E\u043B\u0435\u043F\u0438\u0438 \u0432\u0441\u0435\u0433\u0434\u0430 \u0438 \u0432\u0435\u0437\u0434\u0435. \u0410\u0432\u0442\u043E\u0440 \u0433\u043E\u0432\u043E\u0440\u0438\u0442 \u0447\u0442\u043E-\u0442\u043E \u043F\u043E\u0434\u043E\u0431\u043D\u043E\u0435, \u043D\u043E \u0437\u0430\u0432\u0443\u0430\u043B\u0438\u0440\u043E\u0432\u0430\u043D\u043E, \u0442.\u0435. \u0431\u0435\u0437 \u043C\u043E\u0438\u0445 \u043F\u043E\u0434\u0440\u043E\u0431\u043D\u044B\u0445 \u043E\u0431\u044A\u044F\u0441\u043D\u0435\u043D\u0438\u0439. OK, \u0445\u0432\u0430\u0442\u0438\u0442 \u043F\u043E\u043A\u0430 \u0440\u0430\u0441\u043A\u0440\u044B\u0432\u0430\u0442\u044C \u044D\u0442\u0438 \u0441\u0435\u043A\u0440\u0435\u0442\u044B \u043E Tury\u0101t\u012Bta.</p><p>\u0412\u043E\u0437\u0432\u0440\u0430\u0449\u0430\u044F\u0441\u044C \u043A \u043F\u0440\u043E\u0446\u0435\u0441\u0441\u0430\u043C \u043F\u0440\u043E\u044F\u0432\u043B\u0435\u043D\u0438\u044F, \u043F\u043E\u0434\u0434\u0435\u0440\u0436\u0430\u043D\u0438\u044F \u0438 \u0440\u0430\u0441\u0442\u0432\u043E\u0440\u0435\u043D\u0438\u044F \u043E\u0431\u044A\u0435\u043A\u0442\u043E\u0432, \u0432\u043E \u0432\u0441\u0435\u043C \u044D\u0442\u043E\u043C \u043D\u0435\u0442 \u043D\u0438\u0447\u0435\u0433\u043E \u0441\u043B\u043E\u0436\u043D\u043E\u0433\u043E, \u043F\u043E\u0441\u043A\u043E\u043B\u044C\u043A\u0443 \u044D\u0442\u043E \u0441\u0432\u044F\u0437\u0430\u043D\u043E \u0441 \u0441\u043E\u0431\u0441\u0442\u0432\u0435\u043D\u043D\u044B\u043C \u043E\u043F\u044B\u0442\u043E\u043C \u043A\u0430\u0436\u0434\u043E\u0433\u043E. \u0418 \u0434\u0430\u0436\u0435 \u0432 \u0441\u043B\u0443\u0447\u0430\u0435, \u043A\u043E\u0433\u0434\u0430 \u0443 \u0442\u0435\u0431\u044F \u0431\u0443\u0434\u0443\u0442 \u043E\u0442\u043A\u043B\u044E\u0447\u0435\u043D\u044B \u0432\u0441\u0435 \u0447\u0443\u0432\u0441\u0442\u0432\u0430 (\u043D\u0430\u043F\u0440\u0438\u043C\u0435\u0440, \u0432\u043E \u0432\u0440\u0435\u043C\u044F \u0441\u043D\u0430), \u043C\u0435\u043D\u0442\u0430\u043B\u044C\u043D\u044B\u0435 \u043E\u0431\u044A\u0435\u043A\u0442\u044B \u043F\u0440\u043E\u0434\u043E\u043B\u0436\u0430\u0442 \u043F\u0440\u043E\u044F\u0432\u043B\u044F\u0442\u044C\u0441\u044F, \u0441\u043E\u0445\u0440\u0430\u043D\u044F\u0442\u044C\u0441\u044F \u043D\u0435\u043A\u043E\u0442\u043E\u0440\u043E\u0435 \u0432\u0440\u0435\u043C\u044F, \u0438 \u043D\u0430\u043A\u043E\u043D\u0435\u0446, \u0432\u043D\u043E\u0432\u044C \u0440\u0430\u0441\u0442\u0432\u043E\u0440\u044F\u0442\u044C\u0441\u044F. \u0414\u0430\u0436\u0435 \u043F\u0443\u0441\u0442\u043E\u0442\u0430 \u0433\u043B\u0443\u0431\u043E\u043A\u043E\u0433\u043E \u0441\u043D\u0430 \u043F\u0440\u043E\u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F, \u043F\u043E\u0434\u0434\u0435\u0440\u0436\u0438\u0432\u0430\u0435\u0442\u0441\u044F \u0438 \u0440\u0430\u0441\u0442\u0432\u043E\u0440\u044F\u0435\u0442\u0441\u044F. \u041E\u0434\u043D\u0430\u043A\u043E, Turya \u043F\u0440\u0438\u0441\u0443\u0442\u0441\u0442\u0432\u0443\u0435\u0442 \u0432\u0441\u0435\u0433\u0434\u0430, \u043F\u0440\u043E\u043D\u0438\u0437\u044B\u0432\u0430\u044F \u0432\u0441\u0435 \u0434\u0440\u0443\u0433\u0438\u0435 \u0442\u0440\u0438 \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u044F. \u041E\u043D\u0430 \u043D\u0435 \u043F\u0440\u043E\u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F, \u043D\u0435 \u043F\u043E\u0434\u0434\u0435\u0440\u0436\u0438\u0432\u0430\u0435\u0442\u0441\u044F \u0438 \u043D\u0435 \u0440\u0430\u0441\u0442\u0432\u043E\u0440\u044F\u0435\u0442\u0441\u044F, \u043F\u043E\u0441\u043A\u043E\u043B\u044C\u043A\u0443 \u041E\u043D\u0430 \u2014 \u043D\u0435 \u043E\u0431\u044A\u0435\u043A\u0442 (\u0442\u043E, \u0447\u0442\u043E \u043C\u043E\u0436\u0435\u0442 \u0431\u044B\u0442\u044C \u0432\u043E\u0441\u043F\u0440\u0438\u043D\u044F\u0442\u043E, \u0442.\u0435. \u0442\u0432\u043E\u0451 \u0442\u0435\u043B\u043E, \u0441\u0442\u043E\u043B, \u043C\u044B\u0441\u043B\u044C \u0438 \u0442.\u0434.), \u0430 \u0412\u044B\u0441\u0448\u0438\u0439 \u0421\u0443\u0431\u044A\u0435\u043A\u0442, \u0438\u043B\u0438 \u0413\u043E\u0441\u043F\u043E\u0434\u044C (\u0422\u044B!).</p><p>\u041D\u0430 \u0441\u0430\u043C\u043E\u043C \u0434\u0435\u043B\u0435, \u043E\u0441\u043E\u0437\u043D\u0430\u0451\u0448\u044C \u043B\u0438 \u0442\u044B \u0438\u043B\u0438 \u043D\u0435\u0442, \u0447\u0442\u043E \u044F\u0432\u043B\u044F\u0435\u0448\u044C\u0441\u044F \u0421\u0432\u0438\u0434\u0435\u0442\u0435\u043B\u0435\u043C, \u0438\u043B\u0438 \u041F\u043E\u0437\u043D\u0430\u044E\u0449\u0438\u043C, \u0442\u044B \u2014 \u0432\u0441\u0451 \u0440\u0430\u0432\u043D\u043E \u041E\u043D. \u0417\u0434\u0435\u0441\u044C \u043D\u0435\u0442 \u043D\u0438\u043A\u043E\u0433\u043E \u0434\u0440\u0443\u0433\u043E\u0433\u043E, \u043A\u0440\u043E\u043C\u0435 \u0413\u043E\u0441\u043F\u043E\u0434\u0430. \u0412\u0441\u0435, \u0447\u0442\u043E \u043A\u0430\u0436\u0435\u0442\u0441\u044F \u0441\u0443\u0449\u0435\u0441\u0442\u0432\u0443\u044E\u0449\u0438\u043C \u043E\u0442\u043B\u0438\u0447\u043D\u044B\u043C \u0438 \u043E\u0442\u0434\u0435\u043B\u044C\u043D\u044B\u043C \u043E\u0442 \u041D\u0435\u0433\u043E, \u043E\u0431\u0443\u0441\u043B\u043E\u0432\u043B\u0435\u043D\u043E \u0438\u0433\u0440\u043E\u0439 \u0415\u0433\u043E m\u0101y\u0101\u015Bakti.</p></li><li><p>\u042D\u0442\u0430 \u0441\u0442\u0440\u043E\u0444\u0430 \u0438\u0437 Vij\xF1\u0101nabhairava \u2014 \u043E\u0447\u0435\u043D\u044C \u043A\u0430\u0432\u0435\u0440\u0437\u043D\u0430\u044F, \u0438 \u0435\u0441\u043B\u0438 \u0442\u044B \u044F\u0432\u043B\u044F\u0435\u0448\u044C\u0441\u044F \u0441\u0430\u043D\u0441\u043A\u0440\u0438\u0442\u0441\u043A\u0438\u043C \u0441\u0442\u0443\u0434\u0435\u043D\u0442\u043E\u043C, \u043F\u044B\u0442\u0430\u044E\u0449\u0438\u043C\u0441\u044F \u043F\u0435\u0440\u0435\u0432\u0435\u0441\u0442\u0438 \u0435\u0435, \u0442\u043E \u0431\u0435\u0437 \u0434\u043E\u043F\u043E\u043B\u043D\u0438\u0442\u0435\u043B\u044C\u043D\u043E\u0439 \u043F\u043E\u043C\u043E\u0449\u0438 \u0442\u044B \u0441\u043A\u043E\u0440\u0435\u0435 \u0432\u0441\u0435\u0433\u043E \u0434\u043E\u043F\u0443\u0441\u0442\u0438\u0448\u044C \u043D\u0435\u043A\u043E\u0442\u043E\u0440\u044B\u0435 \u043E\u0448\u0438\u0431\u043A\u0438. \u0427\u0442\u043E\u0431\u044B \u043F\u0440\u0435\u0434\u043E\u0442\u0432\u0440\u0430\u0442\u0438\u0442\u044C \u044D\u0442\u0438 \u043E\u0448\u0438\u0431\u043A\u0438, \u0438 \u043F\u043E\u043A\u0430\u0437\u0430\u0442\u044C \u0434\u0440\u0443\u0433\u0438\u043C \u043B\u044E\u0434\u044F\u043C, \u0447\u0438\u0442\u0430\u044E\u0449\u0438\u043C \u044D\u0442\u043E \u043F\u0440\u0438\u043C\u0435\u0447\u0430\u043D\u0438\u0435, \u043F\u043E\u0447\u0435\u043C\u0443 \u044F \u043F\u0435\u0440\u0435\u0432\u0435\u043B \u044D\u0442\u0443 \u0441\u0442\u0440\u043E\u0444\u0443 \u0442\u0430\u043A\u0438\u043C \u043E\u0431\u0440\u0430\u0437\u043E\u043C, \u043C\u043D\u0435 \u043F\u0440\u0438\u0434\u0435\u0442\u0441\u044F \u043F\u0440\u043E\u0446\u0438\u0442\u0438\u0440\u043E\u0432\u0430\u0442\u044C \u043D\u0435\u043A\u043E\u0442\u043E\u0440\u044B\u0435 \u043E\u0431\u044A\u044F\u0441\u043D\u0435\u043D\u0438\u044F \u0438\u0437 \u043A\u043E\u043C\u043C\u0435\u043D\u0442\u0430\u0440\u0438\u044F, \u043D\u0430\u043F\u0438\u0441\u0430\u043D\u043D\u043E\u0433\u043E \u015Aivop\u0101dhy\u0101ya... \u0434\u0430, \u043C\u043D\u0435 \u043F\u0440\u0438\u0434\u0435\u0442\u0441\u044F \u043F\u0440\u043E\u0434\u043E\u043B\u0436\u0430\u0442\u044C \u043F\u0435\u0440\u0435\u0432\u043E\u0434\u0438\u0442\u044C. \u041D\u0430\u0447\u043D\u0435\u043C: &quot; \u0936\u0915\u094D\u0924\u093F\u0938\u0919\u094D\u0917\u092E\u0903 \u0938\u094D\u0924\u094D\u0930\u0940\u0938\u0919\u094D\u0917\u0938\u094D\u0924\u0947\u0928 \u0938\u0919\u094D\u0915\u094D\u0937\u0941\u092C\u094D\u0927\u0903 \u0938\u092E\u094D\u092A\u094D\u0930\u0935\u0943\u0924\u094D\u0924\u0903 \u0936\u0915\u094D\u0924\u094D\u092F\u093E\u0935\u0947\u0936 \u0906\u0928\u0928\u094D\u0926\u0936\u0915\u094D\u0924\u093F\u0938\u092E\u093E\u0935\u0947\u0936\u0938\u094D\u0924\u0926\u093E\u0935\u0938\u093E\u0928\u093F\u0915\u0902 \u0924\u0924\u094D\u092A\u093E\u0930\u094D\u092F\u0928\u094D\u0924\u093F\u0915\u092E\u094D\u0964 &quot; - &quot;\u015Aaktisa\u1E45gama\u1E25 str\u012Bsa\u1E45gastena sa\u1E45k\u1E63ubdha\u1E25 samprav\u1E5Btta\u1E25 \u015Bakty\u0101ve\u015Ba \u0101nanda\u015Baktisam\u0101ve\u015Bastad\u0101vas\u0101nika\u1E41 tatp\u0101ryantikam|&quot; - &quot;&#39;\u015Aaktisa\u1E45gama&#39; [\u043E\u0437\u043D\u0430\u0447\u0430\u0435\u0442] &#39;\u043F\u043E\u043B\u043E\u0432\u043E\u0439 \u0430\u043A\u0442 \u0441 \u0436\u0435\u043D\u0449\u0438\u043D\u043E\u0439&#39;; &#39;sa\u1E45k\u1E63ubdha&#39; [\u2014 \u044D\u0442\u043E] &#39;\u0442\u043E, \u0447\u0442\u043E \u043F\u043E\u0440\u043E\u0436\u0434\u0430\u0435\u0442\u0441\u044F \u044D\u0442\u0438\u043C [\u043F\u043E\u043B\u043E\u0432\u044B\u043C \u0430\u043A\u0442\u043E\u043C]&#39;; &#39;\u015Bakty\u0101ve\u015Ba&#39; [\u043E\u0442\u043D\u043E\u0441\u0438\u0442\u0441\u044F \u043A] &#39;\u0440\u0430\u0441\u0442\u0432\u043E\u0440\u0435\u043D\u0438\u044E \u0432 \u0421\u0438\u043B\u0435 \u0411\u043B\u0430\u0436\u0435\u043D\u0441\u0442\u0432\u0430 --\u0442.\u0435. \u015Aakti--&#39;; [\u0438] &#39;tad\u0101vas\u0101nika&#39; [\u0443\u043A\u0430\u0437\u044B\u0432\u0430\u0435\u0442] &#39;\u043D\u0430 \u043A\u043E\u043D\u0435\u0446 \u044D\u0442\u043E\u0433\u043E [\u0440\u0430\u0441\u0442\u0432\u043E\u0440\u0435\u043D\u0438\u044F]&#39;&quot;. \u041F\u043E\u0441\u043B\u0435 \u044D\u0442\u043E\u0433\u043E, \u0441\u0432\u044F\u0442\u043E\u0439 \u043E\u0431\u044A\u044F\u0441\u043D\u044F\u0435\u0442 \u0441\u043B\u0435\u0434\u0443\u044E\u0449\u0435\u0435: &quot; ... \u092C\u094D\u0930\u0939\u094D\u092E\u0924\u0924\u094D\u0924\u094D\u0935\u0938\u094D\u092F \u0938\u0941\u0916\u0902 \u092A\u0930\u092C\u094D\u0930\u0939\u094D\u092E\u093E\u0928\u0928\u094D\u0926\u0938\u094D... &quot; - &quot;... brahmatattvasya sukha\u1E41 parabrahm\u0101nandas...&quot; - &quot;... \u0432\u043E\u0441\u0442\u043E\u0440\u0433 Brahmatattva, \u0442.\u0435. \u041D\u0430\u0441\u043B\u0430\u0436\u0434\u0435\u043D\u0438\u0435 \u0412\u044B\u0441\u0448\u0438\u043C \u0411\u0440\u0430\u0445\u043C\u043E\u0439 --\u0410\u0431\u0441\u043E\u043B\u044E\u0442\u043E\u043C--&quot;, \u0438 \u0432 \u0437\u0430\u043A\u043B\u044E\u0447\u0435\u043D\u0438\u0438 &quot; ... \u0924\u0924\u094D\u0938\u0941\u0916\u0902 \u0938\u094D\u0935\u0915\u092E\u0947\u0935 \u0938\u094D\u0935\u093E\u0915\u094D\u092F\u092E\u094D... \u0906\u0924\u094D\u092E\u0928 \u090F\u0935 \u0938\u092E\u094D\u092C\u0928\u094D\u0927\u093F... &quot; - &quot;... tatsukha\u1E41 svakameva sv\u0101kyam... \u0101tmana eva sambandhi...&quot; - &quot;... \u043D\u0430\u0441\u043B\u0430\u0436\u0434\u0435\u043D\u0438\u0435 [\u0435\u0441\u0442\u044C] &#39;sv\u0101kya&#39;, \u0438\u043B\u0438 &#39;\u0441\u0432\u043E\u0435 \u0441\u043E\u0431\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u0435&#39;, [\u043A\u043E\u0440\u043E\u0447\u0435 \u0433\u043E\u0432\u043E\u0440\u044F,] \u043E\u0442\u043D\u043E\u0441\u044F\u0449\u0435\u0435\u0441\u044F \u0438\u0441\u043A\u043B\u044E\u0447\u0438\u0442\u0435\u043B\u044C\u043D\u043E \u043A \u0441\u0432\u043E\u0435\u0439 \u0441\u043E\u0431\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u0439 \u0421\u0430\u043C\u043E\u0441\u0442\u0438...&quot;, \u0430 \u0438\u043C\u0435\u043D\u043D\u043E, \u0442\u043E\u043B\u044C\u043A\u043E \u0442\u044B \u0441\u0430\u043C &quot;\u0432\u0441\u0435\u0433\u0434\u0430&quot; \u044F\u0432\u043B\u044F\u0435\u0448\u044C\u0441\u044F \u0438\u0441\u0442\u043E\u0447\u043D\u0438\u043A\u043E\u043C \u044D\u0442\u043E\u0433\u043E \u0432\u043E\u0441\u0442\u043E\u0440\u0433\u0430.</p><p>\u041E\u0434\u043D\u0430\u043A\u043E, \u043C\u0443\u0434\u0440\u0435\u0446 \u0446\u0438\u0442\u0438\u0440\u0443\u0435\u0442 \u0441\u0442\u0440\u043E\u0444\u0443 \u043D\u0430 \u0432\u0441\u044F\u043A\u0438\u0439 \u0441\u043B\u0443\u0447\u0430\u0439, \u0435\u0441\u043B\u0438 \u043A\u0442\u043E-\u0442\u043E \u043C\u043E\u0436\u0435 \u043D\u0435\u043F\u0440\u0430\u0432\u0438\u043B\u044C\u043D\u043E \u043F\u043E\u043D\u044F\u0442\u044C \u0443\u0447\u0435\u043D\u0438\u0435:</p><blockquote><p>&quot;\u091C\u093E\u092F\u092F\u093E \u0938\u092E\u094D\u092A\u0930\u093F\u0937\u094D\u0935\u0915\u094D\u0924\u094B \u0928 \u092C\u093E\u0939\u094D\u092F\u0902 \u0935\u0947\u0926 \u0928\u093E\u0928\u094D\u0924\u0930\u092E\u094D\u0964<br> \u0928\u093F\u0926\u0930\u094D\u0936\u0928\u0902 \u0936\u094D\u0930\u0941\u0924\u093F\u0903 \u092A\u094D\u0930\u093E\u0939 \u092E\u0942\u0930\u094D\u0916\u0938\u094D\u0924\u0902 \u092E\u0928\u094D\u092F\u0924\u0947 \u0935\u093F\u0927\u093F\u092E\u094D\u0965&quot; -</p></blockquote><blockquote><p>&quot;J\u0101yay\u0101 sampari\u1E63vakto na b\u0101hya\u1E41 veda n\u0101ntaram|<br> Nidar\u015Bana\u1E41 \u015Bruti\u1E25 pr\u0101ha m\u016Brkhasta\u1E41 manyate vidhim||&quot; -</p></blockquote><blockquote><p>&quot;\u041A\u043E\u0433\u0434\u0430 \u0447\u0435\u043B\u043E\u0432\u0435\u043A \u0442\u0435\u0441\u043D\u043E \u043E\u0431\u043D\u0438\u043C\u0430\u0435\u0442\u0441\u044F \u0441 \u0436\u0435\u043D\u0449\u0438\u043D\u043E\u0439, \u043E\u043D \u0437\u043D\u0430\u0435\u0442/\u043E\u0449\u0443\u0449\u0430\u0435\u0442 \u043D\u0438 \u0441\u043D\u0430\u0440\u0443\u0436\u0438 \u0438 \u043D\u0438 \u0432\u043D\u0443\u0442\u0440\u0438 --\u044D\u0442\u043E \u043F\u043E\u043B\u043D\u043E\u0435 \u0435\u0434\u0438\u043D\u0441\u0442\u0432\u043E--. \u0412\u0435\u0434\u0438\u0447\u0435\u0441\u043A\u043E\u0435 \u041F\u0438\u0441\u0430\u043D\u0438\u0435 \u0443\u043F\u043E\u043C\u0438\u043D\u0430\u0435\u0442 [\u044D\u0442\u043E \u043A\u0430\u043A] \u043F\u0440\u0438\u043C\u0435\u0440 \u0438\u043B\u0438 \u0438\u043B\u043B\u044E\u0441\u0442\u0440\u0430\u0446\u0438\u044E. [\u0422\u043E\u043B\u044C\u043A\u043E] \u0433\u043B\u0443\u043F\u0435\u0446 \u0440\u0430\u0441\u0446\u0435\u043D\u0438\u0432\u0430\u0435\u0442 \u044D\u0442\u043E \u043A\u0430\u043A \u0437\u0430\u043F\u0440\u0435\u0442 [\u0434\u043B\u044F \u043F\u0440\u043E\u0441\u0442\u043E\u0433\u043E \u043F\u043B\u043E\u0442\u0441\u043A\u043E\u0433\u043E \u0443\u0434\u043E\u0432\u043E\u043B\u044C\u0441\u0442\u0432\u0438\u044F]&quot;.</p></blockquote><p>\u0422\u043E\u0433\u0434\u0430 \u043D\u0435 \u0431\u0443\u0434\u044C \u0433\u043B\u0443\u043F\u044B\u043C \u0438 \u0440\u0430\u0441\u0441\u043C\u0430\u0442\u0440\u0438\u0432\u0430\u0439 \u044D\u0442\u0443 \u0430\u043D\u0430\u043B\u043E\u0433\u0438\u044E \u0432 \u043A\u0430\u0447\u0435\u0441\u0442\u0432\u0435 \u043F\u0440\u0438\u043C\u0435\u0440\u0430 \u0442\u043E\u0433\u043E, \u043A\u0430\u043A \u0432\u043E \u0432\u0440\u0435\u043C\u044F \u043F\u043E\u043B\u043E\u0432\u043E\u0433\u043E \u0430\u043A\u0442\u0430 \u0441 \u0436\u0435\u043D\u0449\u0438\u043D\u043E\u0439 \u0411\u043B\u0430\u0436\u0435\u043D\u0441\u0442\u0432\u043E \u0413\u043E\u0441\u043F\u043E\u0434\u0430 \u043F\u0440\u043E\u0441\u0430\u0447\u0438\u0432\u0430\u0435\u0442\u0441\u044F \u0441\u043A\u0432\u043E\u0437\u044C \u0441\u0435\u0442\u044C, \u0441\u043E\u0437\u0434\u0430\u043D\u043D\u0443\u044E \u0415\u0433\u043E \u0441\u043E\u0431\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u0439 m\u0101y\u0101\u015Bakti. \u041E\u0431\u044B\u0447\u043D\u043E\u0435 \u0441\u043E\u0438\u0442\u0438\u0435 \u0441 \u0436\u0435\u043D\u0449\u0438\u043D\u043E\u0439 \u043D\u0435 \u043E\u0436\u0438\u0432\u043E\u0442\u0432\u043E\u0440\u044F\u0435\u0442 \u0442\u0435\u0431\u044F, \u0430 \u0434\u0435\u043B\u0430\u0435\u0442 \u0442\u0432\u043E\u0435 \u0442\u0435\u043B\u043E/\u0443\u043C \u0443\u0441\u0442\u0430\u0432\u0448\u0438\u043C \u0438 \u0442\u0443\u043F\u044B\u043C. \u0427\u0442\u043E\u0431\u044B \u0438\u0441\u043F\u044B\u0442\u0430\u0442\u044C \u043E\u0436\u0438\u0432\u043E\u0442\u0432\u043E\u0440\u0435\u043D\u0438\u0435 \u0447\u0435\u0440\u0435\u0437 \u043F\u043E\u043B\u043E\u0432\u043E\u0439 \u0430\u043A\u0442 \u0441 \u0436\u0435\u043D\u0449\u0438\u043D\u043E\u0439, \u043D\u0435\u043E\u0431\u0445\u043E\u0434\u0438\u043C\u043E \u0431\u044B\u0442\u044C \u043C\u043E\u0449\u043D\u044B\u043C Yog\u012B, \u043D\u0430\u0434\u0435\u043B\u0435\u043D\u043D\u044B\u043C \u0431\u043E\u043B\u044C\u0448\u0438\u043C \u043A\u043E\u043B\u0438\u0447\u0435\u0441\u0442\u0432\u043E\u043C \u043D\u0443\u0436\u043D\u044B\u0445 \u0437\u043D\u0430\u043D\u0438\u0439 \u043E \u0442\u043E\u043C, \u0447\u0435\u043C, \u043D\u0430 \u0441\u0430\u043C\u043E\u043C \u0434\u0435\u043B\u0435, \u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F \u0436\u0435\u043D\u0449\u0438\u043D\u0430 \u043F\u043E \u043E\u0442\u043D\u043E\u0448\u0435\u043D\u0438\u044E \u043A \u043C\u0443\u0436\u0447\u0438\u043D\u0435. \u041D\u043E \u0431\u043E\u043B\u044C\u0448\u0438\u043D\u0441\u0442\u0432\u043E \u043C\u0443\u0436\u0447\u0438\u043D \u0432\u043E\u043E\u0431\u0449\u0435 \u043D\u0435 \u043E\u0431\u043B\u0430\u0434\u0430\u044E\u0442 \u043F\u043E\u0434\u043E\u0431\u043D\u044B\u043C \u0442\u0438\u043F\u043E\u043C \u0437\u043D\u0430\u043D\u0438\u044F \u0438 \u0441\u0438\u043B\u044B, \u0438\u043C \u043D\u0435 \u0440\u0435\u043A\u043E\u043C\u0435\u043D\u0434\u0443\u0435\u0442\u0441\u044F \u0438\u0441\u043A\u0430\u0442\u044C \u0411\u043B\u0430\u0436\u0435\u043D\u0441\u0442\u0432\u043E \u0422\u0443\u0440\u044C\u0438 \u0447\u0435\u0440\u0435\u0437 \u043F\u0440\u043E\u0441\u0442\u043E\u0439 \u043F\u043E\u043B\u043E\u0432\u043E\u0439 \u0430\u043A\u0442 \u0441 \u0436\u0435\u043D\u0449\u0438\u043D\u043E\u0439. \u0411\u0435\u0437\u0443\u0441\u043B\u043E\u0432\u043D\u043E, \u044D\u0442\u043E \u0436\u0435 \u043E\u0442\u043D\u043E\u0441\u0438\u0442\u0441\u044F \u0438 \u043A \u0436\u0435\u043D\u0449\u0438\u043D\u0430\u043C. \u041B\u044E\u0431\u043E\u0439 \u0447\u0435\u043B\u043E\u0432\u0435\u043A, \u044F\u0432\u043B\u044F\u044E\u0449\u0438\u0439\u0441\u044F \u0421\u0430\u043A\u0430\u043B\u043E\u0439, \u0438\u043B\u0438 \u0442\u0435\u043C, \u043A\u0442\u043E \u043F\u043E\u043B\u043D\u043E\u0441\u0442\u044C\u044E \u043E\u0442\u043E\u0436\u0434\u0435\u0441\u0442\u0432\u043B\u0435\u043D \u0441\u043E \u0441\u0432\u043E\u0438\u043C \u0444\u0438\u0437\u0438\u0447\u0435\u0441\u043A\u0438\u043C \u0442\u0435\u043B\u043E\u043C \u0438 \u0443\u043C\u043E\u043C/\u044D\u0433\u043E/\u0438\u043D\u0442\u0435\u043B\u043B\u0435\u043A\u0442\u043E\u043C, \u043D\u0435 \u043C\u043E\u0436\u0435\u0442 \u043F\u043E\u043B\u0443\u0447\u0438\u0442\u044C &quot;\u043F\u043E\u043B\u043D\u043E\u0435&quot; \u041D\u0430\u0441\u043B\u0430\u0436\u0434\u0435\u043D\u0438\u0435 \u0411\u0440\u0430\u0445\u043C\u044B, \u0437\u0430\u043D\u0438\u043C\u0430\u044F\u0441\u044C \u0441\u0435\u043A\u0441\u043E\u043C, \u0430 &quot;\u0442\u043E\u043B\u044C\u043A\u043E&quot; \u0435\u0433\u043E \u043A\u0430\u043F\u043B\u044E, \u043A\u043E\u0442\u043E\u0440\u0430\u044F \u043F\u0440\u043E\u0441\u0430\u0447\u0438\u0432\u0430\u0435\u0442\u0441\u044F \u0447\u0435\u0440\u0435\u0437 \u043D\u0435\u0433\u043E.</p><p>\u0411\u043E\u043B\u044C\u0448\u0435 \u0430\u043D\u0430\u043B\u043E\u0433\u0438\u0439 \u0431\u0443\u0434\u0435\u0442 \u0434\u0430\u043D\u043E \u0447\u0435\u0440\u0435\u0437 \u0434\u0440\u0443\u0433\u0438\u0435 \u0441\u0442\u0440\u043E\u0444\u044B, \u0438\u0437\u0432\u043B\u0435\u0447\u0435\u043D\u043D\u044B\u0435 \u0438\u0437 Vij\xF1\u0101nabhairava. OK, \u0442\u0435\u043F\u0435\u0440\u044C \u0432\u0441\u0435 \u0434\u043E\u043B\u0436\u043D\u043E \u0431\u044B\u0442\u044C \u0441\u043E\u0432\u0435\u0440\u0448\u0435\u043D\u043D\u043E \u044F\u0441\u043D\u043E.</p></li><li><p>\u0414\u043E\u0433\u0430\u0434\u0430\u0439\u0441\u044F \u0447\u0442\u043E? \u0414\u0440\u0443\u0433\u0430\u044F \u0445\u0438\u0442\u0440\u0430\u044F \u0441\u0442\u0440\u043E\u0444\u0430 \u0438\u0437 Vij\xF1\u0101nabhairava. \u042F \u0432\u043E\u043E\u0431\u0449\u0435 \u043D\u0435 \u0440\u0435\u043A\u043E\u043C\u0435\u043D\u0434\u0443\u044E \u044D\u0442\u0443 \u0441\u0442\u0440\u043E\u0444\u0443 \u0434\u043B\u044F \u043D\u043E\u0432\u0438\u0447\u043A\u043E\u0432 \u0432 \u0441\u0430\u043D\u0441\u043A\u0440\u0438\u0442\u0435. \u042D\u0442\u043E \u0442\u043E\u043B\u044C\u043A\u043E \u0434\u043B\u044F \u043F\u0440\u043E\u0434\u0432\u0438\u043D\u0443\u0442\u044B\u0445 \u043F\u0435\u0440\u0435\u0432\u043E\u0434\u0447\u0438\u043A\u043E\u0432, \u043A\u043E\u0442\u043E\u0440\u044B\u0435 \u0441\u043F\u043E\u0441\u043E\u0431\u043D\u044B \u0447\u0438\u0442\u0430\u0442\u044C \u0441\u043E\u043E\u0442\u0432\u0435\u0442\u0441\u0442\u0432\u0443\u044E\u0449\u0438\u0435 \u043A\u043E\u043C\u043C\u0435\u043D\u0442\u0430\u0440\u0438\u0438, \u043D\u0430\u043F\u0438\u0441\u0430\u043D\u043D\u044B\u0435 \u0447\u0430\u0441\u0442\u0438\u0447\u043D\u043E K\u1E63emar\u0101ja \u0438 \u0447\u0430\u0441\u0442\u0438\u0447\u043D\u043E \u015Aivop\u0101dhy\u0101ya. \u0418\u043C\u0435\u0435\u0435\u0442\u0441\u044F \u0435\u0449\u0435 \u0434\u0440\u0443\u0433\u043E\u0439 \u043A\u043E\u043C\u043C\u0435\u043D\u0442\u0430\u0440\u0438\u0439, \u043D\u0430\u0437\u044B\u0432\u0430\u0435\u043C\u044B\u0439 Vij\xF1\u0101nakaumud\u012B, \u043D\u0430\u043F\u0438\u0441\u0430\u043D\u043D\u044B\u0439 \u0100nandabha\u1E6D\u1E6Da. \u0415\u0441\u043B\u0438 \u0432\u044B \u043F\u043E\u043B\u0443\u0447\u0438\u0442\u0435 \u0438\u0445 \u043E\u0431\u0430, \u043D\u0430\u0434\u043E \u0431\u044B\u0442\u044C \u043E\u0441\u0442\u043E\u0440\u043E\u0436\u043D\u044B\u043C \u0441 \u043D\u043E\u043C\u0435\u0440\u0430\u043C\u0438 \u0441\u0442\u0440\u043E\u0444, \u043F\u043E\u0441\u043A\u043E\u043B\u044C\u043A\u0443 \u043E\u043D\u0438 \u0432\u0441\u0435 \u0432\u0440\u0435\u043C\u044F \u043D\u0435 \u0441\u043E\u0432\u043F\u0430\u0434\u0430\u044E\u0442 \u0434\u0440\u0443\u0433 \u0441 \u0434\u0440\u0443\u0433\u043E\u043C (\u043D\u0430\u043F\u0440\u0438\u043C\u0435\u0440, \u0441\u0442\u0440\u043E\u0444\u0430 70, \u043A\u043E\u0442\u043E\u0440\u0443\u044E \u044F \u0441\u0435\u0439\u0447\u0430\u0441 \u043E\u0431\u044A\u044F\u0441\u043D\u044F\u044E, \u0441\u043E\u0433\u043B\u0430\u0441\u043D\u043E \u043F\u0435\u0440\u0432\u043E\u043C\u0443 \u043A\u043E\u043C\u043C\u0435\u043D\u0442\u0430\u0440\u0438\u044E, \u0432 Vij\xF1\u0101nakaumud\u012B \u043D\u0430\u0445\u043E\u0434\u0438\u0442\u0441\u044F \u043F\u043E\u0434 \u043D\u043E\u043C\u0435\u0440\u043E\u043C 69!). \u041D\u0443 \u0445\u043E\u0440\u043E\u0448\u043E, \u044F \u0431\u0443\u0434\u0443 \u0438\u0441\u043F\u043E\u043B\u044C\u0437\u043E\u0432\u0430\u0442\u044C \u043A\u043E\u043C\u043C\u0435\u043D\u0442\u0430\u0440\u0438\u0439, \u043D\u0430\u043F\u0438\u0441\u0430\u043D\u043D\u044B\u0439 \u0447\u0430\u0441\u0442\u0438\u0447\u043D\u043E K\u1E63emar\u0101ja \u0438 \u0447\u0430\u0441\u0442\u0438\u0447\u043D\u043E \u015Aivop\u0101dhy\u0101ya, \u0447\u0442\u043E\u0431\u044B \u0440\u0430\u0441\u0441\u0435\u044F\u0442\u044C \u0432\u0441\u0435 \u0441\u043E\u043C\u043D\u0435\u043D\u0438\u044F \u0438 \u043D\u0435\u0434\u043E\u043F\u043E\u043D\u0438\u043C\u0430\u043D\u0438\u0435 \u043E\u0442\u043D\u043E\u0441\u0438\u0442\u0435\u043B\u044C\u043D\u043E \u0437\u043D\u0430\u0447\u0435\u043D\u0438\u044F \u043E\u043F\u0440\u0435\u0434\u0435\u043B\u0435\u043D\u043D\u044B\u0445 \u0442\u0435\u0440\u043C\u0438\u043D\u043E\u0432:</p><p>&quot;\u0932\u0947\u0939\u0928\u0902 \u0935\u0915\u094D\u0924\u094D\u0930\u093E\u0938\u0935\u093E\u0938\u094D\u0935\u093E\u0926\u0928\u0902 \u092A\u0930\u093F\u091A\u0941\u092E\u094D\u092C\u0928\u092E\u093F\u0924\u093F \u092F\u093E\u0935\u0924\u094D\u0964 \u0906\u092E\u0928\u094D\u0925\u0928\u0902 \u092A\u094D\u0930\u0927\u093E\u0928\u093E\u0919\u094D\u0917\u0935\u093F\u0932\u094B\u0921\u0928\u092E\u093E\u0932\u093F\u0919\u094D\u0917\u0928\u0902 \u0935\u093E\u0964 \u0906\u0915\u094B\u091F\u0903 \u092A\u0941\u0928\u0903\u092A\u0941\u0928\u0930\u094D\u092E\u0930\u094D\u0926\u0928\u0902 \u0928\u0916\u0915\u094D\u0937\u0924\u093E\u0926\u093F\u0930\u094D\u0935\u093E\u0964&quot; - &quot;Lehana\u1E41 vaktr\u0101sav\u0101sv\u0101dana\u1E41 paricumbanamiti y\u0101vat| \u0100manthana\u1E41 pradh\u0101n\u0101\u1E45gavilo\u1E0Danam\u0101li\u1E45gana\u1E41 v\u0101| \u0100ko\u1E6Da\u1E25 puna\u1E25punarmardana\u1E41 nakhak\u1E63at\u0101dirv\u0101|&quot; - &quot;[\u0422\u0435\u0440\u043C\u0438\u043D] &#39;lehana&#39; [\u0431\u0443\u043A\u0432\u0430\u043B\u044C\u043D\u043E \u043E\u0437\u043D\u0430\u0447\u0430\u0435\u0442] &#39;\u0432\u043A\u0443\u0448\u0435\u043D\u0438\u0435 \u043D\u0435\u043A\u0442\u0430\u0440\u0430, \u0438\u043B\u0438 \u0441\u043E\u043A\u0430 \u0433\u0443\u0431 \u0436\u0435\u043D\u0449\u0438\u043D\u044B [\u0441\u0432\u043E\u0438\u043C \u0441\u043E\u0431\u0441\u0442\u0432\u0435\u043D\u043D\u044B\u043C] \u0440\u0442\u043E\u043C&#39;, \u0442.\u0435. &#39;\u043A\u0440\u0435\u043F\u043A\u0438\u0439 \u043F\u043E\u0446\u0435\u043B\u0443\u0439&#39; --\u043F\u0440\u0438\u0441\u0442\u0430\u0432\u043A\u0430 &#39;pari&#39; \u0443\u0441\u0438\u043B\u0438\u0432\u0430\u0435\u0442 \u043A\u043E\u0440\u0435\u043D\u044C &#39;cumb&#39;, &#39;\u0446\u0435\u043B\u043E\u0432\u0430\u0442\u044C&#39;, \u0441\u043B\u0435\u0434\u043E\u0432\u0430\u0442\u0435\u043B\u044C\u043D\u043E \u044D\u0442\u043E &#39;\u043A\u0440\u0435\u043F\u043A\u043E&#39; \u0434\u043E\u0431\u0430\u0432\u043B\u044F\u0435\u0442\u0441\u044F \u043A \u0432\u044B\u0440\u0430\u0436\u0435\u043D\u0438\u044E--; \u0442\u0430\u043A\u043E\u0432\u043E \u0437\u043D\u0430\u0447\u0435\u043D\u0438\u0435. [\u0421 \u0434\u0440\u0443\u0433\u043E\u0439 \u0441\u0442\u043E\u0440\u043E\u043D\u044B,] &#39;\u0101manthana&#39; [\u2014 \u044D\u0442\u043E] &#39;\u0441\u043C\u0435\u0448\u0438\u0432\u0430\u043D\u0438\u0435 \u0441 \u043E\u0441\u043D\u043E\u0432\u043D\u044B\u043C\u0438 \u0447\u0430\u0441\u0442\u044F\u043C\u0438 \u0442\u0435\u043B\u0430&#39;, \u0438\u043B\u0438 &#39;\u043E\u0431\u043D\u0438\u043C\u0430\u043D\u0438\u0435&#39;. [\u0418] &#39;\u0101ko\u1E6Da&#39; [\u0443\u043A\u0430\u0437\u044B\u0432\u0430\u0435\u0442 \u043D\u0430] &#39;\u043D\u0430\u0434\u0430\u0432\u043B\u0438\u0432\u0430\u043D\u0438\u0435 \u0441\u043D\u043E\u0432\u0430 \u0438 \u0441\u043D\u043E\u0432\u0430&#39;, \u0438\u043B\u0438 &#39;\u0446\u0430\u0440\u0430\u043F\u0430\u043D\u0438\u0435 \u043D\u043E\u0433\u0442\u044F\u043C\u0438, \u0438 \u0442.\u0434.&#39;&quot;.</p><p>\u0410\u0445, \u044D\u0442\u043E \u0431\u044B\u043B\u043E \u043A\u0440\u0443\u0442\u043E! \u0422\u0435\u043F\u0435\u0440\u044C \u0432\u0430\u043C \u043F\u043E\u043B\u043D\u043E\u0441\u0442\u044C\u044E \u043F\u043E\u043D\u044F\u0442\u043D\u043E, \u0447\u0442\u043E \u043E\u0437\u043D\u0430\u0447\u0430\u044E\u0442 \u0442\u0435\u0440\u043C\u0438\u043D\u044B. \u041A\u0430\u043A \u0432\u0438\u0434\u043D\u043E, \u0445\u043E\u0440\u043E\u0448\u0435\u0433\u043E \u0441\u043B\u043E\u0432\u0430\u0440\u044F \u0441\u0430\u043D\u0441\u043A\u0440\u0438\u0442\u0430 \u043D\u0435 \u0434\u043E\u0441\u0442\u0430\u0442\u043E\u0447\u043D\u043E \u0434\u043B\u044F \u0440\u0430\u0441\u0448\u0438\u0444\u0440\u043E\u0432\u043A\u0438 \u0441\u0442\u0440\u043E\u0444\u044B. \u042D\u0442\u043E \u0434\u043E\u0432\u043E\u043B\u044C\u043D\u043E \u0440\u0430\u0441\u043F\u0440\u043E\u0441\u0442\u0440\u0430\u043D\u0435\u043D\u043E \u0432 \u0441\u043B\u0443\u0447\u0430\u0435 \u043F\u043E\u0434\u0430\u0432\u043B\u044F\u044E\u0449\u0435\u0433\u043E \u0431\u043E\u043B\u044C\u0448\u0438\u043D\u0441\u0442\u0432\u0430 \u0441\u0430\u043D\u0441\u043A\u0440\u0438\u0442\u0441\u043A\u0438\u0445 \u041F\u0438\u0441\u0430\u043D\u0438\u0439, \u0438\u043C\u0435\u044E\u0449\u0438\u0445 \u0434\u0435\u043B\u043E \u0441 \u0433\u043B\u0443\u0431\u043E\u043A\u043E\u0439 \u0444\u0438\u043B\u043E\u0441\u043E\u0444\u0438\u0435\u0439, \u043D\u043E \u043D\u0435\u043A\u043E\u0442\u043E\u0440\u044B\u0435 \u0438\u0437 \u043D\u0438\u0445 \u043E\u0441\u043E\u0431\u0435\u043D\u043D\u043E \u0442\u0440\u0443\u0434\u043D\u043E \u043F\u0435\u0440\u0435\u0432\u043E\u0434\u0438\u0442\u044C \u043F\u0440\u0430\u0432\u0438\u043B\u044C\u043D\u043E \u0431\u0435\u0437 \u0441\u043F\u0435\u0446\u0438\u0430\u043B\u044C\u043D\u043E\u0439 \u043F\u043E\u043C\u043E\u0449\u0438, \u0442\u0430\u043A\u0438\u0435 \u043A\u0430\u043A Vij\xF1\u0101nabhairava, Svacchandatantra \u0438 M\u0101lin\u012Bvijayatantra. \u0411\u0435\u0437 \u043F\u043E\u043C\u043E\u0449\u0438 \u0441\u043E\u0441\u043E\u0442\u0432\u0435\u0442\u0441\u0442\u0432\u0443\u044E\u0449\u0438\u0445 \u043A\u043E\u043C\u043C\u0435\u043D\u0442\u0430\u0440\u0438\u0435\u0432, \u043D\u0430\u043F\u0438\u0441\u0430\u043D\u043D\u044B\u0445 \u043F\u0440\u0435\u0432\u043E\u0441\u0445\u043E\u0434\u043D\u044B\u043C\u0438 \u0443\u0447\u0435\u043D\u044B\u043C\u0438 \u0438 \u043C\u0430\u0441\u0442\u0435\u0440\u0430\u043C\u0438, \u043D\u0435\u0432\u043E\u0437\u043C\u043E\u0436\u043D\u043E \u0434\u0430\u0436\u0435 \u043F\u0440\u0430\u0432\u0438\u043B\u044C\u043D\u043E \u043D\u0430\u0447\u0430\u0442\u044C \u0438\u0445 \u043F\u0435\u0440\u0435\u0432\u043E\u0434. \u0418 \u043E\u0447\u0435\u043D\u044C \u0447\u0430\u0441\u0442\u043E \u0434\u043B\u044F \u043F\u043E\u043D\u0438\u043C\u0430\u043D\u0438\u044F \u043A\u043E\u043C\u043C\u0435\u043D\u0442\u0430\u0440\u0438\u044F \u0442\u0440\u0435\u0431\u0443\u0435\u0442\u0441\u044F \u0431\u043E\u043B\u044C\u0448\u0435 \u0432\u0440\u0435\u043C\u0435\u043D\u0438, \u0447\u0435\u043C \u0434\u043B\u044F \u0441\u0430\u043C\u043E\u0433\u043E \u041F\u0438\u0441\u0430\u043D\u0438\u044F (\u043A\u0440\u043E\u043C\u0435 \u0448\u0443\u0442\u043E\u043A). \u0412 \u0446\u0435\u043B\u043E\u043C, \u0432\u0430\u0448\u0438 \u0441\u0430\u043D\u0441\u043A\u0440\u0438\u0442\u0441\u043A\u0438\u0435 \u0437\u043D\u0430\u043D\u0438\u044F, \u0442\u0430\u043A\u0436\u0435 \u043A\u0430\u043A \u0438 \u0444\u0438\u043B\u043E\u0441\u043E\u0444\u0441\u043A\u0438\u0435, \u0434\u043E\u043B\u0436\u043D\u044B \u0431\u044B\u0442\u044C \u0434\u043E\u0441\u0442\u0430\u0442\u043E\u0447\u043D\u043E \u0441\u0435\u0440\u044C\u0435\u0437\u043D\u044B\u043C\u0438, \u0438\u043B\u0438 \u0432\u044B \u043F\u043E\u0442\u0435\u0440\u043F\u0438\u0442\u0435 \u043A\u0440\u0430\u0445, \u0435\u0441\u043B\u0438 \u0432\u043E\u0437\u044C\u043C\u0435\u0442\u0435\u0441\u044C \u0437\u0430 \u043F\u0435\u0440\u0435\u0432\u043E\u0434 \u043C\u043E\u043D\u0443\u043C\u0435\u043D\u0442\u0430\u043B\u044C\u043D\u044B\u0445 \u041F\u0438\u0441\u0430\u043D\u0438\u0439, \u043F\u043E\u0434\u043E\u0431\u043D\u044B\u0445 \u0442\u0435\u043C, \u0447\u0442\u043E \u044F \u043F\u0440\u0438\u043C\u0435\u043B \u0432 \u043A\u0430\u0447\u0435\u0441\u0442\u0432\u0435 \u043F\u0440\u0438\u043C\u0435\u0440\u0430.</p></li><li><p>\u041D\u0443, \u043C\u043D\u0435 \u043D\u0435\u043E\u0431\u0445\u043E\u0434\u0438\u043C\u043E \u0441\u0434\u0435\u043B\u0430\u0442\u044C \u0434\u0432\u0430 \u043F\u043E\u044F\u0441\u043D\u0435\u043D\u0438\u044F: (1) \u0421\u043E\u0433\u043B\u0430\u0441\u043D\u043E \u0100nandabha\u1E6D\u1E6Da \u0432 \u0435\u0433\u043E Vij\xF1\u0101nakaumud\u012B: &quot; ... \u092C\u093E\u0928\u094D\u0927\u0935\u0947 \u0935\u093E \u0938\u0941\u0939\u0943\u0926\u093E\u0926\u094C \u091A\u093F\u0930\u0915\u093E\u0932\u093E\u0928\u0928\u094D\u0924\u0930\u0902... \u0926\u0943\u0937\u094D\u091F\u0947... &quot; - &quot;... b\u0101ndhave v\u0101 suh\u1E5Bd\u0101dau cirak\u0101l\u0101nantara\u1E41... d\u1E5B\u1E63\u1E6De...&quot; - &quot;... \u0438\u043B\u0438 \u043A\u043E\u0433\u0434\u0430 &#39;b\u0101ndhava&#39;, \u0430 \u0438\u043C\u0435\u043D\u043D\u043E &#39;suh\u1E5Bd&#39;, \u0438 \u0442.\u0434. \u0432\u0438\u0434\u0435\u0442\u044C\u0441\u044F \u043F\u043E\u0441\u043B\u0435 \u0434\u043E\u043B\u0433\u043E\u0433\u043E \u0432\u0440\u0435\u043C\u0435\u043D\u0438...&quot;. \u0421\u043B\u043E\u0432\u043E &quot;suh\u1E5Bd&quot; (\u0431\u0443\u043A\u0432. \u0434\u043E\u0431\u0440\u043E\u0441\u0435\u0440\u0434\u0435\u0447\u043D\u044B\u0439) \u043F\u043E\u0434\u0440\u0430\u0437\u0443\u043C\u0435\u0432\u0430\u0435\u0442 \u0447\u0435\u043B\u043E\u0432\u0435\u043A\u0430, \u043A\u043E\u0442\u043E\u0440\u043E\u0433\u043E \u043B\u044E\u0431\u0438\u0448\u044C. \u041E\u0447\u0435\u043D\u044C \u0447\u0430\u0441\u0442\u043E \u044D\u0442\u043E \u043F\u0435\u0440\u0435\u0432\u043E\u0434\u0438\u0442\u0441\u044F \u043A\u0430\u043A &quot;\u0434\u0440\u0443\u0433&quot;, \u043D\u043E \u0442\u0430\u043A\u0436\u0435 \u043E\u0437\u043D\u0430\u0447\u0430\u0435\u0442 &quot;\u0441\u043E\u044E\u0437\u043D\u0438\u043A&quot;. \u0418 \u0441\u043E\u0433\u043B\u0430\u0441\u043D\u043E \u043A\u043E\u043C\u043C\u0435\u043D\u0442\u0430\u0440\u0438\u044E K\u1E63emar\u0101ja \u0438 \u015Aivop\u0101dhy\u0101ya: &quot;... \u092C\u093E\u0928\u094D\u0927\u0935\u0947 \u092A\u0941\u0924\u094D\u0930\u092E\u093F\u0924\u094D\u0930\u093E\u0926\u094C...&quot; - &quot;... b\u0101ndhave putramitr\u0101dau...&quot;</p></li></ol><ul><li><p>&quot;... &#39;b\u0101ndhava&#39;, \u0431\u0443\u043A\u0432. \u0441\u044B\u043D, \u0434\u0440\u0443\u0433 \u0438 \u0442.\u043F...&quot;. \u0422\u0435\u043F\u0435\u0440\u044C \u0432\u0430\u043C \u043F\u043E\u043D\u044F\u0442\u043D\u043E, \u043F\u043E\u0447\u0435\u043C\u0443 \u044F \u043F\u0435\u0440\u0435\u0432\u0435\u043B \u0442\u0435\u0440\u043C\u0438\u043D &quot;b\u0101ndhava&quot; \u043A\u0430\u043A &quot;\u0440\u043E\u0434\u0441\u0442\u0432\u0435\u043D\u043D\u0438\u043A, \u0434\u0440\u0443\u0433 \u0438 \u0442.\u043F.&quot;.</p><p>(2) \u0412 \u043A\u043E\u043C\u043C\u0435\u043D\u0442\u0430\u0440\u0438\u0438, \u043D\u0430\u043F\u0438\u0441\u0430\u043D\u043D\u043E\u043C \u044D\u0442\u0438\u043C\u0438 \u0434\u0432\u0443\u043C\u044F \u043C\u0443\u0434\u0440\u0435\u0446\u0430\u043C\u0438 (K\u1E63emar\u0101ja \u0438 \u015Aivop\u0101dhy\u0101ya) \u0438 \u0442\u0430\u043A\u0436\u0435 \u0432 Vij\xF1\u0101nakaumud\u012B, \u0438\u043C\u0435\u0435\u0442\u0441\u044F \u0434\u0440\u0443\u0433\u043E\u0435 \u043F\u0440\u043E\u0447\u0442\u0435\u043D\u0438\u0435 \u0434\u043B\u044F \u043F\u043E\u0441\u043B\u0435\u0434\u043D\u0435\u0439 \u0441\u0442\u0440\u043E\u043A\u0438 \u0432 \u0441\u0442\u0440\u043E\u0444\u0435: &quot;\u0906\u0928\u0928\u094D\u0926\u092E\u0941\u0926\u094D\u0917\u0924\u0902 \u0927\u094D\u092F\u093E\u0924\u094D\u0935\u093E \u0924\u0932\u094D\u0932\u092F\u0938\u094D\u0924\u0928\u094D\u092E\u0928\u093E \u092D\u0935\u0947\u0924\u094D&quot; - &quot;\u0100nandamudgata\u1E41 dhy\u0101tv\u0101 tallayastanman\u0101 bhavet&quot; - &quot;\u0420\u0430\u0437\u043C\u044B\u0448\u043B\u044F\u044F \u043E \u0432\u043E\u0437\u043D\u0438\u043A\u0448\u0435\u0439 \u0440\u0430\u0434\u043E\u0441\u0442\u0438, \u0447\u0435\u043B\u043E\u0432\u0435\u043A \u0440\u0430\u0441\u0442\u0432\u043E\u0440\u044F\u0435\u0442\u0441\u044F \u0432 \u043D\u0435\u0439 --\u0432 \u044D\u0442\u043E\u0439 \u0440\u0430\u0434\u043E\u0441\u0442\u0438-- [\u0438] \u0435\u0433\u043E \u0443\u043C \u043F\u043E\u0433\u0440\u0443\u0436\u0430\u0435\u0442\u0441\u044F \u0432 \u043D\u0435\u0435 --\u0431\u0443\u043A\u0432\u0430\u043B\u044C\u043D\u043E, \u0447\u0435\u043B\u043E\u0432\u0435\u043A \u0441\u0442\u0430\u043D\u043E\u0432\u0438\u0442\u0441\u044F \u0442\u0435\u043C, \u0447\u0435\u0439 \u0443\u043C \u043F\u043E\u0433\u043B\u043E\u0449\u0451\u043D \u044D\u0442\u0438\u043C&#39;--&quot;.</p><p>\u042D\u0442\u043E \u0432\u0441\u0435!</p></li></ul><ol start="5"><li>\u0427\u0430\u0441\u0442\u044C &quot;Bh\u0101vayedbharit\u0101vasth\u0101\u1E41...&quot; \u0441\u0442\u0440\u043E\u0444\u044B \u0442\u0440\u0443\u0434\u043D\u0430 \u0434\u043B\u044F \u043F\u043E\u043D\u0438\u043C\u0430\u043D\u0438\u044F, \u043D\u043E, \u043A \u0441\u0447\u0430\u0441\u0442\u044C\u044E, \u043C\u0443\u0434\u0440\u0435\u0446 \u0100nandabha\u1E6D\u1E6Da \u043F\u0440\u043E\u043B\u0438\u0432\u0430\u0435\u0442 \u043C\u043D\u043E\u0433\u043E \u0441\u0432\u0435\u0442\u0430 \u043D\u0430 \u044D\u0442\u043E \u0432 \u0441\u0432\u043E\u0435\u0439 Vij\xF1\u0101nakaumud\u012B: &quot; ... \u0924\u0926\u0928\u0941\u092D\u0935\u0947\u0928\u093E\u0928\u0928\u094D\u0926\u092A\u0942\u0930\u094D\u0923\u0924\u094D\u0935\u093E\u0935\u0938\u094D\u0925\u093E\u092F\u093E\u0902 \u092D\u093E\u0935\u092F\u0924 \u090F\u0915\u093E\u0917\u094D\u0930\u091A\u093F\u0924\u094D\u0924\u0938\u094D\u092F \u092A\u0930\u092E\u093E\u0928\u0928\u094D\u0926\u092A\u094D\u0930\u093E\u092A\u094D\u0924\u093F\u0930\u094D... &quot; - &quot;... tadanubhaven\u0101nandap\u016Br\u1E47atv\u0101vasth\u0101y\u0101\u1E41 bh\u0101vayata ek\u0101gracittasya param\u0101nandapr\u0101ptir...&quot;</li></ol><ul><li><p>&quot;\u0411\u043B\u0430\u0433\u043E\u0434\u0430\u0440\u044F \u043F\u0435\u0440\u0435\u0436\u0438\u0432\u0430\u043D\u0438\u044E \u044D\u0442\u043E\u0433\u043E \u0443\u0434\u043E\u0432\u043E\u043B\u044C\u0441\u0442\u0432\u0438\u044F [\u0441\u0432\u044F\u0437\u0430\u043D\u043D\u043E\u0433\u043E \u0441\u043E \u0432\u043A\u0443\u0441\u043E\u043C], \u043C\u043E\u0436\u043D\u043E \u0434\u043E\u0441\u0442\u0438\u0447\u044C \u0432\u044B\u0441\u0448\u0435\u0433\u043E \u0431\u043B\u0430\u0436\u0435\u043D\u0441\u0442\u0432\u0430 \u0432 \u0441\u043B\u0443\u0447\u0430\u0435 \u0442\u043E\u0433\u043E, \u043A\u0442\u043E \u0441\u043E\u0437\u0435\u0440\u0446\u0430\u0435\u0442 \u2014\u0430 \u0438\u043C\u0435\u043D\u043D\u043E, \u0442\u043E\u0433\u043E, \u0447\u0435\u0439 \u0443\u043C \u0441\u043A\u043E\u043D\u0446\u0435\u043D\u0442\u0440\u0438\u0440\u043E\u0432\u0430\u043D\u2014 \u0432 \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u0438 \u043F\u043E\u043B\u043D\u043E\u0442\u044B [\u0442\u0430\u043A\u043E\u0433\u043E] \u043D\u0430\u0441\u043B\u0430\u0436\u0434\u0435\u043D\u0438\u044F&quot;.</p><p>\u0422\u0435\u043F\u0435\u0440\u044C \u0432\u0430\u043C \u0434\u043E\u043B\u0436\u0435\u043D \u0431\u044B\u0442\u044C \u0441\u043E\u0432\u0435\u0440\u0448\u0435\u043D\u043D\u043E \u043F\u043E\u043D\u044F\u0442\u0435\u043D \u043C\u043E\u0439 \u043F\u043E\u0434\u0445\u043E\u0434 \u043A \u043F\u0435\u0440\u0435\u0432\u043E\u0434\u0443.</p></li></ul><ol start="6"><li>\u041F\u043E\u0441\u043A\u043E\u043B\u044C\u043A\u0443 \u043F\u043E\u0441\u043B\u0435\u0434\u043D\u044F\u044F \u0447\u0430\u0441\u0442\u044C \u0441\u0442\u0440\u043E\u0444\u044B \u043E\u0447\u0435\u043D\u044C \u0441\u043B\u043E\u0436\u043D\u0430, \u043C\u043D\u0435 \u043F\u0440\u0438\u0448\u043B\u043E\u0441\u044C \u043F\u0440\u0438\u0431\u0435\u0433\u043D\u0443\u0442\u044C \u043A \u043A\u043E\u043C\u043C\u0435\u043D\u0442\u0430\u0440\u0438\u044F\u043C, \u0441\u043E\u0441\u0442\u0430\u0432\u043B\u0435\u043D\u043D\u044B\u043C K\u1E63emar\u0101ja \u0438 \u015Aivop\u0101dhy\u0101ya, \u0447\u0442\u043E\u0431\u044B \u043F\u043E\u043B\u043D\u043E\u0441\u0442\u044C\u044E \u043F\u043E\u043D\u044F\u0442\u044C \u0441\u043C\u044B\u0441\u043B: &quot; ... \u0924\u0938\u094D\u092F \u092E\u0928\u094B\u0930\u0942\u0922\u0947\u0930\u094D\u0939\u0947\u0924\u094B\u0930\u094D\u092F\u0924\u094D\u0924\u0928\u094D\u092E\u092F\u0924\u094D\u0935\u0902 \u0936\u093E\u0915\u094D\u0924\u0938\u094D\u092A\u0930\u094D\u0936\u093E\u0935\u0947\u0936\u0938\u094D\u0924\u0947\u0928 \u0939\u0947\u0924\u0941\u0928\u093E \u0924\u0926\u093E\u0924\u094D\u092E\u0924\u093E\u2014 \u092A\u0930\u092C\u094D\u0930\u0939\u094D\u092E\u092E\u092F\u0924\u094D\u0935\u093E\u092A\u0924\u094D\u0924\u093F\u0903\u0964... &quot; - &quot;... tasya manor\u016B\u1E0Dherhetoryattanmayatva\u1E41 \u015B\u0101ktaspar\u015B\u0101ve\u015Bastena hetun\u0101 tad\u0101tmat\u0101\u2014 parabrahmamayatv\u0101patti\u1E25|...&quot; - &quot;\u0418\u0437-\u0437\u0430 \u0432\u043E\u0437\u0432\u044B\u0448\u0435\u043D\u0438\u044F \u0443\u043C\u0430 \u044D\u0442\u043E\u0433\u043E Yog\u012B, [\u0432\u043E\u0437\u043D\u0438\u043A\u0430\u0435\u0442] \u043E\u0442\u043E\u0436\u0434\u0435\u0441\u0442\u0432\u043B\u0435\u043D\u0438\u0435 \u0441 \u043D\u0438\u043C --\u0441 \u0442\u0430\u043A\u0438\u043C \u043D\u0435\u0441\u0440\u0430\u0432\u043D\u0438\u043C\u044B\u043C \u0432\u043E\u0441\u0442\u043E\u0440\u0433\u043E\u043C--, \u0447\u0442\u043E \u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F \u043F\u043E\u0433\u0440\u0443\u0436\u0435\u043D\u0438\u0435\u043C \u0432 \u043F\u0440\u0438\u043A\u043E\u0441\u043D\u043E\u0432\u0435\u043D\u0438\u0435, \u0438\u043B\u0438 \u043A\u043E\u043D\u0442\u0430\u043A\u0442 \u0441 \u015Aakti --\u0431\u043E\u0436\u0435\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u0439 \u0421\u0438\u043B\u043E\u0439 \u0432 \u0444\u043E\u0440\u043C\u0435 \u042F-\u0441\u043E\u0437\u043D\u0430\u043D\u0438\u044F--. \u0418\u0437-\u0437\u0430 \u044D\u0442\u043E\u0433\u043E [\u043E\u0442\u043E\u0436\u0434\u0435\u0441\u0442\u0432\u043B\u0435\u043D\u0438\u044F \u0438\u043B\u0438 \u043F\u043E\u0433\u043B\u043E\u0449\u0435\u043D\u0438\u044F, \u043F\u0440\u043E\u0438\u0441\u0445\u043E\u0434\u0438\u0442] \u043E\u0442\u043E\u0436\u0434\u0435\u0441\u0442\u0432\u043B\u0435\u043D\u0438\u0435 \u0441 \u0422\u0435\u043C, \u0442.\u0435. \u0438\u043C\u0435\u0435\u0442 \u043C\u0435\u0441\u0442\u043E \u043E\u0442\u043E\u0436\u0434\u0435\u0441\u0442\u0432\u043B\u0435\u043D\u0438\u0435 \u0441 \u0412\u044B\u0441\u0448\u0438\u043C \u0411\u0440\u0430\u0445\u043C\u043E\u0439 --\u0410\u0431\u0441\u043E\u043B\u044E\u0442\u043E\u043C--&quot;.</li></ol><p>\u041D\u0443 \u0432\u043E\u0442, \u0433\u043E\u0442\u043E\u0432\u043E!</p></div><div class="stanza"><a href="#s3.39" id="s3.39" class="num">3.39</a><div class="sans"><p>\u090F\u0924\u091A\u094D\u091A \u0924\u094D\u0930\u093F\u092A\u0926\u093E\u0926\u094D\u092F\u0928\u0941\u092A\u094D\u0930\u093E\u0923\u0928\u092E\u0928\u094D\u0924\u0930\u094D\u092E\u0941\u0916\u0924\u094D\u0935\u093E\u0935\u0937\u094D\u091F\u092E\u094D\u092D\u0924\u094D\u0935\u0926\u0936\u093E\u092F\u093E\u092E\u0947\u0935\u093E\u0938\u093E\u0926\u094D\u092F \u0928 \u0938\u0928\u094D\u0924\u0941\u0937\u094D\u092F\u0947\u0926\u092A\u093F \u0924\u0941\u2014</p><blockquote><p><strong>\u091A\u093F\u0924\u094D\u0924\u0938\u094D\u0925\u093F\u0924\u093F\u0935\u091A\u094D\u091B\u0930\u0940\u0930\u0915\u0930\u0923\u092C\u093E\u0939\u094D\u092F\u0947\u0937\u0941\u0965\u0969\u096F\u0965</strong></p></blockquote><p>\u0924\u094D\u0930\u093F\u092A\u0926\u093E\u0926\u094D\u092F\u0928\u0941\u092A\u094D\u0930\u093E\u0923\u0928\u092E\u093F\u0924\u094D\u092F\u0947\u0935\u0964 \u092F\u0925\u093E\u0928\u094D\u0924\u0930\u094D\u092E\u0941\u0916\u0930\u0942\u092A\u093E\u092F\u093E\u0902 \u091A\u093F\u0924\u094D\u0924\u0938\u094D\u0925\u093F\u0924\u094C \u0924\u0941\u0930\u094D\u092F\u0947\u0923\u093E\u0928\u0941\u092A\u094D\u0930\u093E\u0923\u0928\u0902 \u0915\u0941\u0930\u094D\u092F\u093E\u0924\u094D\u0924\u0925\u093E \u0936\u0930\u0940\u0930\u0915\u0930\u0923\u092C\u093E\u0939\u094D\u092F\u093E\u092D\u093E\u0938\u093E\u0924\u094D\u092E\u093F\u0915\u093E\u092F\u093E\u0902 \u092C\u0939\u093F\u0930\u094D\u092E\u0941\u0916\u0924\u093E\u092F\u093E\u092E\u092A\u094D\u092F\u093E\u0928\u094D\u0924\u0930\u0935\u093F\u092E\u0930\u094D\u0936\u093E\u0935\u0937\u094D\u091F\u092E\u094D\u092D\u092C\u0932\u093E\u0924\u094D\u0915\u094D\u0930\u092E\u093E\u0924\u094D\u0915\u094D\u0930\u092E\u0902 \u0924\u093E\u0930\u0924\u092E\u094D\u092F\u092D\u093E\u091C\u093E \u0924\u0947\u0928\u093E\u0928\u0941\u092A\u094D\u0930\u093E\u0923\u0928\u0902 \u0915\u0941\u0930\u094D\u092F\u093E\u0924\u094D\u0964 \u092F\u0926\u0941\u0915\u094D\u0924\u0902 \u0936\u094D\u0930\u0940\u0935\u093F\u091C\u094D\u091E\u093E\u0928\u092D\u0948\u0930\u0935\u0947</p><blockquote><p>\u0938\u0930\u094D\u0935\u0902 \u091C\u0917\u0924\u094D\u0938\u094D\u0935\u0926\u0947\u0939\u0902 \u0935\u093E \u0938\u094D\u0935\u093E\u0928\u0928\u094D\u0926\u092D\u0930\u093F\u0924\u0902 \u0938\u094D\u092E\u0930\u0947\u0924\u094D\u0964<br> \u092F\u0941\u0917\u092A\u0924\u094D\u0938\u094D\u0935\u093E\u092E\u0943\u0924\u0947\u0928\u0948\u0935 \u092A\u0930\u093E\u0928\u0928\u094D\u0926\u092E\u092F\u094B \u092D\u0935\u0947\u0924\u094D\u0965</p></blockquote><p>\u0907\u0924\u093F\u0964 \u090F\u0935\u0902 \u0939\u094D\u092F\u093E\u0928\u0928\u094D\u0926\u093E\u0924\u094D\u092E\u093E \u0938\u094D\u0935\u093E\u0924\u0928\u094D\u0924\u094D\u0930\u094D\u092F\u0936\u0915\u094D\u0924\u093F\u0903 \u0938\u0930\u094D\u0935\u0926\u0936\u093E\u0938\u0941 \u0938\u094D\u092B\u0941\u091F\u0940\u092D\u0942\u0924\u093E \u0938\u0924\u0940 \u092F\u0925\u0947\u0937\u094D\u091F\u0928\u093F\u0930\u094D\u092E\u093E\u0923\u0915\u093E\u0930\u093F\u0923\u0940 \u092D\u0935\u0924\u093F\u0965\u0969\u096F\u0965</p></div><hr><div class="trans"><p>Etacca tripad\u0101dyanupr\u0101\u1E47anamantarmukhatv\u0101va\u1E63\u1E6Dambhatvada\u015B\u0101y\u0101mev\u0101s\u0101dya na santu\u1E63yedapi tu\u2014</p><blockquote><p><strong>Cittasthitivacchar\u012Brakara\u1E47ab\u0101hye\u1E63u||39||</strong></p></blockquote><p>Tripad\u0101dyanupr\u0101\u1E47anamityeva| Yath\u0101ntarmukhar\u016Bp\u0101y\u0101\u1E41 cittasthitau turye\u1E47\u0101nupr\u0101\u1E47ana\u1E41 kury\u0101ttath\u0101 \u015Bar\u012Brakara\u1E47ab\u0101hy\u0101bh\u0101s\u0101tmik\u0101y\u0101\u1E41 bahirmukhat\u0101y\u0101mapy\u0101ntaravimar\u015B\u0101va\u1E63\u1E6Dambhabal\u0101tkram\u0101tkrama\u1E41 t\u0101ratamyabh\u0101j\u0101 ten\u0101nupr\u0101\u1E47ana\u1E41 kury\u0101t| Yadukta\u1E41 \u015Br\u012Bvij\xF1\u0101nabhairave</p><blockquote><p>Sarva\u1E41 jagatsvadeha\u1E41 v\u0101 sv\u0101nandabharita\u1E41 smaret|<br> Yugapatsv\u0101m\u1E5Btenaiva par\u0101nandamayo bhavet||</p></blockquote><p>iti| Eva\u1E41 hy\u0101nand\u0101tm\u0101 sv\u0101tantrya\u015Bakti\u1E25 sarvada\u015B\u0101su sphu\u1E6D\u012Bbh\u016Bt\u0101 sat\u012B yathe\u1E63\u1E6Danirm\u0101\u1E47ak\u0101ri\u1E47\u012B bhavati||39||</p></div><hr><p>\u0418 <em>(ca)</em> \u044D\u0442\u043E\u0442 [Yog\u012B] <em>(etad)</em>, \u0434\u043E\u0441\u0442\u0438\u0433\u043D\u0443\u0432 <em>(\u0101s\u0101dya)</em> \u043E\u0436\u0438\u0432\u043B\u0435\u043D\u0438\u044F <em>(anupr\u0101\u1E47anam)</em> \u0442\u0440\u0435\u0445 \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u0439 --\u043F\u0440\u043E\u044F\u0432\u043B\u0435\u043D\u0438\u044F, \u043F\u043E\u0434\u0434\u0435\u0440\u0436\u0430\u043D\u0438\u044F \u0438 \u0440\u0430\u0441\u0442\u0432\u043E\u0440\u0435\u043D\u0438\u044F-- <em>(tri-pada)</em> \u043F\u043E\u0441\u0440\u0435\u0434\u0441\u0442\u0432\u043E\u043C \u0433\u043B\u0430\u0432\u043D\u043E\u0433\u043E --\u0447\u0435\u0440\u0435\u0437 Turya-- <em>(\u0101di)</em> \u0442\u043E\u043B\u044C\u043A\u043E <em>(eva)</em> \u043F\u0440\u0438 \u0443\u0441\u043B\u043E\u0432\u0438\u0438 <em>(da\u015B\u0101y\u0101m)</em> \u0432\u043D\u0443\u0442\u0440\u0435\u043D\u043D\u0435\u0433\u043E <em>(antarmukhatva)</em> \u043A\u0440\u0435\u043F\u043A\u043E\u0433\u043E \u0443\u0434\u0435\u0440\u0436\u0438\u0432\u0430\u043D\u0438\u044F <em>(ava\u1E63\u1E6Dambhatva)</em>, \u043D\u0435 \u0434\u043E\u043B\u0436\u0435\u043D \u0434\u043E\u0432\u043E\u043B\u044C\u0441\u0442\u0432\u043E\u0432\u0430\u0442\u044C\u0441\u044F <em>(na santu\u1E63yet)</em> [\u0442\u043E\u043B\u044C\u043A\u043E \u044D\u0442\u0438\u043C], \u043D\u043E \u0442\u0430\u043A\u0436\u0435 <em>(api tu)</em>\u2014</p><blockquote><p><strong>\u041A\u0430\u043A [\u0432 \u0441\u043B\u0443\u0447\u0430\u0435] <em>(vat)</em> \u043C\u0435\u043D\u0442\u0430\u043B\u044C\u043D\u044B\u0445 <em>(citta)</em> \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u0439 <em>(sthiti)</em>, [\u0442\u0430\u043A \u0438 \u043A\u0430\u0441\u0430\u0442\u0435\u043B\u044C\u043D\u043E] \u0442\u0435\u043B\u0430 <em>(\u015Bar\u012Bra)</em>, \u043E\u0440\u0433\u0430\u043D\u043E\u0432 \u0447\u0443\u0432\u0441\u0442\u0432 <em>(kara\u1E47a)</em> \u0438 \u0432\u043D\u0435\u0448\u043D\u0438\u0445 \u043E\u0431\u044A\u0435\u043A\u0442\u043E\u0432 --b\u0101hya-- <em>(b\u0101hye\u1E63u)</em>, [\u0434\u043E\u043B\u0436\u043D\u043E \u0431\u044B\u0442\u044C &quot;\u043E\u0436\u0438\u0432\u043B\u0435\u043D\u0438\u0435, \u0438\u043B\u0438 \u043E\u0436\u0438\u0432\u043E\u0442\u0432\u043E\u0440\u0435\u043D\u0438\u0435&quot; \u0447\u0435\u0440\u0435\u0437 \u043D\u0430\u043F\u043E\u043B\u043D\u0435\u043D\u0438\u0435 \u0438\u0445 \u0411\u043B\u0430\u0436\u0435\u043D\u0441\u0442\u0432\u043E\u043C \u0447\u0435\u0442\u0432\u0435\u0440\u0442\u043E\u0433\u043E \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u044F \u0441\u043E\u0437\u043D\u0430\u043D\u0438\u044F]||39||</strong></p></blockquote><p>[\u0414\u043E\u043B\u0436\u0435\u043D \u0431\u044B\u0442\u044C \u0434\u043E\u0431\u0430\u0432\u043B\u0435\u043D \u043F\u0440\u0435\u0434\u044B\u0434\u0443\u0449\u0438\u0439 \u0430\u0444\u043E\u0440\u0438\u0437\u043C \u0434\u043B\u044F \u0437\u0430\u0432\u0435\u0440\u0448\u0435\u043D\u0438\u044F \u0441\u043C\u044B\u0441\u043B\u0430 \u0442\u0435\u043A\u0443\u0449\u0435\u0433\u043E:] &quot;[\u0414\u043E\u043B\u0436\u043D\u043E \u0431\u044B\u0442\u044C] \u043E\u0436\u0438\u0432\u043B\u0435\u043D\u0438\u0435 <em>(anupr\u0101\u1E47anam)</em> \u0442\u0440\u0435\u0445 \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u0439 --\u043F\u0440\u043E\u044F\u0432\u043B\u0435\u043D\u0438\u044F, \u043F\u043E\u0434\u0434\u0435\u0440\u0436\u0430\u043D\u0438\u044F \u0438 \u0440\u0430\u0441\u0442\u0432\u043E\u0440\u0435\u043D\u0438\u044F-- <em>(tri-pada)</em> \u043F\u043E\u0441\u0440\u0435\u0434\u0441\u0442\u0432\u043E\u043C \u0433\u043B\u0430\u0432\u043D\u043E\u0433\u043E <em>(\u0101di... iti eva)</em> [\u0434\u0440\u0443\u0433\u0438\u043C\u0438 \u0441\u043B\u043E\u0432\u0430\u043C\u0438, &#39;\u0447\u0435\u0442\u0432\u0435\u0440\u0442\u044B\u043C \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u0435\u043C \u0441\u043E\u0437\u043D\u0430\u043D\u0438\u044F, \u043A\u043E\u0442\u043E\u0440\u043E\u0435 \u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F \u0421\u0432\u0438\u0434\u0435\u0442\u0435\u043B\u0435\u043C \u0442\u0440\u0435\u0445 \u0434\u0440\u0443\u0433\u0438\u0445 \u0438 \u043D\u0430\u043F\u043E\u043B\u043D\u0435\u043D\u043E \u0442\u0440\u0430\u043D\u0441\u0446\u0435\u043D\u0434\u0435\u043D\u0442\u043D\u044B\u043C \u0411\u043B\u0430\u0436\u0435\u043D\u0441\u0442\u0432\u043E\u043C&#39;]&quot;|</p><p>\u0422\u0430\u043A \u0436\u0435, \u043A\u0430\u043A <em>(yath\u0101)</em> \u0435\u043C\u0443 \u0441\u043B\u0435\u0434\u0443\u0435\u0442 \u0432\u044B\u043F\u043E\u043B\u043D\u044F\u0442\u044C <em>(kury\u0101t)</em> \u043E\u0436\u0438\u0432\u043B\u0435\u043D\u0438\u0435 <em>(anupr\u0101\u1E47anam)</em> \u043F\u043E\u0441\u0440\u0435\u0434\u0441\u0442\u0432\u043E\u043C Turya --\u0447\u0435\u0442\u0432\u0435\u0440\u0442\u044B\u043C \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u0435\u043C, \u043A\u043E\u0442\u043E\u0440\u043E\u0435 \u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F \u043A\u043E\u043C\u043F\u0430\u043A\u0442\u043D\u043E\u0439 \u043C\u0430\u0441\u0441\u043E\u0439 \u0411\u043B\u0430\u0436\u0435\u043D\u0441\u0442\u0432\u0430-- <em>(turye\u1E47a)</em> \u0432 \u043E\u0442\u043D\u043E\u0448\u0435\u043D\u0438\u0438 \u0432\u043D\u0443\u0442\u0440\u0435\u043D\u043D\u0435\u0433\u043E \u043C\u0435\u043D\u0442\u0430\u043B\u044C\u043D\u043E\u0433\u043E \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u044F <em>(antarmukha-r\u016Bp\u0101y\u0101m citta-sthitau)</em>, \u0442\u0430\u043A\u0436\u0435 <em>(tath\u0101)</em> \u0438 <em>(api)</em> \u0432 \u043E\u0442\u043D\u043E\u0448\u0435\u043D\u0438\u0438 \u0432\u043D\u0435\u0448\u043D\u0435\u0433\u043E \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u044F <em>(bahis-mukhat\u0101y\u0101m)</em>, \u0447\u044C\u0435\u0439 \u043F\u0440\u0438\u0440\u043E\u0434\u043E\u0439 <em>(\u0101tmik\u0101y\u0101m)</em> \u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F \u043F\u0440\u043E\u044F\u0432\u043B\u0435\u043D\u0438\u0435 <em>(\u0101bh\u0101sa)</em> \u0442\u0435\u043B\u0430 <em>(\u015Bar\u012Bra)</em>, \u043E\u0440\u0433\u0430\u043D\u043E\u0432 \u0447\u0443\u0432\u0441\u0442\u0432 <em>(kara\u1E47a)</em> [\u0438] \u0432\u043D\u0435\u0448\u043D\u0438\u0445 \u043E\u0431\u044A\u0435\u043A\u0442\u043E\u0432 <em>(b\u0101hya)</em>, \u043E\u043D \u0434\u043E\u043B\u0436\u0435\u043D \u0432\u044B\u043F\u043E\u043B\u043D\u044F\u0442\u044C <em>(kury\u0101t)</em> \u043E\u0436\u0438\u0432\u043B\u0435\u043D\u0438\u0435 <em>(anupr\u0101\u1E47anam)</em> \u043F\u043E\u0441\u0440\u0435\u0434\u0441\u0442\u0432\u043E\u043C \u044D\u0442\u043E\u0433\u043E --\u0447\u0435\u0440\u0435\u0437 Turya-- <em>(tena)</em>, \u043E\u0447\u0435\u043D\u044C \u043F\u043E\u0441\u0442\u0435\u043F\u0435\u043D\u043D\u043E <em>(kram\u0101t-kramam)</em>, \u0442.\u0435. \u043F\u043E\u043D\u0435\u043C\u043D\u043E\u0433\u0443 <em>(t\u0101ratamya-bh\u0101j\u0101)</em>, \u0441 \u043F\u043E\u043C\u043E\u0449\u044C\u044E \u0441\u0438\u043B\u044B, [\u043F\u043E\u043B\u0443\u0447\u0430\u0435\u043C\u043E\u0439 \u0438\u0437] <em>(bal\u0101t)</em> \u043A\u0440\u0435\u043F\u043A\u043E\u0433\u043E \u0443\u0434\u0435\u0440\u0436\u0438\u0432\u0430\u043D\u0438\u044F <em>(ava\u1E63\u1E6Dambha)</em> \u0432\u043D\u0443\u0442\u0440\u0435\u043D\u043D\u0435\u0439 <em>(\u0101ntara)</em> \u043E\u0441\u043E\u0437\u043D\u0430\u043D\u043D\u043E\u0441\u0442\u0438 <em>(vimar\u015Ba)</em>|</p><p>\u042D\u0442\u043E <em>(yad)</em> \u0431\u044B\u043B\u043E \u043E\u043F\u0438\u0441\u0430\u043D\u043E <em>(uktam)</em> \u0432 \u0443\u0432\u0430\u0436\u0430\u0435\u043C\u043E\u043C Vij\xF1\u0101nabhairava <em>(\u015Br\u012B-vij\xF1\u0101nabhairave)</em>:</p><blockquote><p>&quot;\u0421\u043B\u0435\u0434\u0443\u0435\u0442 \u043F\u043E\u043C\u043D\u0438\u0442\u044C <em>(smaret)</em> \u0432\u0435\u0441\u044C <em>(sarvam)</em> \u043C\u0438\u0440 <em>(jagat)</em> \u0438\u043B\u0438 <em>(v\u0101)</em> \u0441\u0432\u043E\u0435 \u0441\u043E\u0431\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u0435 <em>(sva)</em> \u0442\u0435\u043B\u043E <em>(deham)</em>, \u043A\u0430\u043A \u043D\u0430\u043F\u043E\u043B\u043D\u0435\u043D\u043D\u044B\u0435 <em>(bharitam)</em> \u0441\u0432\u043E\u0438\u043C \u0441\u043E\u0431\u0441\u0442\u0432\u0435\u043D\u043D\u044B\u043C <em>(sva)</em> \u0431\u043B\u0430\u0436\u0435\u043D\u0441\u0442\u0432\u043E\u043C <em>(\u0101nanda)</em>. \u0412 \u0442\u043E \u0436\u0435 \u0432\u0440\u0435\u043C\u044F <em>(yugapad)</em> --\u0442.\u0435. \u043A\u043E\u0433\u0434\u0430 \u043E\u043D \u0441\u043F\u043E\u0441\u043E\u0431\u0435\u043D \u043F\u043E\u043C\u043D\u0438\u0442\u044C \u0442\u0430\u043A\u0438\u043C \u043E\u0431\u0440\u0430\u0437\u043E\u043C--, \u043E\u043D \u043D\u0430\u043F\u043E\u043B\u043D\u0435\u043D <em>(maya\u1E25 bhavet)</em> \u0412\u044B\u0441\u0448\u0438\u043C <em>(para)</em> \u041D\u0430\u0441\u043B\u0430\u0436\u0434\u0435\u043D\u0438\u0435\u043C <em>(\u0101nanda)</em> \u0438\u0437-\u0437\u0430 \u0441\u0432\u043E\u0435\u0433\u043E \u0441\u043E\u0431\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u0433\u043E \u041D\u0435\u043A\u0442\u0430\u0440\u0430 <em>(sva-am\u1E5Btena eva... iti)</em>&quot;||</p></blockquote><p>\u0422\u0430\u043A\u0438\u043C \u043E\u0431\u0440\u0430\u0437\u043E\u043C <em>(evam hi)</em>, \u0421\u0438\u043B\u0430 <em>(\u015Bakti\u1E25)</em> \u0410\u0431\u0441\u043E\u043B\u044E\u0442\u043D\u043E\u0439 \u0421\u0432\u043E\u0431\u043E\u0434\u044B <em>(sv\u0101tantrya)</em>, \u0447\u044C\u044F \u043F\u0440\u0438\u0440\u043E\u0434\u0430 <em>(\u0101tm\u0101)</em> \u2014 \u0411\u043B\u0430\u0436\u0435\u043D\u0441\u0442\u0432\u043E <em>(\u0101nanda)</em>, \u0441\u0442\u0430\u043D\u043E\u0432\u0438\u0442\u0441\u044F \u043F\u0440\u043E\u044F\u0432\u043B\u0435\u043D\u043D\u043E\u0439 <em>(sphu\u1E6D\u012B-bh\u016Bt\u0101 sat\u012B)</em> \u0432\u043E \u0432\u0441\u0435\u0445 \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u044F\u0445 <em>(sarva-da\u015B\u0101su)</em>, [\u0438 \u0432 \u0440\u0435\u0437\u0443\u043B\u044C\u0442\u0430\u0442\u0435,] \u043F\u0440\u0435\u0432\u0440\u0430\u0449\u0430\u0435\u0442\u0441\u044F \u0432 <em>(bhavati)</em> \u0422\u0432\u043E\u0440\u0446\u0430 <em>(nirm\u0101\u1E47ak\u0101ri\u1E47\u012B)</em>, [\u043A\u043E\u0442\u043E\u0440\u044B\u0439 \u0441\u043F\u043E\u0441\u043E\u0431\u0435\u043D \u043F\u0440\u043E\u044F\u0432\u043B\u044F\u0442\u044C \u0432\u0441\u0435, \u0447\u0442\u043E \u0443\u0433\u043E\u0434\u043D\u043E] \u043F\u043E \u0436\u0435\u043B\u0430\u043D\u0438\u044E <em>(yath\u0101-i\u1E63\u1E6Da)</em><sup>1</sup>||39||</p><hr><ol><li>\u0410\u0431\u0441\u043E\u043B\u044E\u0442\u043D\u0430\u044F \u0421\u0432\u043E\u0431\u043E\u0434\u0430 \u0413\u043E\u0441\u043F\u043E\u0434\u0430 \u0432\u0441\u0435\u0433\u0434\u0430 \u043F\u0440\u043E\u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F \u0432\u043E \u0432\u0441\u0435\u0445 \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u044F\u0445 \u0432\u0441\u0435\u0445 \u0441\u0443\u0449\u0435\u0441\u0442\u0432, \u043D\u043E \u0432 \u0441\u043B\u0443\u0447\u0430\u0435 \u0432\u0435\u043B\u0438\u043A\u043E\u0433\u043E Yog\u012B, \u0440\u0430\u0437\u043D\u0438\u0446\u0430 \u0437\u0430\u043A\u043B\u044E\u0447\u0430\u0435\u0442\u0441\u044F \u0432 \u0442\u043E\u043C, \u0447\u0442\u043E \u043E\u043D \u043F\u043E\u043B\u043D\u043E\u0441\u0442\u044C\u044E \u043E\u0441\u043E\u0437\u043D\u0430\u0435\u0442 \u044D\u0442\u0443 \u0410\u0431\u0441\u043E\u043B\u044E\u0442\u043D\u0443\u044E \u0421\u0432\u043E\u0431\u043E\u0434\u0443. \u0414\u0440\u0443\u0433\u0438\u043C\u0438 \u0441\u043B\u043E\u0432\u0430\u043C\u0438, \u043E\u043D \u0438\u043C\u0435\u0435\u0442 \u043F\u043E\u0441\u0442\u043E\u044F\u043D\u043D\u043E\u0435 \u043E\u0441\u043E\u0437\u043D\u0430\u043D\u0438\u0435 \u042D\u0442\u043E\u0433\u043E, \u0432 \u0442\u043E \u0432\u0440\u0435\u043C\u044F \u043A\u0430\u043A \u043E\u0441\u0442\u0430\u043B\u044C\u043D\u044B\u0435 \u0441\u0443\u0449\u0435\u0441\u0442\u0432\u0430, \u043F\u0440\u0435\u0431\u044B\u0432\u0430\u044E\u0449\u0438\u0435 \u0432 \u0440\u0430\u0431\u0441\u0442\u0432\u0435, \u043D\u0435 \u0438\u043C\u0435\u044E\u0442 \u0442\u0430\u043A\u043E\u0433\u043E \u043E\u0441\u043E\u0437\u043D\u0430\u0432\u0430\u043D\u0438\u044F. \u0412 \u044D\u0442\u043E\u043C \u043E\u0442\u043B\u0438\u0447\u0438\u0435! \u0418 \u043A\u043E\u043D\u0435\u0447\u043D\u043E, \u0438\u043C\u0435\u043D\u043D\u043E \u0432 \u044D\u0442\u043E\u043C \u0441\u043C\u044B\u0441\u043B\u0435 \u043C\u0443\u0434\u0440\u0435\u0446 K\u1E63emar\u0101ja \u0443\u0442\u0432\u0435\u0440\u0436\u0434\u0430\u043B, \u0447\u0442\u043E \u0432 \u044D\u0442\u043E\u043C \u043F\u0440\u0435\u0432\u043E\u0441\u0445\u043E\u0434\u043D\u043E\u043C Yog\u012B \u0421\u0438\u043B\u0430 \u0410\u0431\u0441\u043E\u043B\u044E\u0442\u043D\u043E\u0439 \u0421\u0432\u043E\u0431\u043E\u0434\u044B \u0441\u0442\u0430\u043D\u043E\u0432\u0438\u0442\u0441\u044F \u0422\u0432\u043E\u0440\u0446\u043E\u043C \u0447\u0435\u0433\u043E \u0443\u0433\u043E\u0434\u043D\u043E \u043F\u043E (\u0435\u0433\u043E) \u0436\u0435\u043B\u0430\u043D\u0438\u044E. \u0425\u043E\u0440\u043E\u0448\u043E!</li></ol></div>',6),p=[o];function r(i,s,n,h,v,k){return m(),e("div",null,p)}var y=a(u,[["render",r]]);export{q as __pageData,y as default};
